function mapRemoteAgentForUi(agent = {}) {
  const covered = Array.isArray(agent.districts_covered) ? agent.districts_covered.filter(Boolean) : [];
  const area = covered.length ? covered.slice(0, 3).join(" • ") : (agent.area || "Uganda");
  const specializations = Array.isArray(agent.specializations) ? agent.specializations.filter(Boolean) : [];
  return {
    id: String(agent.id || ""),
    name: agent.full_name || agent.name || "MakaUg Agent",
    company: agent.company_name || agent.company || "MakaUg",
    phone: agent.phone || "",
    email: agent.email || "",
    whatsapp: String(agent.whatsapp || agent.phone || "").replace(/\D/g, ""),
    area,
    rating: Number(agent.rating || 0) || 4.5,
    listings: Number(agent.listings_count || agent.total_listings || agent.listings || 0) || 0,
    live_listings: Number(agent.live_listings || agent.listings_count || 0) || 0,
    pending_listings: Number(agent.pending_listings || 0) || 0,
    rejected_listings: Number(agent.rejected_listings || 0) || 0,
    sales: Number(agent.sales_count || agent.sales || 0) || 0,
    emoji: agent.profile_photo_url ? "" : "👔",
    photo: agent.profile_photo_url || "",
    profile_photo_url: agent.profile_photo_url || "",
    registration_status: String(agent.registration_status || "not_registered").toLowerCase(),
    experience: agent.experience || "",
    licence: agent.licence_number || agent.licence || "",
    languages: Array.isArray(agent.languages) ? agent.languages.filter(Boolean) : ["English"],
    specialties: specializations,
    bio: agent.bio || "Professional MakaUg agent profile.",
    featured_homepage: agent.featured_homepage === true,
    featured_at: agent.featured_at || null,
    status: agent.status || "approved",
    districts_covered: covered,
    specializations
  };
}

function getBrokerDirectory() {
  return remoteBrokersLoaded ? REMOTE_BROKERS : BROKERS;
}

function findBrokerById(id) {
  const key = String(id || "");
  return getBrokerDirectory().find((broker) => String(broker.id || "") === key) || null;
}

function getFeaturedBrokers(list = getBrokerDirectory()) {
  const rows = Array.isArray(list) ? [...list] : [];
  rows.sort((a, b) => {
    const af = a?.featured_homepage === true ? 1 : 0;
    const bf = b?.featured_homepage === true ? 1 : 0;
    if (af !== bf) return bf - af;
    const ar = Number(a?.rating || 0);
    const br = Number(b?.rating || 0);
    if (ar !== br) return br - ar;
    return Number(b?.listings || 0) - Number(a?.listings || 0);
  });
  return rows;
}

async function refreshBrokersFromApi({ silent = true } = {}) {
  try {
    const response = await apiRequest("/api/agents?status=approved&limit=100");
    const rows = Array.isArray(response?.data) ? response.data : [];
    REMOTE_BROKERS = rows.map(mapRemoteAgentForUi).filter((broker) => broker.id);
    remoteBrokersLoaded = true;
    populateBrokerFilterOptions();
    renderAll();
    setBrokerMapMarkers(getBrokerDirectory());
    return true;
  } catch (error) {
    if (!silent) toast(`Agent refresh failed: ${error.message || "error"}`);
    return false;
  }
}

function getHierarchyPointForArea(district, area) {
  const districtName = String(district || "").trim();
  const areaName = String(area || "").trim().toLowerCase();
  if (!districtName || !areaName) return null;
  const tree = getDistrictLocationTree(districtName);
  for (const node of tree) {
    if (String(node.city || "").trim().toLowerCase() === areaName) {
      return getCityPoint(districtName, node.city);
    }
    const neighborhood = (node.neighborhoods || []).find((item) => String(item.name || "").trim().toLowerCase() === areaName);
    if (neighborhood && Number.isFinite(neighborhood.lat) && Number.isFinite(neighborhood.lng)) {
      return { lat: neighborhood.lat, lng: neighborhood.lng };
    }
  }
  return null;
}

function getListingMapPoint(property = {}) {
  const rawLat = Number(property?.lat ?? property?.latitude);
  const rawLng = Number(property?.lng ?? property?.longitude);
  if (Number.isFinite(rawLat) && Number.isFinite(rawLng) && isLikelyUgandaCoordinate(rawLat, rawLng)) {
    return { lat: rawLat, lng: rawLng, exact: true };
  }

  const district = property?.district || "";
  const city = property?.city || property?.location_town || "";
  const neighborhood = property?.neighborhood || property?.area || "";
  const hierarchyPoint = getNeighborhoodPoint(district, city, neighborhood)
    || getHierarchyPointForArea(district, neighborhood)
    || getCityPoint(district, city)
    || getHierarchyPointForArea(district, city);
  if (hierarchyPoint) return { ...hierarchyPoint, exact: false };

  const districtCenter = getDistrictCenter(district);
  if (districtCenter) return { ...districtCenter, exact: false };

  const regionCenter = getRegionCenter(regionForDistrict(district));
  if (regionCenter) return { ...regionCenter, exact: false };

  return { ...MAP_DEFAULT_CENTER, exact: false };
}

