const UGANDA_COORD_BOUNDS = {
  latMin: -1.6,
  latMax: 4.5,
  lngMin: 29.4,
  lngMax: 35.1
};

function isLikelyUgandaCoordinate(lat, lng) {
  return Number.isFinite(lat)
    && Number.isFinite(lng)
    && lat >= UGANDA_COORD_BOUNDS.latMin
    && lat <= UGANDA_COORD_BOUNDS.latMax
    && lng >= UGANDA_COORD_BOUNDS.lngMin
    && lng <= UGANDA_COORD_BOUNDS.lngMax;
}

function getHomeMapOverviewCenter() {
  return { ...MAP_UGANDA_OVERVIEW_CENTER };
}

