function contentTr(key) {
  const lang = currentLang || "en";
  const fallback = LANG_FALLBACK[lang] || "en";
  const value = CONTENT_I18N[lang]?.[key]
    || CONTENT_I18N[fallback]?.[key]
    || CONTENT_I18N.en?.[key]
    || "";
  if (!CONTENT_I18N[lang]?.[key] && lang !== "en") {
    window.MAKAUG_MISSING_TRANSLATIONS = window.MAKAUG_MISSING_TRANSLATIONS || [];
    const missingKey = `${lang}:${key}`;
    if (!window.MAKAUG_MISSING_TRANSLATIONS.includes(missingKey)) {
      window.MAKAUG_MISSING_TRANSLATIONS.push(missingKey);
    }
  }
  return value || key;
}

function applyContentLanguageUI(root = document) {
  if (!root) return;
  root.querySelectorAll("[data-content-i18n]").forEach((el) => {
    const key = el.getAttribute("data-content-i18n");
    if (key) el.textContent = contentTr(key);
  });
}

function applyAboutLanguageUI() {
  applyContentLanguageUI(document.getElementById("page-about"));
}

function tr(key) {
  const lang = currentLang || "en";
  const langPack = I18N_UI[lang] || I18N_UI.en;
  const fallbackPack = I18N_UI[LANG_FALLBACK[lang] || "en"] || I18N_UI.en;
  return langPack[key] || fallbackPack[key] || I18N_UI.en[key] || key;
}

