function aiTr(key) {
  const lang = currentLang || "en";
  const fallback = LANG_FALLBACK[lang] || "en";
  return AI_CHATBOT_I18N[lang]?.[key]
    || AI_CHATBOT_I18N[fallback]?.[key]
    || AI_CHATBOT_I18N.en?.[key]
    || key;
}

