["ac", "ny", "rn", "sm"].forEach((lang) => {
  FRAUD_EXTRA_I18N[lang] = FRAUD_EXTRA_I18N[LANG_FALLBACK[lang] || "en"] || FRAUD_EXTRA_I18N.en;
});

function fraudTr(key) {
  const lang = currentLang || "en";
  const fallback = LANG_FALLBACK[lang] || "en";
  return FRAUD_I18N[lang]?.[key]
    || FRAUD_EXTRA_I18N[lang]?.[key]
    || FRAUD_I18N[fallback]?.[key]
    || FRAUD_EXTRA_I18N[fallback]?.[key]
    || FRAUD_I18N.en?.[key]
    || FRAUD_EXTRA_I18N.en?.[key]
    || key;
}

function setTextById(id, text) {
  const el = document.getElementById(id);
  if (el) el.textContent = text;
}

function setPageHeading(pageId, text) {
  const h = document.querySelector(`#${pageId} h1`);
  if (h && text) h.textContent = text;
}

