function normalizeStudentDashboardProperty(item) {
  const property = item?.property || item || {};
  return {
    ...property,
    id: property.id || item?.listing_id || item?.listingId || "",
    title: property.title || item?.title || "Student accommodation",
    area: property.area || property.location || property.neighborhood || property.neighbourhood || "",
    district: property.district || "",
    price: property.price || property.price_per_month || property.pricePerMonth || 0,
    period: property.period || property.price_period || property.pricePeriod || "month"
  };
}

async function renderStudentDashboard() {
  const gate = document.getElementById("student-dashboard-auth-gate");
  const body = document.getElementById("student-dashboard-body");
  if (!gate || !body) return;

  const mode = derivePortalMode(authState?.user, authState?.user?.portal_mode);
  if (!authState?.user || mode !== "student") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }

  gate.classList.add("hidden");
  body.classList.remove("hidden");

  const first = authState.user.first_name || "there";
  setTextById("student-dashboard-greeting", `${timeOfDayGreeting()}, ${first}`);
  setTextById("student-dashboard-greeting-sub", "Your campus accommodation matches, saved rooms, alerts, and recent views are kept here.");

  let payload = null;
  if (authState?.token && !authState?.user?.is_demo) {
    try {
      const res = await apiRequest("/api/student/dashboard");
      payload = res?.data || res || null;
    } catch (e) {
      console.warn("Student dashboard backend unavailable", e);
    }
  }

  const pref = payload?.preference || {};
  const localStudentListings = getPublicListings().filter((p) => isStudentDiscoverable(p));
  const recommendedRaw = Array.isArray(payload?.recommendations) ? payload.recommendations : [];
  const recommendations = (recommendedRaw.length ? recommendedRaw.map(normalizeStudentDashboardProperty) : localStudentListings)
    .filter(Boolean)
    .slice(0, 8);
  const savedRaw = Array.isArray(payload?.savedListings) ? payload.savedListings : [];
  const savedItems = (savedRaw.length ? savedRaw.map(normalizeStudentDashboardProperty) : localStudentListings.filter((p) => isPropertySaved(p.id)))
    .filter(Boolean);
  const alertCount = Array.isArray(payload?.savedSearches) ? payload.savedSearches.length : 0;
  const recentRaw = Array.isArray(payload?.recentlyViewed) ? payload.recentlyViewed : [];
  const localRecent = (getCurrentUserActivity().recentViewed || [])
    .map((id) => findPropertyForUi(id))
    .filter((p) => p && isListingPublicVisible(p) && isStudentDiscoverable(p));
  const recentItems = (recentRaw.length ? recentRaw.map(normalizeStudentDashboardProperty) : localRecent)
    .filter(Boolean)
    .slice(0, 4);

  const budgetParts = [];
  const minBudget = parseInt(pref.min_budget || pref.minBudget || 0, 10) || 0;
  const maxBudget = parseInt(pref.max_budget || pref.maxBudget || 0, 10) || 0;
  if (minBudget) budgetParts.push(`from ${fmtP(minBudget, "month")}`);
  if (maxBudget) budgetParts.push(`up to ${fmtP(maxBudget, "month")}`);
  setTextById("student-dashboard-campus", pref.campus || pref.university || authState.user.profile_data?.student_campus || "Add your campus");
  setTextById("student-dashboard-budget", budgetParts.length ? budgetParts.join(" ") : "Set your budget");
  setTextById("student-dashboard-room", pref.room_type || pref.roomType || pref.shared_or_self_contained || "Any room");
  setTextById("student-dashboard-stat-saved", String(savedItems.length));
  setTextById("student-dashboard-stat-recommended", String(recommendations.length));
  setTextById("student-dashboard-stat-alerts", String(alertCount));

  const grid = document.getElementById("student-dashboard-grid");
  if (grid) {
    grid.innerHTML = recommendations.length
      ? recommendations.map(renderDashboardCard).join("")
      : `<div class="col-span-full text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No student accommodation matches yet. Tell MakaUg what you need and we will help source options.</div>`;
  }

  const recentGrid = document.getElementById("student-dashboard-recent-grid");
  if (recentGrid) {
    recentGrid.innerHTML = recentItems.length
      ? recentItems.map(renderDashboardCard).join("")
      : `<div class="text-sm text-gray-500 bg-white border border-gray-200 rounded-xl p-4">No student rooms viewed yet.</div>`;
  }
}

function renderAgentDashboard() {
  const gate = document.getElementById("agent-auth-gate");
  const body = document.getElementById("agent-body");
  if (!gate || !body) return;

  if (!authState?.user || authState.user.role !== "agent_broker") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }

  gate.classList.add("hidden");
  body.classList.remove("hidden");

  const broker = resolveCurrentAgentProfile();
  const nameEl = document.getElementById("agent-dashboard-name");
  const statusEl = document.getElementById("agent-dashboard-status");
  const gridEl = document.getElementById("agent-listings-grid");

  if (!broker) {
    if (nameEl) nameEl.textContent = `${authState.user.first_name || "Broker"} ${authState.user.last_name || ""}`.trim();
    if (statusEl) statusEl.textContent = "No broker profile linked yet. Register as a broker to unlock listing analytics.";
    if (gridEl) {
      gridEl.innerHTML = `<div class="col-span-full bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-800">No linked broker profile found. Please register through “Register as Broker”.</div>`;
    }
    return;
  }

  const myListings = PROPERTIES.filter((p) => String(p.agent || "") === String(broker.id || ""));
  const totalViews = myListings.reduce((sum, p) => sum + getPropertyViewCount(p.id), 0);
  const totalSaves = myListings.reduce((sum, p) => sum + getPropertySaveCount(p.id), 0);
  const profileViews = getBrokerProfileViewCount(broker.id);

  if (nameEl) nameEl.textContent = `${broker.name} • ${broker.company}`;
  if (statusEl) {
    const regLabel = broker.registration_status === "registered" ? "Registered" : "Under review";
    statusEl.textContent = `${regLabel} broker`;
  }

  const setText = (id, value) => {
    const el = document.getElementById(id);
    if (el) el.textContent = String(value);
  };
  setText("agent-stat-listings", myListings.length);
  setText("agent-stat-views", totalViews);
  setText("agent-stat-saves", totalSaves);
  setText("agent-stat-profile-views", profileViews);

  if (gridEl) {
    if (!myListings.length) {
      gridEl.innerHTML = `<div class="col-span-full text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No listings yet. Click “+ List Property” to publish your first listing.</div>`;
    } else {
      gridEl.innerHTML = myListings.map(renderDashboardCard).join("");
    }
  }
}

function extractFieldAgentCodeFromText(text) {
  const raw = String(text || "").trim();
  if (!raw) return "";
  const match = raw.match(/(?:^|[^0-9])([0-9]{6})(?:[^0-9]|$)/);
  return match ? match[1] : "";
}

function inferFieldListingStatus(property) {
  const explicit = String(property?.status || property?.extra_fields?.review_status || "").toLowerCase();
  if (["approved", "live", "published"].includes(explicit)) return "approved";
  if (["rejected", "declined", "fraud"].includes(explicit)) return "rejected";
  if (["pending", "under_review", "submitted"].includes(explicit)) return "pending";
  if (property?.featured) return "approved";
  return "pending";
}

function getFieldPayoutCutoff() {
  const now = new Date();
  const day = now.getDay(); // 0 Sun ... 5 Fri
  const daysToFriday = (5 - day + 7) % 7;
  const nextFriday = new Date(now);
  nextFriday.setDate(now.getDate() + (daysToFriday === 0 ? 7 : daysToFriday));
  const cutoff = new Date(nextFriday);
  cutoff.setDate(nextFriday.getDate() - 1);
  cutoff.setHours(23, 59, 59, 999);
  return { nextFriday, cutoff };
}

function getFieldSourceListingsForUser(user) {
  const profile = user?.profile_data && typeof user.profile_data === "object" ? user.profile_data : {};
  const code = String(user?.field_agent_code || profile.field_agent_code || profile.employee_number || "").trim();
  const real = PROPERTIES
    .filter((p) => {
      const textCode = extractFieldAgentCodeFromText(p?.desc || p?.description || "");
      return textCode === code || String(p?.field_agent_id || p?.field_agent_code || p?.extra_fields?.field_agent_id || "").trim() === code;
    })
    .map((p) => ({ ...p, review_status: inferFieldListingStatus(p) }));
  if (real.length) return real;
  if (!user?.is_demo) return [];

  const samples = PROPERTIES.slice(0, 5).map((p, idx) => {
    const status = idx === 0 ? "approved" : idx === 1 ? "rejected" : idx === 2 ? "approved" : "pending";
    const rejectionReason = status === "rejected" ? "Duplicate photos / unclear ownership proof" : null;
    return {
      ...p,
      review_status: status,
      field_agent_code: code || "123456",
      sourced_at: new Date(Date.now() - ((idx + 2) * 24 * 60 * 60 * 1000)).toISOString(),
      extra_fields: {
        ...(p.extra_fields || {}),
        rejection_reason: rejectionReason
      }
    };
  });
  return samples;
}

function renderFieldDashboard() {
  const gate = document.getElementById("field-auth-gate");
  const body = document.getElementById("field-body");
  if (!gate || !body) return;

  if (!authState?.user || derivePortalMode(authState.user, authState.user.portal_mode) !== "field_agent") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }

  gate.classList.add("hidden");
  body.classList.remove("hidden");

  const user = authState.user;
  const profile = user.profile_data && typeof user.profile_data === "object" ? user.profile_data : {};
  const sourcedListings = getFieldSourceListingsForUser(user);
  const approved = sourcedListings.filter((p) => p.review_status === "approved");
  const rejected = sourcedListings.filter((p) => p.review_status === "rejected");
  const pending = sourcedListings.filter((p) => p.review_status === "pending");
  const submitted = sourcedListings.length;
  const conv = submitted ? Math.round((approved.length / submitted) * 100) : 0;
  const payoutPerApproved = Number(profile.payout_rate_ugx || user.payout_rate_ugx || 15000) || 15000;
  const payable = approved.length * payoutPerApproved;
  const rank = submitted ? Math.max(1, Math.min(99, 20 - approved.length)) : "-";

  const setText = (id, value) => {
    const el = document.getElementById(id);
    if (el) el.textContent = String(value);
  };
  const fieldCode = user.field_agent_code || profile.field_agent_code || profile.employee_number || "-";
  const employeeNumber = user.employee_number || profile.employee_number || fieldCode;
  setText("field-dashboard-name", `${user.first_name || "Field"} ${user.last_name || "Agent"} • ${employeeNumber || "EMP"}`);
  setText("field-dashboard-status", `Code: ${fieldCode} • Territory: ${profile.field_agent_territory || "Uganda"} • Submitted: ${submitted} • Pending: ${pending.length}`);
  setText("field-stat-submitted", submitted);
  setText("field-stat-approved", approved.length);
  setText("field-stat-rejected", rejected.length);
  setText("field-stat-conv", `${conv}%`);
  setText("field-stat-payable", fmtP(payable, ""));
  setText("field-stat-rank", rank === "-" ? "-" : `#${rank}`);
  setText("field-payout-summary", `${approved.length} approved listings x ${fmtP(payoutPerApproved, "")} = ${fmtP(payable, "")}. Next payout is shown after admin review and cut-off.`);
  setText("field-money-summary", `${pending.length} listings pending review. ${rejected.length} rejected listings need correction before they can count toward payout.`);
  const notice = document.getElementById("field-agent-notice");
  if (notice) {
    notice.textContent = profile.field_agent_notes || "Use the online form, WhatsApp listing option, or the WhatsApp AI bot to submit clean property leads. Approved listings count toward your weekly payout.";
  }
  const supportLink = document.getElementById("field-agent-whatsapp-broadcast");
  if (supportLink) {
    const message = `Hi MakaUg Operations, this is ${user.first_name || "a Field Agent"} (${fieldCode}). I need support with field listings, payouts, or approvals.`;
    supportLink.href = `https://wa.me/256760112587?text=${encodeURIComponent(message)}`;
  }

  const regionProgressEl = document.getElementById("field-region-progress");
  if (regionProgressEl) {
    const grouped = {};
    sourcedListings.forEach((p) => {
      const r = regionForDistrict(p.district || "") || "Central";
      grouped[r] = grouped[r] || { submitted: 0, approved: 0 };
      grouped[r].submitted += 1;
      if (p.review_status === "approved") grouped[r].approved += 1;
    });
    const rows = Object.entries(grouped);
    if (!rows.length) {
      regionProgressEl.innerHTML = `<div class="text-sm text-gray-500">No regional activity yet.</div>`;
    } else {
      regionProgressEl.innerHTML = rows.map(([region, vals]) => {
        const ratio = vals.submitted ? Math.round((vals.approved / vals.submitted) * 100) : 0;
        return `<div class="border border-gray-200 rounded-xl p-3">
          <div class="flex justify-between text-sm font-semibold text-gray-800"><span>${region}</span><span>${vals.approved}/${vals.submitted} approved</span></div>
          <div class="mt-2 h-2 rounded bg-gray-100 overflow-hidden"><div class="h-full bg-green-600" style="width:${ratio}%"></div></div>
        </div>`;
      }).join("");
    }
  }

  const rejectionEl = document.getElementById("field-rejections-list");
  if (rejectionEl) {
    if (!rejected.length) {
      rejectionEl.innerHTML = `<div class="text-sm text-gray-500">No rejected listings in the current cycle.</div>`;
    } else {
      rejectionEl.innerHTML = rejected.map((p) => {
        const reason = p?.extra_fields?.rejection_reason || "Failed compliance checks";
        return `<div class="border border-red-100 bg-red-50 rounded-xl p-3">
          <div class="font-semibold text-red-800">${p.title}</div>
          <div class="text-xs text-red-700 mt-1">${p.area || "-"}, ${p.district || "-"}</div>
          <div class="text-xs text-red-700 mt-1"><strong>Reason:</strong> ${reason}</div>
        </div>`;
      }).join("");
    }
  }

  const listingsGrid = document.getElementById("field-listings-grid");
  if (listingsGrid) {
    if (!sourcedListings.length) {
      listingsGrid.innerHTML = `<div class="col-span-full text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No sourced listings found for your field code yet.</div>`;
    } else {
      listingsGrid.innerHTML = sourcedListings.map((p) => {
        const idArg = propertyIdArg(p.id);
        const badgeClass = p.review_status === "approved"
          ? "bg-green-100 text-green-700"
          : (p.review_status === "rejected" ? "bg-red-100 text-red-700" : "bg-amber-100 text-amber-700");
        const badgeLabel = p.review_status === "approved" ? "Approved" : (p.review_status === "rejected" ? "Rejected" : "Pending");
        return `<div class="border border-gray-200 rounded-xl p-4 bg-white">
          <div class="flex items-start justify-between gap-2">
            <button onclick="openPropertyCardDetail(event, ${idArg})" class="text-left font-bold text-gray-800 hover:text-green-700 line-clamp-1">${p.title}</button>
            <span class="text-xs font-semibold px-2 py-1 rounded ${badgeClass}">${badgeLabel}</span>
          </div>
          <p class="text-xs text-gray-500 mt-1">${p.area || "-"}, ${p.district || "-"}</p>
          <p class="text-sm font-bold text-green-700 mt-1">${fmtP(p.price, p.period)}</p>
          <div class="mt-2 text-xs text-gray-500 flex gap-3">
            <span>👁 ${getPropertyViewCount(p.id)} views</span>
            <span>❤️ ${getPropertySaveCount(p.id)} saves</span>
          </div>
        </div>`;
      }).join("");
    }
  }

  const { nextFriday, cutoff } = getFieldPayoutCutoff();
  const statusEl = document.getElementById("field-dashboard-status");
  if (statusEl) {
    const fmt = (d) => d.toLocaleDateString(undefined, { weekday: "short", year: "numeric", month: "short", day: "numeric" });
    statusEl.textContent = `Code: ${fieldCode} • Next payout: ${fmt(nextFriday)} • Cut-off: ${fmt(cutoff)}`;
  }
}

async function hydrateAdvertiserDashboardPlacements() {
  const wrap = document.getElementById("advertiser-dashboard-placements");
  if (!wrap) return;
  try {
    const res = await apiRequest("/api/advertising/placements");
    const rows = Array.isArray(res?.data) ? res.data : [];
    if (!rows.length) {
      wrap.innerHTML = `<div class="sm:col-span-2 text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No live placement catalogue is available yet. MakaUg will confirm package availability after inquiry.</div>`;
      return;
    }
    wrap.innerHTML = rows.slice(0, 8).map((slot) => `
      <div class="rounded-xl border border-gray-200 bg-white p-3">
        <div class="text-xs font-black text-gray-900">${adminEscape(slot.label || slot.key || "Advertising placement")}</div>
        <div class="text-[11px] text-gray-500 mt-1">${adminEscape(slot.page_key || "makaug")} • ${adminEscape(slot.size_label || slot.slot_type || "placement")}</div>
        <div class="text-sm font-black text-amber-700 mt-2">From ${adminEscape(adMoney(slot.base_price_ugx || 0))}</div>
      </div>
    `).join("");
  } catch (error) {
    wrap.innerHTML = `<div class="sm:col-span-2 text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">Placement catalogue unavailable. Campaign requests still submit safely and admins can price them from Advertising Desk.</div>`;
  }
}

async function renderAdvertiserDashboard() {
  const gate = document.getElementById("advertiser-auth-gate");
  const body = document.getElementById("advertiser-body");
  if (!gate || !body) return;

  const mode = derivePortalMode(authState?.user, authState?.user?.portal_mode);
  if (!authState?.user || mode !== "advertiser") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }

  gate.classList.add("hidden");
  body.classList.remove("hidden");
  const user = authState.user || {};
  setTextById("advertiser-dashboard-name", `${user.first_name || "Advertiser"} ${user.last_name || ""}`.trim() || "Advertiser Account");
  setTextById("advertiser-dashboard-status", "Campaign requests are reviewed by MakaUg before payment links, invoices, and live placement approval.");
  try {
    const res = await apiRequest("/api/advertising/dashboard");
    const data = res?.data || {};
    const campaigns = Array.isArray(data.campaigns) ? data.campaigns : [];
    const invoices = Array.isArray(data.invoices) ? data.invoices : [];
    const paid = invoices.filter((item) => String(item.status || "").toLowerCase() === "paid").reduce((sum, item) => sum + (parseInt(item.amount || 0, 10) || 0), 0);
    setTextById("advertiser-stat-campaigns", String(campaigns.length));
    setTextById("advertiser-stat-payment", invoices.length ? `${data.summary?.unpaidInvoices || 0} unpaid invoice(s)` : "Awaiting first campaign");
    setTextById("advertiser-stat-leads", String(campaigns.reduce((sum, item) => sum + (parseInt(item.leads || 0, 10) || 0), 0)));
    setTextById("advertiser-stat-clicks", String(campaigns.reduce((sum, item) => sum + (parseInt(item.clicks || 0, 10) || 0), 0)));
    setTextById("advertiser-stat-spend", `UGX ${Number(paid || 0).toLocaleString("en-UG")}`);
    const payments = document.getElementById("advertiser-dashboard-payments");
    if (payments) {
      payments.textContent = invoices.length
        ? `${invoices.length} invoice(s), ${data.paymentLinks?.length || 0} payment link request(s).`
        : "No payment link has been issued yet.";
    }
  } catch (error) {
    setTextById("advertiser-stat-campaigns", "0");
    setTextById("advertiser-stat-payment", "Awaiting first campaign");
    setTextById("advertiser-stat-leads", "0");
    setTextById("advertiser-stat-clicks", "0");
    setTextById("advertiser-stat-spend", "UGX 0");
  }
  await hydrateAdvertiserDashboardPlacements();
}

async function submitAdvertiserDashboardCampaign(event) {
  event.preventDefault();
  const form = event.currentTarget;
  const status = document.getElementById("advertiser-dashboard-campaign-status");
  const data = new FormData(form);
  const goal = String(data.get("goal") || "listing_promotion");
  const payload = {
    full_name: String(data.get("full_name") || "").trim(),
    business_name: String(data.get("business_name") || "").trim(),
    email: String(data.get("email") || authState?.user?.email || "").trim(),
    phone: normalizePhoneInput(data.get("phone") || authState?.user?.phone || ""),
    preferred_contact_channel: "whatsapp",
    product_interests: [goal],
    target_locations: String(data.get("target_locations") || "").trim(),
    target_listing_types: goal,
    budget_ugx: String(data.get("budget_ugx") || "").trim(),
    desired_duration_days: String(data.get("desired_duration_days") || "").trim(),
    message: String(data.get("message") || "").trim(),
    source: "advertiser_dashboard"
  };
  if (!payload.email && !payload.phone) {
    toast("Add an email or WhatsApp number so MakaUg can reply.");
    return;
  }
  try {
    const submit = form.querySelector("button[type='submit']");
    if (submit) {
      submit.disabled = true;
      submit.textContent = "Submitting...";
    }
    const result = await apiRequest("/api/advertising/campaigns", {
      method: "POST",
      body: {
        ...payload,
        campaign_name: `${payload.business_name || payload.full_name || "Advertiser"} MakaUg campaign`,
        package_key: goal,
        creative_brief: payload.message
      }
    });
    let paymentState = "";
    try {
      const campaignId = result?.data?.campaign?.id;
      if (campaignId) {
        const payment = await apiRequest(`/api/advertising/campaigns/${encodeURIComponent(campaignId)}/payment-link`, {
          method: "POST",
          body: { amount: payload.budget_ugx || result?.data?.campaign?.quoted_amount_ugx || 0 }
        });
        paymentState = payment?.data?.providerMissing
          ? "<br>Payment: provider not configured yet, manual invoice logged for admin."
          : `<br>Payment link: <a class="underline font-bold" href="${adminAttr(payment?.data?.paymentLink?.checkout_url || "#")}" target="_blank" rel="noopener noreferrer">Open payment</a>`;
        const payments = document.getElementById("advertiser-dashboard-payments");
        if (payments) payments.innerHTML = payment?.data?.providerMissing ? "Manual invoice logged. MakaUg will confirm payment instructions." : "Payment link generated.";
      }
    } catch (paymentError) {
      paymentState = "<br>Payment: request logged; MakaUg will confirm payment details.";
    }
    if (status) {
      status.classList.remove("hidden");
      status.innerHTML = `Campaign request received.<br>Reference: <strong>${adminEscape(result?.data?.campaign?.id || result?.data?.inquiry?.id || "pending")}</strong>${paymentState}<br>MakaUg will review the creative before any placement goes live.`;
    }
    setTextById("advertiser-stat-campaigns", "1");
    setTextById("advertiser-stat-payment", "Pending review");
    toast("Advertising campaign request submitted.");
    form.reset();
  } catch (e) {
    toast(`Campaign request failed: ${e.message || "error"}`);
  } finally {
    const submit = form.querySelector("button[type='submit']");
    if (submit) {
      submit.disabled = false;
      submit.textContent = "Submit Campaign Request";
    }
  }
}

function normalizeModerationStatus(status) {
  const raw = String(status || "").toLowerCase();
  if (["approved", "live", "published"].includes(raw)) return "approved";
  if (["sold", "completed"].includes(raw)) return "sold";
  if (["rejected", "declined", "fraud"].includes(raw)) return "rejected";
  if (["pending", "under_review", "submitted"].includes(raw)) return "pending";
  if (["hidden", "off_market", "paused", "archived"].includes(raw)) return "hidden";
  if (["deleted", "removed", "trash"].includes(raw)) return "deleted";
  return "approved";
}

function isListingPublicVisible(property) {
  const status = normalizeModerationStatus(property?.status);
  return status === "approved" || status === "sold";
}

function getPublicListings() {
  return PROPERTIES.filter((p) => isListingPublicVisible(p));
}

function isFeaturedListing(property) {
  return property?.featured === true || String(property?.extra_fields?.featured || "").toLowerCase() === "true";
}

function getFeaturedListings(listings) {
  const source = publicListingsFromApiLoaded
    ? listings.filter((p) => p.remote_source === "api" || isFeaturedListing(p))
    : listings;
  return source
    .filter((p) => isFeaturedListing(p))
    .sort((a, b) => {
      const ad = parseDateSafe(a.featured_at || a.extra_fields?.featured_at || a.updated_at || a.created_at)?.getTime() || 0;
      const bd = parseDateSafe(b.featured_at || b.extra_fields?.featured_at || b.updated_at || b.created_at)?.getTime() || 0;
      return bd - ad;
    });
}

function getKnownUsersForAdmin() {
  const map = {};
  PROPERTIES.forEach((p) => {
    const email = String(p?.lister_email || "").toLowerCase();
    const phone = normalizePhoneInput(p?.lister_phone || "");
    const key = email || phone;
    if (!key) return;
    if (!map[key]) {
      map[key] = {
        id: key,
        first_name: p?.contact_display_name || p?.lister_display_name || p?.lister_name || "Property",
        last_name: "Lister",
        email: email || "",
        phone: phone || "",
        role: "property_owner",
        status: "active",
        created_at: p?.created_at || null
      };
    }
  });
  if (authState?.user?.id) {
    map[authState.user.id] = {
      id: authState.user.id,
      first_name: authState.user.first_name || "",
      last_name: authState.user.last_name || "",
      phone: authState.user.phone || "",
      email: authState.user.email || "",
      role: authState.user.role || "buyer_renter",
      status: authState.user.status || "active",
      marketing_opt_in: authState.user.marketing_opt_in !== false,
      weekly_tips_opt_in: authState.user.weekly_tips_opt_in !== false,
      preferred_contact_channel: authState.user.preferred_contact_channel || "whatsapp",
      created_at: authState.user.created_at || null
    };
  }
  return Object.values(map);
}

function buildLocalAdminSnapshot() {
  const allListings = PROPERTIES.map((p) => ({
    ...p,
    moderation_status: normalizeModerationStatus(p.status)
  }));
  allListings.sort((a, b) => {
    const ad = parseDateSafe(a.created_at || a.updated_at)?.getTime() || 0;
    const bd = parseDateSafe(b.created_at || b.updated_at)?.getTime() || 0;
    return bd - ad;
  });
  const listings = allListings.filter((p) => p.moderation_status !== "deleted");
  const pendingListings = listings.filter((p) => p.moderation_status === "pending").slice(0, 50);
  const approvedListings = listings.filter((p) => p.moderation_status === "approved");
  const rejectedListings = listings.filter((p) => p.moderation_status === "rejected");
  const hiddenListings = listings.filter((p) => p.moderation_status === "hidden");
  const deletedListings = allListings.filter((p) => p.moderation_status === "deleted");
  const users = getKnownUsersForAdmin();
  const totalViews = listings.reduce((sum, p) => sum + getPropertyViewCount(p.id), 0);
  const totalSaves = listings.reduce((sum, p) => sum + getPropertySaveCount(p.id), 0);
  const totalBrokerViews = Object.values(siteMetrics?.brokerProfileViews || {}).reduce((sum, n) => sum + (parseInt(n || 0, 10) || 0), 0);
  const privateListings = listings.filter((p) => listingSourceMeta(p).key === "private").length;
  const agentListings = listings.length - privateListings;
  const studentDiscoverableListings = listings.filter((p) => isStudentDiscoverable(p)).length;
  const brokerDirectory = getBrokerDirectory();
  const registeredAgents = brokerDirectory.filter((b) => String(b.registration_status || "").toLowerCase() === "registered").length;
  const notRegisteredAgents = Math.max(0, brokerDirectory.length - registeredAgents);
  const approvalRate = listings.length ? Math.round((approvedListings.length / listings.length) * 100) : 0;
  const rejectionRate = listings.length ? Math.round((rejectedListings.length / listings.length) * 100) : 0;
  const avgViewsPerListing = listings.length ? Math.round((totalViews / listings.length) * 10) / 10 : 0;
  const saveToViewRatio = totalViews ? Math.round((totalSaves / totalViews) * 100) : 0;
  return {
    summary: {
      totalListings: listings.length,
      pendingListings: pendingListings.length,
      approvedListings: approvedListings.length,
      rejectedListings: rejectedListings.length,
      hiddenListings: hiddenListings.length,
      deletedListings: deletedListings.length,
      totalAgents: brokerDirectory.length,
      totalUsers: users.length,
      totalViews,
      totalSaves,
      totalBrokerViews,
      privateListings,
      agentListings,
      studentDiscoverableListings,
      registeredAgents,
      notRegisteredAgents,
      approvalRate,
      rejectionRate,
      avgViewsPerListing,
      saveToViewRatio
    },
    users,
    pendingListings,
    liveListings: approvedListings.slice(0, 50),
    allListings,
    recentUsers: users.slice(0, 10),
    recentAgents: brokerDirectory.slice(0, 10),
    recentReports: [],
    agents: brokerDirectory,
    fieldAgents: users.filter((user) => user.role === "field_agent").slice(0, 20),
    propertyRequests: [],
    whatsappSummary: {
      total_conversations: 0,
      active_7d: 0,
      needs_human: 0,
      resolved: 0,
      autopilot: 0,
      copilot: 0,
      manual_only: 0
    },
    whatsappConversations: []
  };
}

function buildLocalAdminAreaInsights(listings = []) {
  const counts = {};
  (listings || []).forEach((p) => {
    const key = [p.area, p.district].filter(Boolean).join(", ") || "Unknown area";
    counts[key] = (counts[key] || 0) + getPropertyViewCount(p.id);
  });
  return Object.entries(counts)
    .map(([area, events]) => ({ area, events }))
    .sort((a, b) => b.events - a.events)
    .slice(0, 5);
}

function buildAdminAiSnapshot(remoteSnap, localSnap, sourceLabel = "") {
  const summary = remoteSnap?.summary || {};
  const insights = summary?.ai_insights || {};
  const users = summary?.users || {};
  const engagement = summary?.engagement || {};
  const localSummary = localSnap?.summary || {};
  const topAreas = Array.isArray(insights.top_areas) && insights.top_areas.length
    ? insights.top_areas
    : buildLocalAdminAreaInsights(localSnap?.allListings || []);
  const topListingTypes = Array.isArray(insights.top_listing_types) ? insights.top_listing_types : [];
  return {
    source: sourceLabel || "Dashboard data",
    views48h: Number(insights.last_48h?.property_views ?? 0),
    visitors48h: Number(insights.last_48h?.unique_visitors ?? 0),
    routeEvents48h: Number(insights.last_48h?.route_events ?? 0),
    inquiries48h: Number(insights.last_48h?.property_inquiries ?? 0),
    totalViews: Number(engagement.property_views ?? localSummary.totalViews ?? 0),
    totalSaves: Number(engagement.property_saves ?? localSummary.totalSaves ?? 0),
    weeklyTips: Number(users.weekly_tips_opt_in ?? (localSnap?.recentUsers || []).filter((u) => u.weekly_tips_opt_in !== false).length ?? 0),
    totalUsers: Number(users.total ?? localSummary.totalUsers ?? 0),
    pendingListings: Number(summary?.properties?.pending ?? localSummary.pendingListings ?? 0),
    approvedListings: Number(summary?.properties?.approved ?? localSummary.approvedListings ?? 0),
    topAreas,
    topListingTypes
  };
}

function renderAdminAiAssistant(remoteSnap, localSnap, sourceLabel = "") {
  adminAiSnapshot = buildAdminAiSnapshot(remoteSnap, localSnap, sourceLabel);
  const setText = (id, value) => {
    const el = document.getElementById(id);
    if (el) el.textContent = String(value);
  };
  setText("admin-ai-views-48h", adminAiSnapshot.views48h);
  setText("admin-ai-visitors-48h", adminAiSnapshot.visitors48h);
  setText("admin-ai-weekly-tips", adminAiSnapshot.weeklyTips);
  setText("admin-ai-top-area", adminAiSnapshot.topAreas[0]?.area || "-");
  setText("admin-ai-source", remoteSnap ? "Live data" : "Local data");
  const answer = document.getElementById("admin-ai-answer");
  if (answer) {
    answer.innerHTML = `
      <div class="font-semibold text-gray-900">Snapshot ready.</div>
      <div class="mt-1">Last 48h: <strong>${adminAiSnapshot.views48h}</strong> property views, <strong>${adminAiSnapshot.visitors48h}</strong> visitors, <strong>${adminAiSnapshot.routeEvents48h}</strong> direction opens, and <strong>${adminAiSnapshot.inquiries48h}</strong> enquiries.</div>
      <div class="mt-1">Top area: <strong>${adminEscape(adminAiSnapshot.topAreas[0]?.area || "not enough data yet")}</strong>.</div>`;
  }
}

function askAdminAiAssistant() {
  if (!adminAiSnapshot) {
    toast("Refresh admin data first.");
    return;
  }
  const q = (document.getElementById("admin-ai-question")?.value || "").toLowerCase().trim();
  const answer = document.getElementById("admin-ai-answer");
  if (!answer) return;
  let html = "";
  if (q.includes("two") || q.includes("2") || q.includes("48") || q.includes("visit")) {
    html = `In the last 48 hours the site recorded <strong>${adminAiSnapshot.views48h}</strong> property views from <strong>${adminAiSnapshot.visitors48h}</strong> visitors, plus <strong>${adminAiSnapshot.routeEvents48h}</strong> direction opens and <strong>${adminAiSnapshot.inquiries48h}</strong> enquiries.`;
  } else if (q.includes("area") || q.includes("target") || q.includes("where")) {
    const rows = adminAiSnapshot.topAreas.length
      ? adminAiSnapshot.topAreas.map((row, idx) => `<li>${idx + 1}. ${adminEscape(row.area || "Unknown")} - ${adminEscape(row.events || 0)} events</li>`).join("")
      : "<li>No area data yet.</li>";
    html = `<div>Best current areas to target:</div><ol class="list-decimal pl-5 mt-1">${rows}</ol>`;
  } else if (q.includes("tips") || q.includes("account") || q.includes("users")) {
    html = `<strong>${adminAiSnapshot.weeklyTips}</strong> users are opted in for weekly tips out of <strong>${adminAiSnapshot.totalUsers}</strong> accounts.`;
  } else {
    html = `Current platform snapshot: <strong>${adminAiSnapshot.approvedListings}</strong> live listings, <strong>${adminAiSnapshot.pendingListings}</strong> pending listings, <strong>${adminAiSnapshot.totalViews}</strong> total views, and <strong>${adminAiSnapshot.totalSaves}</strong> saves.`;
  }
  answer.innerHTML = html;
}

function adminAuthHeaders() {
  if (adminApiKey) return { "x-api-key": adminApiKey };
  if (authState?.token && derivePortalMode(authState.user, authState.user?.portal_mode) === "admin") {
    return { Authorization: `Bearer ${authState.token}` };
  }
  return {};
}

function canUseLiveAdminApi() {
  return !!(adminApiKey || (authState?.token && derivePortalMode(authState.user, authState.user?.portal_mode) === "admin"));
}

function normalizeRemoteAdminListing(p) {
  const id = String(p?.id || "");
  return {
    ...p,
    id,
    backend_id: id,
    type: normalizeType(p?.listing_type || p?.type),
    subtype: p?.property_type || p?.subtype,
    img: p?.primary_image_url || p?.img,
    moderation_status: normalizeModerationStatus(p?.status)
  };
}

function adminEscape(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function adminAttr(value) {
  return adminEscape(value);
}

function adminListingIdArg(value) {
  return adminEscape(JSON.stringify(String(value || "")));
}

function propertyIdArg(value) {
  return adminListingIdArg(value);
}

function adminStatusBadge(status) {
  const st = normalizeModerationStatus(status);
  if (st === "approved") return { cls: "bg-green-100 text-green-700", label: "Live" };
  if (st === "sold") return { cls: "bg-blue-100 text-blue-700", label: "Sold" };
  if (st === "pending") return { cls: "bg-amber-100 text-amber-700", label: "Pending" };
  if (st === "rejected") return { cls: "bg-red-100 text-red-700", label: "Rejected" };
  if (st === "hidden") return { cls: "bg-yellow-100 text-yellow-800", label: "Hidden" };
  if (st === "deleted") return { cls: "bg-gray-200 text-gray-700", label: "Deleted" };
  return { cls: "bg-gray-100 text-gray-700", label: st || "Unknown" };
}

function adminVerificationBadge(status) {
  const st = String(status || "").toLowerCase() === "registered" ? "registered" : "not_registered";
  if (st === "registered") return { cls: "bg-green-100 text-green-700", label: "Verified / Registered" };
  return { cls: "bg-gray-100 text-gray-700", label: "Review needed" };
}

function setAdminWorkflowTab(tab = "review") {
  const allowed = ["review", "actioned", "live", "accounts", "ads", "whatsapp", "notifications", "listings"];
  activeAdminWorkflowTab = allowed.includes(String(tab)) ? String(tab) : "review";
  document.querySelectorAll("[data-admin-tab-panel]").forEach((panel) => {
    panel.classList.toggle("hidden", panel.dataset.adminTabPanel !== activeAdminWorkflowTab);
  });
  document.querySelectorAll("[data-admin-tab-button]").forEach((button) => {
    const active = button.dataset.adminTabButton === activeAdminWorkflowTab;
    button.classList.toggle("bg-gray-900", active);
    button.classList.toggle("text-white", active);
    button.classList.toggle("bg-gray-100", !active);
    button.classList.toggle("text-gray-700", !active);
  });
  if (activeAdminWorkflowTab !== "review") closeAdminReviewPanel();
}

async function fetchRemoteAdminSnapshot() {
  if (!canUseLiveAdminApi()) return null;
  const headers = adminAuthHeaders();
  const userSearch = (document.getElementById("admin-users-q")?.value || "").trim();
  const userRole = (document.getElementById("admin-users-role")?.value || "").trim();
  const weeklyOnly = (document.getElementById("admin-users-tips")?.value || "") === "weekly";
  const whatsappSearch = (document.getElementById("admin-whatsapp-search")?.value || "").trim();
  const whatsappStatus = (document.getElementById("admin-whatsapp-status")?.value || "").trim();
  const whatsappCategory = (document.getElementById("admin-whatsapp-category")?.value || "").trim();
  const whatsappAiMode = (document.getElementById("admin-whatsapp-ai-mode")?.value || "").trim();
  const userParams = new URLSearchParams({ limit: "100" });
  const propertyRequestParams = new URLSearchParams({ limit: "100" });
  const fieldAgentParams = new URLSearchParams({ limit: "100", role: "field_agent" });
  const whatsappParams = new URLSearchParams({ limit: "50" });
  if (userSearch) userParams.set("search", userSearch);
  if (userRole) userParams.set("role", userRole);
  if (weeklyOnly) userParams.set("weekly_tips_only", "true");
  if (whatsappSearch) whatsappParams.set("search", whatsappSearch);
  if (whatsappStatus) whatsappParams.set("status", whatsappStatus);
  if (whatsappCategory) whatsappParams.set("category", whatsappCategory);
  if (whatsappAiMode) whatsappParams.set("ai_mode", whatsappAiMode);
  const [summaryRes, recentRes, pendingRes, allRes, usersRes, agentsRes, propertyRequestsRes, fieldAgentsRes, campaignsRes, adPackagesRes, adPlacementsRes, adSummaryRes, adInquiriesRes, adCampaignsRes, whatsappInsightsRes, whatsappConversationsRes, crmSummaryRes, crmLeadsRes, notificationsRes, emailsRes, whatsappLogsRes] = await Promise.all([
    apiRequest("/api/admin/summary", { headers }),
    apiRequest("/api/admin/recent", { headers }),
    apiRequest("/api/properties?status=pending&limit=100", { headers }),
    apiRequest("/api/properties?status=all&limit=100", { headers }),
    apiRequest(`/api/admin/users?${userParams.toString()}`, { headers }),
    apiRequest("/api/admin/agents?limit=100", { headers }),
    apiRequest(`/api/admin/property-requests?${propertyRequestParams.toString()}`, { headers }),
    apiRequest(`/api/admin/users?${fieldAgentParams.toString()}`, { headers }),
    apiRequest("/api/admin/campaigns?limit=20", { headers }),
    apiRequest("/api/admin/advertising/packages", { headers }),
    apiRequest("/api/admin/advertising/placements", { headers }),
    apiRequest("/api/admin/advertising/summary", { headers }),
    apiRequest("/api/admin/advertising/inquiries?limit=100", { headers }),
    apiRequest("/api/admin/advertising/campaigns?limit=100", { headers }),
    apiRequest("/api/admin/whatsapp/insights", { headers }),
    apiRequest(`/api/admin/whatsapp/conversations?${whatsappParams.toString()}`, { headers }),
    apiRequest("/api/admin/crm/summary", { headers }),
    apiRequest("/api/admin/leads?limit=50", { headers }),
    apiRequest("/api/admin/notifications?limit=50", { headers }),
    apiRequest("/api/admin/emails?limit=50", { headers }),
    apiRequest("/api/admin/whatsapp-message-logs?limit=50", { headers })
  ]);
  const pendingListings = (pendingRes?.data || []).map(normalizeRemoteAdminListing);
  const allListings = (allRes?.data || []).map(normalizeRemoteAdminListing);
  let liveListings = allListings.filter((p) => ["approved", "sold"].includes(normalizeModerationStatus(p.status)));
  try {
    const liveRes = await apiRequest("/api/admin/properties/live?limit=100", { headers });
    liveListings = (liveRes?.data || []).map(normalizeRemoteAdminListing);
  } catch (e) {}
  adminRemoteListings = allListings;
  adminLiveListings = liveListings;
  adminRemoteAgents = Array.isArray(agentsRes?.data) ? agentsRes.data.map(mapRemoteAgentForUi) : [];
  adminPropertyRequests = Array.isArray(propertyRequestsRes?.data) ? propertyRequestsRes.data : [];
  adminFieldAgents = Array.isArray(fieldAgentsRes?.data) ? fieldAgentsRes.data : [];
  adminCurrentCampaigns = Array.isArray(campaignsRes?.data) ? campaignsRes.data : [];
  adminAdvertisingPackages = Array.isArray(adPackagesRes?.data) ? adPackagesRes.data : [];
  adminAdvertisingPlacements = Array.isArray(adPlacementsRes?.data) ? adPlacementsRes.data : [];
  adminAdvertisingSummary = adSummaryRes?.data || {};
  adminAdvertisingInquiries = Array.isArray(adInquiriesRes?.data) ? adInquiriesRes.data : [];
  adminAdvertisingCampaigns = Array.isArray(adCampaignsRes?.data) ? adCampaignsRes.data : [];
  adminWhatsappSummary = {
    ...(whatsappInsightsRes?.data || {}),
    ...(whatsappConversationsRes?.summary || {}),
    webBridge: whatsappInsightsRes?.data?.webBridge || {}
  };
  adminWhatsappConversations = Array.isArray(whatsappConversationsRes?.data) ? whatsappConversationsRes.data : [];
  adminCrmSummary = crmSummaryRes?.data || {};
  adminCrmLeads = Array.isArray(crmLeadsRes?.data) ? crmLeadsRes.data : [];
  adminCrmTasks = Array.isArray(crmSummaryRes?.data?.openTasks) ? crmSummaryRes.data.openTasks : [];
  adminNotificationLogs = Array.isArray(notificationsRes?.data) ? notificationsRes.data : [];
  adminEmailLogs = Array.isArray(emailsRes?.data) ? emailsRes.data : [];
  adminWhatsappLogs = Array.isArray(whatsappLogsRes?.data) ? whatsappLogsRes.data : [];
  return {
    summary: summaryRes?.data || {},
    recent: recentRes?.data || {},
    pendingListings,
    liveListings,
    allListings,
    users: usersRes?.data || [],
    agents: adminRemoteAgents,
    propertyRequests: adminPropertyRequests,
    fieldAgents: adminFieldAgents,
    campaigns: adminCurrentCampaigns,
    advertisingPackages: adminAdvertisingPackages,
    advertisingPlacements: adminAdvertisingPlacements,
    advertisingSummary: adminAdvertisingSummary,
    advertisingInquiries: adminAdvertisingInquiries,
    advertisingCampaigns: adminAdvertisingCampaigns,
    whatsappSummary: adminWhatsappSummary,
    whatsappConversations: adminWhatsappConversations,
    crmSummary: adminCrmSummary,
    crmLeads: adminCrmLeads,
    crmTasks: adminCrmTasks,
    notificationLogs: adminNotificationLogs,
    emailLogs: adminEmailLogs,
    whatsappLogs: adminWhatsappLogs
  };
}

function renderAdminPendingRows(listings) {
  const wrap = document.getElementById("admin-pending-table");
  if (!wrap) return;
  if (!listings.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No pending listings in the current snapshot.</div>`;
    return;
  }
  wrap.innerHTML = listings.map((p) => {
    const statusMeta = adminStatusBadge(p.status);
    const locationText = [p.area, p.district].filter(Boolean).join(", ") || "-";
    const createdText = listingDateMeta(p);
    const localId = String(p.id || "");
    const backendId = String(p.backend_id || p.id || "");
    const reviewId = backendId || localId;
    const reviewArg = adminListingIdArg(reviewId);
    const featured = isFeaturedListing(p);
    return `
      <div class="border border-gray-200 rounded-xl p-4 bg-white">
        <div class="flex justify-between items-start gap-3 flex-wrap">
          <div>
            <div class="font-bold text-gray-800">${adminEscape(p.title || "Untitled listing")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape(locationText)}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape(createdText)} • Ref: ${adminEscape(p.inquiry_reference || reviewId || "-")}</div>
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${statusMeta.cls}">${statusMeta.label}</span>
        </div>
        <div class="mt-3 flex gap-2 flex-wrap">
          <button onclick="openAdminListingReview(${reviewArg})" class="bg-gray-900 hover:bg-gray-800 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Open Review</button>
          <button onclick="adminQuickRejectListing(${reviewArg})" class="border border-red-200 text-red-600 hover:bg-red-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Reject</button>
        </div>
      </div>`;
  }).join("");
}

function renderAdminActionedRows(listings) {
  const wrap = document.getElementById("admin-actioned-table");
  if (!wrap) return;
  const view = [...(listings || [])]
    .filter((p) => ["approved", "sold", "rejected", "hidden", "deleted"].includes(normalizeModerationStatus(p.status)))
    .sort((a, b) => {
      const ad = parseDateSafe(a.reviewed_at || a.approved_at || a.updated_at || a.created_at)?.getTime() || 0;
      const bd = parseDateSafe(b.reviewed_at || b.approved_at || b.updated_at || b.created_at)?.getTime() || 0;
      return bd - ad;
    })
    .slice(0, 10);
  if (!view.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No actioned listings yet.</div>`;
    return;
  }
  wrap.innerHTML = view.map((p) => {
    const status = normalizeModerationStatus(p.status);
    const meta = adminStatusBadge(status);
    const id = String(p.backend_id || p.id || "");
    const idArg = adminListingIdArg(id);
    const actionText = status === "approved"
      ? "Moved to Live Listings"
      : status === "rejected"
        ? "Moved to Rejected"
        : status === "hidden"
          ? "Moved to Hidden"
          : "Moved to Deleted";
    return `
      <div class="border border-gray-200 rounded-xl p-4 bg-white">
        <div class="flex items-start justify-between gap-3 flex-wrap">
          <div>
            <div class="font-bold text-gray-800">${adminEscape(p.title || "Untitled listing")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape([p.area, p.district].filter(Boolean).join(", ") || "-")} • Ref: ${adminEscape(p.inquiry_reference || id || "-")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape(actionText)} • ${adminEscape(formatListingDate(p.reviewed_at || p.approved_at || p.updated_at || p.created_at))}</div>
            ${status === "rejected" ? `<div class="text-xs text-red-700 mt-1">${adminEscape(p.moderation_reason || p.extra_fields?.moderation_reason || "Rejection reason saved on the review record.")}</div>` : ""}
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${meta.cls}">${meta.label}</span>
        </div>
        <div class="mt-3 flex gap-2 flex-wrap">
          <button onclick="openAdminListingReview(${idArg})" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Open Record</button>
          ${status === "approved" ? `<button onclick="openAdminFollowUpWhatsApp(${idArg})" class="bg-green-700 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Owner Message</button>` : ""}
          ${status === "rejected" ? `<button onclick="openAdminRejectedListingWhatsApp(${idArg})" class="bg-red-600 hover:bg-red-500 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Contact Lister</button>` : ""}
          ${status === "rejected" || status === "deleted" ? `<button onclick="adminSetListingStatus(${idArg}, 'pending', ${idArg})" class="border border-amber-300 text-amber-700 hover:bg-amber-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Restore to Pending</button>` : ""}
          ${status === "hidden" || status === "sold" ? `<button onclick="adminSetListingStatus(${idArg}, 'approved', ${idArg})" class="border border-green-300 text-green-700 hover:bg-green-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Restore Live</button>` : ""}
          ${status === "approved" ? `<button onclick="adminSetListingStatus(${idArg}, 'deleted', ${idArg})" class="bg-gray-800 hover:bg-gray-700 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Remove from Site</button>` : ""}
        </div>
      </div>`;
  }).join("");
}

function adminLiveAtText(p) {
  return formatListingDate(p.live_at || p.approved_at || p.reviewed_at || p.updated_at || p.created_at);
}

function adminFollowUpText(p) {
  const due = p.follow_up_due_at || "";
  if (!due) return "Follow-up date not set";
  return `${p.follow_up_due ? "Due now" : "Due"} • ${formatListingDate(due)}`;
}

function buildAdminFollowUpWhatsAppMessage(p = {}) {
  const name = p.lister_name || "there";
  const ref = p.inquiry_reference || p.id || "-";
  const title = p.title || "your MakaUg property listing";
  const liveAt = adminLiveAtText(p);
  return [
    `Hello ${name}, this is MakaUg.`,
    `Your listing is live: ${title}`,
    `Reference: ${ref}`,
    `Live since: ${liveAt}`,
    "",
    "Has the property sold or rented, or should we keep promoting it for you?"
  ].join("\n");
}

function renderAdminFeaturedRows(listings) {
  const wrap = document.getElementById("admin-featured-listings-table");
  if (!wrap) return;
  const live = [...(listings || [])]
    .filter((p) => normalizeModerationStatus(p.status) === "approved")
    .sort((a, b) => {
      const af = isFeaturedListing(a) ? 1 : 0;
      const bf = isFeaturedListing(b) ? 1 : 0;
      if (af !== bf) return bf - af;
      const ad = parseDateSafe(a.featured_at || a.extra_fields?.featured_at || a.approved_at || a.updated_at || a.created_at)?.getTime() || 0;
      const bd = parseDateSafe(b.featured_at || b.extra_fields?.featured_at || b.approved_at || b.updated_at || b.created_at)?.getTime() || 0;
      return bd - ad;
    })
    .slice(0, 75);
  if (!live.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No live listings available for featured placement yet.</div>`;
    return;
  }
  wrap.innerHTML = live.map((p) => {
    const id = String(p.backend_id || p.id || "");
    const idArg = adminListingIdArg(id);
    const featured = isFeaturedListing(p);
    return `
      <div class="border ${featured ? "border-green-200 bg-green-50" : "border-gray-200 bg-white"} rounded-xl p-4">
        <div class="flex items-start justify-between gap-3 flex-wrap">
          <div class="min-w-0">
            <div class="font-bold text-gray-800 break-words">${adminEscape(p.title || "Untitled listing")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape([p.area, p.district].filter(Boolean).join(", ") || "-")} • Ref: ${adminEscape(p.inquiry_reference || id || "-")}</div>
            <div class="text-xs text-gray-500 mt-1">${featured ? `Featured since ${adminEscape(formatListingDate(p.featured_at || p.extra_fields?.featured_at || p.updated_at))}` : "Not currently on the homepage featured section."}</div>
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${featured ? "bg-green-700 text-white" : "bg-gray-100 text-gray-700"}">${featured ? "Featured" : "Available"}</span>
        </div>
        <div class="mt-3 flex flex-wrap gap-2">
          <button onclick="openAdminListingLivePreview(${idArg})" class="border border-green-700 text-green-700 hover:bg-white px-3 py-1.5 rounded-lg text-xs font-semibold">Preview</button>
          <button onclick="adminSetListingFeatured(${idArg}, ${featured ? "false" : "true"})" class="${featured ? "bg-gray-800 hover:bg-gray-700" : "bg-green-700 hover:bg-green-600"} text-white px-3 py-1.5 rounded-lg text-xs font-semibold">${featured ? "Remove Featured" : "Feature on Homepage"}</button>
        </div>
      </div>`;
  }).join("");
}

function renderAdminLiveListingsRows(listings) {
  const wrap = document.getElementById("admin-live-listings-table");
  if (!wrap) return;
  const view = [...(listings || [])].filter((p) => ["approved", "sold"].includes(normalizeModerationStatus(p.status))).slice(0, 50);
  if (!view.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No live listings found yet.</div>`;
    return;
  }
  wrap.innerHTML = view.map((p) => {
    const id = String(p.backend_id || p.id || "");
    const idArg = adminListingIdArg(id);
    const featured = isFeaturedListing(p);
    const followClass = p.follow_up_due ? "bg-amber-100 text-amber-800" : "bg-green-100 text-green-700";
    return `
      <div class="border border-gray-200 rounded-xl p-4 bg-white">
        <div class="flex items-start justify-between gap-3 flex-wrap">
          <div class="min-w-0">
            <div class="font-bold text-gray-800 break-words">${adminEscape(p.title || "Untitled listing")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape([p.area, p.district].filter(Boolean).join(", ") || "-")} • Ref: ${adminEscape(p.inquiry_reference || id || "-")}</div>
            <div class="text-xs text-gray-500 mt-1">Live: ${adminEscape(adminLiveAtText(p))} • Owner: ${adminEscape(p.lister_name || "-")} • ${adminEscape(p.lister_phone || p.lister_email || "-")}</div>
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${followClass}">${adminEscape(adminFollowUpText(p))}</span>
        </div>
        <div class="mt-3 flex flex-wrap gap-2">
          <button onclick="openAdminListingLivePreview(${idArg})" class="border border-green-700 text-green-700 hover:bg-green-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Open Live Listing</button>
          <button onclick="openAdminFollowUpWhatsApp(${idArg})" class="bg-green-700 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">WhatsApp Follow-up</button>
          <button onclick="adminSetListingStatus(${idArg}, 'sold', ${idArg})" class="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Mark Sold</button>
          <button onclick="adminSetListingFeatured(${idArg}, ${featured ? "false" : "true"})" class="${featured ? "bg-gray-800 hover:bg-gray-700" : "bg-emerald-700 hover:bg-emerald-600"} text-white px-3 py-1.5 rounded-lg text-xs font-semibold">${featured ? "Remove Featured" : "Feature"}</button>
          <button onclick="adminSetListingStatus(${idArg}, 'hidden', ${idArg})" class="bg-yellow-500 hover:bg-yellow-400 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Hide</button>
          <button onclick="adminSetListingStatus(${idArg}, 'deleted', ${idArg})" class="bg-gray-800 hover:bg-gray-700 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Remove from Site</button>
          <button onclick="openAdminListingReview(${idArg})" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Review Record</button>
        </div>
      </div>`;
  }).join("");
}

function renderAdminAllListingsRows(listings) {
  const wrap = document.getElementById("admin-all-listings-table");
  if (!wrap) return;
  const q = (document.getElementById("admin-listings-q")?.value || "").toLowerCase().trim();
  const statusFilter = (document.getElementById("admin-listings-status")?.value || "").toLowerCase().trim();
  let view = [...(listings || [])];
  if (statusFilter) {
    view = view.filter((p) => normalizeModerationStatus(p.status) === statusFilter);
  }
  if (q) {
    view = view.filter((p) => {
      const hay = [
        p.title,
        p.area,
        p.district,
        p.city,
        p.subtype,
        p.id
      ].filter(Boolean).join(" ").toLowerCase();
      return hay.includes(q);
    });
  }
  if (!view.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No listings match this filter.</div>`;
    return;
  }
  wrap.innerHTML = view.map((p) => {
    const status = normalizeModerationStatus(p.status);
    const meta = adminStatusBadge(status);
    const featured = isFeaturedListing(p);
    const localId = String(p.id || "");
    const backendId = String(p.backend_id || p.id || "");
    const reviewId = backendId || localId;
    const reviewArg = adminListingIdArg(reviewId);
    return `
      <div class="border border-gray-200 rounded-xl p-4 bg-white">
        <div class="flex items-start justify-between gap-3 flex-wrap">
          <div>
            <div class="font-bold text-gray-800">${adminEscape(p.title || "Untitled listing")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape([p.area, p.district].filter(Boolean).join(", ") || "-")}</div>
            <div class="text-xs text-gray-500 mt-1">ID: ${adminEscape(localId || "-")} • ${adminEscape(listingDateMeta(p))}</div>
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${meta.cls}">${meta.label}</span>
        </div>
        <div class="mt-3 flex flex-wrap gap-2">
          <button onclick="openAdminListingReview(${reviewArg})" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Review</button>
          ${status !== "pending" ? `<button onclick="adminSetListingStatus(${reviewArg}, 'pending', ${reviewArg})" class="bg-amber-500 hover:bg-amber-400 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Set Pending</button>` : ""}
          ${status === "approved" ? `<button onclick="adminSetListingFeatured(${reviewArg}, ${featured ? "false" : "true"})" class="${featured ? "bg-gray-800 hover:bg-gray-700" : "bg-emerald-700 hover:bg-emerald-600"} text-white px-3 py-1.5 rounded-lg text-xs font-semibold">${featured ? "Remove Featured" : "Feature"}</button>` : ""}
          ${status !== "hidden" ? `<button onclick="adminSetListingStatus(${reviewArg}, 'hidden', ${reviewArg})" class="bg-yellow-500 hover:bg-yellow-400 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Hide</button>` : ""}
          ${status !== "deleted" ? `<button onclick="adminSetListingStatus(${reviewArg}, 'deleted', ${reviewArg})" class="bg-gray-800 hover:bg-gray-700 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Delete</button>` : ""}
        </div>
      </div>
    `;
  }).join("");
}

function renderAdminList(id, items, renderer) {
  const el = document.getElementById(id);
  if (!el) return;
  if (!items || !items.length) {
    el.innerHTML = `<div class="text-sm text-gray-500">No data available.</div>`;
    return;
  }
  el.innerHTML = items.map(renderer).join("");
}

function renderAdminCrmOverview(summary = {}) {
  const wrap = document.getElementById("admin-crm-overview");
  if (!wrap) return;
  const leadTotal = Number(summary.leads?.total || adminCrmLeads.length || 0);
  const openLeads = Number(summary.leads?.open || 0);
  const hotLeads = Number(summary.leads?.hot || 0);
  const unassigned = Number(summary.leads?.unassigned || 0);
  const overdueTasks = Number(summary.tasks?.overdue || 0);
  const failedNotifications = Number(summary.notifications?.failed || adminNotificationLogs.filter((row) => String(row.status || "").toLowerCase() === "failed").length || 0);
  const stat = (label, value, tone = "gray") => {
    const tones = {
      green: "bg-green-50 border-green-100 text-green-800",
      amber: "bg-amber-50 border-amber-100 text-amber-800",
      red: "bg-red-50 border-red-100 text-red-700",
      gray: "bg-gray-50 border-gray-200 text-gray-900"
    };
    return `<div class="rounded-2xl border ${tones[tone] || tones.gray} p-4">
      <div class="text-[11px] uppercase tracking-wide font-bold opacity-70">${adminEscape(label)}</div>
      <div class="text-2xl font-black mt-1">${adminEscape(value)}</div>
    </div>`;
  };
  wrap.innerHTML = [
    stat("Total Leads", leadTotal, "green"),
    stat("Open Leads", openLeads, "amber"),
    stat("Hot Leads", hotLeads, "red"),
    stat("Unassigned", unassigned, "amber"),
    stat("Overdue Tasks", overdueTasks, overdueTasks ? "red" : "gray"),
    stat("Failed Notices", failedNotifications, failedNotifications ? "red" : "gray")
  ].join("");
}

function renderAdminCrmLeadsRows(leads = []) {
  const wrap = document.getElementById("admin-crm-leads-table");
  if (!wrap) return;
  const rows = Array.isArray(leads) ? leads : [];
  if (!rows.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-white border border-gray-200 rounded-xl p-4">No CRM leads in this snapshot yet. New WhatsApp clicks, saved searches, viewings, callbacks, property needs, advertiser signups, and mortgage requests will appear here.</div>`;
    return;
  }
  wrap.innerHTML = rows.slice(0, 25).map((lead) => {
    const score = Number(lead.lead_score || 0);
    const hot = score >= 50 || String(lead.priority || "").toLowerCase() === "urgent";
    return `<div class="border border-gray-200 rounded-xl p-4 bg-white">
      <div class="flex items-start justify-between gap-3 flex-wrap">
        <div>
          <div class="font-bold text-gray-800">${adminEscape(lead.category || lead.lead_type || "Lead")} ${lead.location ? `• ${adminEscape(lead.location)}` : ""}</div>
          <div class="text-xs text-gray-500 mt-1">${adminEscape(lead.contact_name || "Unknown contact")} • ${adminEscape(lead.contact_phone || lead.contact_email || "-")}</div>
          <div class="text-xs text-gray-500 mt-1">Source: ${adminEscape(lead.source || "-")} • Stage: ${adminEscape(lead.lifecycle_stage || "-")} • Status: ${adminEscape(lead.lead_status || "-")}</div>
          ${lead.message ? `<div class="text-xs text-gray-700 mt-2">${adminEscape(lead.message).slice(0, 180)}</div>` : ""}
        </div>
        <span class="text-xs font-bold px-2 py-1 rounded-full ${hot ? "bg-red-100 text-red-700" : "bg-green-100 text-green-700"}">Score ${adminEscape(score)}</span>
      </div>
    </div>`;
  }).join("");
}

function renderAdminCrmTasksRows(tasks = []) {
  const wrap = document.getElementById("admin-crm-tasks-table");
  if (!wrap) return;
  const rows = Array.isArray(tasks) ? tasks : [];
  if (!rows.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-white border border-gray-200 rounded-xl p-4">No open follow-up tasks yet.</div>`;
    return;
  }
  wrap.innerHTML = rows.slice(0, 15).map((task) => `
    <div class="border border-gray-200 rounded-xl p-3 bg-white">
      <div class="font-bold text-gray-800">${adminEscape(task.task_type || "Follow-up")}</div>
      <div class="text-xs text-gray-500 mt-1">${adminEscape(task.title || task.note || "Lead follow-up")} • ${adminEscape(task.due_at ? formatListingDate(task.due_at) : "No due date")}</div>
      <div class="text-xs text-gray-500 mt-1">Status: ${adminEscape(task.status || "open")} • Lead: ${adminEscape(task.lead_id || "-")}</div>
    </div>`).join("");
}

function adminLogStatusClass(status) {
  const st = String(status || "").toLowerCase();
  if (["failed", "bounced", "error"].includes(st)) return "bg-red-100 text-red-700";
  if (["queued", "pending"].includes(st)) return "bg-amber-100 text-amber-800";
  if (["sent", "delivered", "read", "logged"].includes(st)) return "bg-green-100 text-green-700";
  if (["skipped", "duplicate"].includes(st)) return "bg-gray-100 text-gray-700";
  return "bg-gray-100 text-gray-700";
}

function renderAdminLogRows(id, logs = [], options = {}) {
  const wrap = document.getElementById(id);
  if (!wrap) return;
  const rows = Array.isArray(logs) ? logs : [];
  if (!rows.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">${adminEscape(options.empty || "No log entries in this snapshot.")}</div>`;
    return;
  }
  wrap.innerHTML = rows.slice(0, 20).map((row) => {
    const event = row.event_type || row.type || row.template_key || row.templateKey || row.message_type || row.channel || "event";
    const status = row.status || "logged";
    const target = row.recipient_email_masked || row.recipient_phone_masked || row.recipient_email || row.recipient_phone || row.recipientPhoneMasked || row.related_lead_id || row.relatedListingId || row.related_listing_id || "-";
    const failure = row.failure_reason || row.failureReason || "";
    const ref = row.related_listing_id || row.relatedListingId || row.related_lead_id || row.relatedLeadId || row.related_campaign_id || row.relatedCampaignId || "";
    return `<div class="border border-gray-200 rounded-xl p-3 bg-white">
      <div class="flex items-start justify-between gap-2">
        <div class="min-w-0">
          <div class="font-bold text-gray-800 break-words">${adminEscape(event)}</div>
          <div class="text-xs text-gray-500 mt-1">${adminEscape(target)}${ref ? ` • Ref: ${adminEscape(ref)}` : ""}</div>
          ${failure ? `<div class="text-xs text-red-700 mt-1">${adminEscape(failure)}</div>` : ""}
          <div class="text-[11px] text-gray-400 mt-1">${adminEscape(formatListingDate(row.created_at || row.sent_at || row.createdAt || row.sentAt || new Date().toISOString()))}</div>
        </div>
        <span class="shrink-0 text-[11px] font-bold px-2 py-1 rounded-full ${adminLogStatusClass(status)}">${adminEscape(status)}</span>
      </div>
    </div>`;
  }).join("");
}

async function renderAdminDashboard() {
  const gate = document.getElementById("admin-auth-gate");
  const body = document.getElementById("admin-body");
  if (!gate || !body) return;

  if (!authState?.user || derivePortalMode(authState.user, authState.user.portal_mode) !== "admin") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }

  gate.classList.add("hidden");
  body.classList.remove("hidden");

  const nameEl = document.getElementById("admin-dashboard-name");
  const statusEl = document.getElementById("admin-dashboard-status");
  const sourceEl = document.getElementById("admin-summary-note");
  const keyInput = document.getElementById("admin-api-key");

  if (nameEl) nameEl.textContent = `${authState.user.first_name || "Admin"} ${authState.user.last_name || ""}`.trim();
  if (statusEl) statusEl.textContent = `Role: ${mapRoleLabel(authState.user.role)} • ${authState.user.email || authState.user.phone || "-"}`;
  if (keyInput && document.activeElement !== keyInput) keyInput.value = adminApiKey;

  const localSnap = buildLocalAdminSnapshot();
  let remoteSnap = null;
  let sourceLabel = "Data source: local browser data.";

  if (canUseLiveAdminApi()) {
    try {
      remoteSnap = await fetchRemoteAdminSnapshot();
      sourceLabel = adminApiKey ? "Data source: live admin API." : "Data source: live admin API via signed-in admin.";
    } catch (e) {
      sourceLabel = `Live API unavailable (${e.message || "request failed"}). Showing local browser data.`;
    }
  }

  const summary = remoteSnap?.summary || {};
  const totalListings = summary?.properties?.total ?? localSnap.summary.totalListings;
  const pendingListings = summary?.properties?.pending ?? localSnap.summary.pendingListings;
  const approvedListings = summary?.properties?.approved ?? localSnap.summary.approvedListings;
  const rejectedListings = summary?.properties?.rejected ?? localSnap.summary.rejectedListings;
  const hiddenListings = summary?.properties?.hidden ?? localSnap.summary.hiddenListings;
  const deletedListings = summary?.properties?.deleted ?? localSnap.summary.deletedListings;
  const totalAgents = summary?.agents?.total ?? localSnap.summary.totalAgents;
  const totalUsers = summary?.users?.total ?? localSnap.summary.totalUsers;
  const totalViews = summary?.engagement?.property_views ?? localSnap.summary.totalViews;
  const totalSaves = summary?.engagement?.property_saves ?? localSnap.summary.totalSaves;
  const totalBrokerViews = summary?.engagement?.broker_profile_views ?? localSnap.summary.totalBrokerViews;
  const privateListings = summary?.properties?.private ?? localSnap.summary.privateListings;
  const agentListings = summary?.properties?.agent_listed ?? localSnap.summary.agentListings;
  const studentDiscoverableListings = summary?.properties?.student_discoverable ?? localSnap.summary.studentDiscoverableListings;
  const registeredAgents = summary?.agents?.registered ?? localSnap.summary.registeredAgents;
  const notRegisteredAgents = summary?.agents?.not_registered ?? localSnap.summary.notRegisteredAgents;
  const approvalRate = summary?.properties?.approval_rate_pct ?? localSnap.summary.approvalRate;
  const rejectionRate = summary?.properties?.rejection_rate_pct ?? localSnap.summary.rejectionRate;
  const avgViewsPerListing = summary?.engagement?.avg_views_per_listing ?? localSnap.summary.avgViewsPerListing;
  const saveToViewRatio = summary?.engagement?.save_to_view_ratio_pct ?? localSnap.summary.saveToViewRatio;

  const setText = (id, value) => {
    const el = document.getElementById(id);
    if (el) el.textContent = String(value);
  };
  setText("admin-stat-total-listings", totalListings);
  setText("admin-stat-pending", pendingListings);
  setText("admin-stat-approved", approvedListings);
  setText("admin-stat-rejected", rejectedListings);
  setText("admin-stat-hidden", hiddenListings);
  setText("admin-stat-deleted", deletedListings);
  setText("admin-stat-agents", totalAgents);
  setText("admin-stat-users", totalUsers);
  setText("admin-stat-total-views", totalViews);
  setText("admin-stat-total-saves", totalSaves);
  setText("admin-stat-broker-views", totalBrokerViews);
  setText("admin-stat-private", privateListings);
  setText("admin-stat-agent-listings", agentListings);
  setText("admin-stat-students", studentDiscoverableListings);
  setText("admin-stat-approval-rate", `${approvalRate}%`);
  setText("admin-stat-rejection-rate", `${rejectionRate}%`);
  setText("admin-stat-avg-views", avgViewsPerListing);
  setText("admin-stat-save-view-ratio", `${saveToViewRatio}%`);
  setText("admin-stat-registered-agents", registeredAgents);
  setText("admin-stat-not-registered-agents", notRegisteredAgents);
  setText("admin-stat-ad-leads", remoteSnap?.advertisingSummary?.open_inquiries ?? 0);
  setText("admin-stat-live-ads", remoteSnap?.advertisingSummary?.live_campaigns ?? 0);
  setText("admin-stat-ad-revenue", `UGX ${Number(remoteSnap?.advertisingSummary?.paid_revenue_ugx || 0).toLocaleString("en-UG")}`);
  if (sourceEl) sourceEl.textContent = sourceLabel;
  renderAdminAiAssistant(remoteSnap, localSnap, sourceLabel);

  const adminUsers = remoteSnap?.users || localSnap.users || [];
  const adminAgents = remoteSnap?.agents || localSnap.agents || [];
  renderAdminPendingRows(remoteSnap?.pendingListings || localSnap.pendingListings);
  renderAdminActionedRows(remoteSnap?.allListings || localSnap.allListings || []);
  renderAdminLiveListingsRows(remoteSnap?.liveListings || localSnap.liveListings || []);
  renderAdminFeaturedRows(remoteSnap?.allListings || localSnap.allListings || []);
  renderAdminOutreachOverview({
    summary,
    users: adminUsers,
    agents: adminAgents,
    fieldAgents: remoteSnap?.fieldAgents || localSnap.fieldAgents || [],
    propertyRequests: remoteSnap?.propertyRequests || localSnap.propertyRequests || [],
    campaigns: remoteSnap?.campaigns || []
  });
  renderAdminCampaignRows(remoteSnap?.campaigns || []);
  renderAdminAdvertisingOverview(remoteSnap?.advertisingSummary || {});
  renderAdminAdvertisingPackages(remoteSnap?.advertisingPackages || []);
  renderAdminAdvertisingPlacements(remoteSnap?.advertisingPlacements || []);
  renderAdminAdvertisingInquiries(remoteSnap?.advertisingInquiries || []);
  renderAdminAdvertisingCampaigns(remoteSnap?.advertisingCampaigns || []);
  renderAdminUsersRows(adminUsers);
  renderAdminBrokerRows(adminAgents);
  renderAdminFeaturedAgentsRows(adminAgents);
  renderAdminPropertyRequestRows(remoteSnap?.propertyRequests || localSnap.propertyRequests || []);
  renderAdminFieldAgentRows(remoteSnap?.fieldAgents || localSnap.fieldAgents || []);
  renderAdminWhatsappOverview(remoteSnap?.whatsappSummary || localSnap.whatsappSummary || {});
  renderAdminWhatsappConversationList(remoteSnap?.whatsappConversations || localSnap.whatsappConversations || []);
  renderAdminAllListingsRows(remoteSnap?.allListings || localSnap.allListings);
  renderAdminCrmOverview(remoteSnap?.crmSummary || {});
  renderAdminCrmLeadsRows(remoteSnap?.crmLeads || []);
  renderAdminCrmTasksRows(remoteSnap?.crmTasks || []);
  renderAdminLogRows("admin-notification-log", remoteSnap?.notificationLogs || [], { empty: "No notification records yet. Failed sends and safe provider-missing logs will appear here." });
  renderAdminLogRows("admin-email-log", remoteSnap?.emailLogs || [], { empty: "No email log records yet. Listing submissions, OTPs, account events, and failure logs will appear here." });
  renderAdminLogRows("admin-whatsapp-log", remoteSnap?.whatsappLogs || [], { empty: "No WhatsApp message log records yet. Template/freeform send attempts will appear here." });
  setAdminWorkflowTab(activeAdminWorkflowTab);
  await ensureAdminWhatsappConversationLoaded();
  renderAdminList("admin-recent-users", remoteSnap?.recent?.recentUsers || localSnap.recentUsers, (u) => `
    <div class="border border-gray-200 rounded-lg p-2.5">
      <div class="font-semibold text-gray-800">${u.first_name || ""} ${u.last_name || ""}</div>
      <div class="text-xs text-gray-500">${u.email || u.phone || "-"}</div>
      <div class="text-xs text-gray-500 mt-1">${mapRoleLabel(u.role || "buyer_renter")} • ${u.status || "active"}</div>
    </div>`);
  renderAdminList("admin-recent-agents", remoteSnap?.recent?.recentAgents || localSnap.recentAgents, (a) => `
    <div class="border border-gray-200 rounded-lg p-2.5">
      <div class="font-semibold text-gray-800">${a.full_name || a.name || "-"}</div>
      <div class="text-xs text-gray-500">${a.company_name || a.company || "-"}</div>
      <div class="text-xs text-gray-500 mt-1">${a.licence_number || a.licence || "No licence recorded"}</div>
      <div class="text-[11px] mt-1"><span class="inline-flex px-2 py-0.5 rounded-full ${adminVerificationBadge(a.registration_status).cls}">${adminVerificationBadge(a.registration_status).label}</span></div>
      <div class="text-[11px] mt-1"><span class="inline-flex px-2 py-0.5 rounded-full ${String(a.status || "").toLowerCase() === "approved" ? "bg-green-100 text-green-700" : String(a.status || "").toLowerCase() === "rejected" ? "bg-red-100 text-red-700" : String(a.status || "").toLowerCase() === "suspended" ? "bg-yellow-100 text-yellow-700" : "bg-amber-100 text-amber-700"}">${a.status || "pending"}</span></div>
      ${canUseLiveAdminApi() && a.id ? `
      <div class="flex flex-wrap gap-1.5 mt-2">
        <button onclick="adminSetAgentStatus('${a.id}','approved')" class="bg-green-700 hover:bg-green-600 text-white px-2 py-1 rounded text-[11px] font-semibold">Approve</button>
        <button onclick="adminSetAgentStatus('${a.id}','pending')" class="bg-amber-500 hover:bg-amber-400 text-white px-2 py-1 rounded text-[11px] font-semibold">Pending</button>
        <button onclick="adminSetAgentStatus('${a.id}','rejected')" class="bg-red-600 hover:bg-red-500 text-white px-2 py-1 rounded text-[11px] font-semibold">Reject</button>
        <button onclick="adminSetAgentStatus('${a.id}','suspended')" class="bg-yellow-500 hover:bg-yellow-400 text-white px-2 py-1 rounded text-[11px] font-semibold">Suspend</button>
        <button onclick="adminSetAgentRegistrationStatus('${a.id}','registered')" class="border border-green-700 text-green-700 hover:bg-green-50 px-2 py-1 rounded text-[11px] font-semibold">Mark Verified</button>
        <button onclick="adminSetAgentRegistrationStatus('${a.id}','not_registered')" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-2 py-1 rounded text-[11px] font-semibold">Mark Pending</button>
      </div>` : ""}
    </div>`);
  renderAdminList("admin-recent-reports", remoteSnap?.recent?.recentReports || localSnap.recentReports, (r) => `
    <div class="border border-gray-200 rounded-lg p-2.5">
      <div class="font-semibold text-gray-800">${r.property_reference || "Listing report"}</div>
      <div class="text-xs text-gray-500">${r.reason || "No reason provided"}</div>
      <div class="text-xs text-gray-500 mt-1">Status: ${r.status || "open"}</div>
      ${canUseLiveAdminApi() && r.id ? `
      <div class="flex flex-wrap gap-1.5 mt-2">
        <button onclick="adminSetReportStatus('${r.id}','in_review')" class="bg-amber-500 hover:bg-amber-400 text-white px-2 py-1 rounded text-[11px] font-semibold">In Review</button>
        <button onclick="adminSetReportStatus('${r.id}','resolved')" class="bg-green-700 hover:bg-green-600 text-white px-2 py-1 rounded text-[11px] font-semibold">Resolve</button>
        <button onclick="adminSetReportStatus('${r.id}','dismissed')" class="bg-gray-700 hover:bg-gray-600 text-white px-2 py-1 rounded text-[11px] font-semibold">Dismiss</button>
      </div>` : ""}
    </div>`);
}

function setupBadge(ok, label) {
  return `<span class="inline-flex px-2.5 py-1 rounded-full text-[11px] font-black ${ok ? "bg-green-100 text-green-700" : "bg-amber-100 text-amber-800"}">${adminEscape(label || (ok ? "Ready" : "Needs action"))}</span>`;
}

function renderAdminSetupStatusCards(status = {}) {
  const summary = document.getElementById("admin-setup-summary");
  if (!summary) return;
  const superAdmin = status.superAdmin || {};
  const dbStatus = status.database || {};
  const proof = status.launchProof || {};
  summary.innerHTML = [
    {
      title: "Super admin",
      value: superAdmin.exists ? "Exists" : "Missing",
      note: `Last login: ${superAdmin.lastLoginAt ? formatListingDate(superAdmin.lastLoginAt) : "not proven"}`
    },
    {
      title: "Migrations 033/034",
      value: (dbStatus.missingMigrations || []).length ? "Needs check" : "Applied",
      note: (dbStatus.missingMigrations || []).length ? `Missing: ${(dbStatus.missingMigrations || []).join(", ")}` : "Both launch migrations are visible."
    },
    {
      title: "Launch proof actions",
      value: Object.keys(proof.latest || {}).length,
      note: "Latest admin proof actions recorded in audit log."
    }
  ].map((card) => `<article class="bg-white border border-gray-200 rounded-2xl p-5">
    <div class="text-xs uppercase tracking-wide text-gray-500 font-black">${adminEscape(card.title)}</div>
    <div class="text-2xl font-black text-gray-900 mt-2">${adminEscape(card.value)}</div>
    <div class="text-xs text-gray-500 mt-2">${adminEscape(card.note)}</div>
  </article>`).join("");
}

function renderAdminSetupProviders(status = {}) {
  const wrap = document.getElementById("admin-setup-provider-status");
  if (!wrap) return;
  const providers = Array.isArray(status.providers) ? status.providers : [];
  wrap.innerHTML = providers.map((provider) => `<div class="rounded-2xl border border-gray-200 bg-gray-50 p-4">
    <div class="flex items-start justify-between gap-3">
      <div>
        <div class="font-black text-gray-900">${adminEscape(provider.label || provider.key)}</div>
        <div class="text-xs text-gray-500 mt-1">Required env: ${adminEscape((provider.requiredEnv || []).join(", ") || "none")}</div>
        ${provider.configured ? "" : `<div class="text-xs text-amber-700 mt-1">Missing: ${adminEscape((provider.missingEnv || []).join(", ") || "provider env")}</div>`}
      </div>
      ${setupBadge(provider.configured, provider.configured ? "Configured" : "Missing")}
    </div>
  </div>`).join("") || `<div class="text-sm text-gray-500">Provider status unavailable.</div>`;
}

function renderAdminSetupProof(status = {}) {
  const wrap = document.getElementById("admin-setup-proof-status");
  if (!wrap) return;
  const counts = status.launchProof?.counts || {};
  const latest = status.launchProof?.latest || {};
  const dbStatus = status.database || {};
  const rows = [
    ["DATABASE_URL", dbStatus.databaseUrlConnected ? "connected" : "not proven"],
    ["Migrations", (dbStatus.missingMigrations || []).length ? `missing ${(dbStatus.missingMigrations || []).join(", ")}` : "033 and 034 applied"],
    ["Property submission tests", counts.listingTests || 0],
    ["Saved searches / alert matches", `${counts.savedSearches || 0} / ${counts.alertMatches || 0}`],
    ["Viewing / callbacks", `${counts.viewings || 0} / ${counts.callbacks || 0}`],
    ["Campaigns / invoices", `${counts.campaigns || 0} / ${counts.invoices || 0}`],
    ["Failed email / WhatsApp / SMS", `${counts.failedEmails || 0} / ${counts.failedWhatsApp || 0} / ${counts.failedSms || 0}`],
    ["Latest proof actions", Object.keys(latest).join(", ") || "none yet"]
  ];
  wrap.innerHTML = rows.map(([label, value]) => `<div class="rounded-2xl border border-gray-200 bg-gray-50 p-4">
    <div class="text-xs uppercase tracking-wide text-gray-500 font-black">${adminEscape(label)}</div>
    <div class="text-sm font-bold text-gray-900 mt-1 break-words">${adminEscape(value)}</div>
  </div>`).join("");
}

function renderAdminSetupOwnerActions(status = {}) {
  const wrap = document.getElementById("admin-setup-owner-actions");
  if (!wrap) return;
  const actions = Array.isArray(status.ownerActions) ? status.ownerActions : [];
  wrap.innerHTML = actions.map((action) => `<div class="rounded-2xl border border-amber-100 bg-amber-50 p-4">
    <div class="flex items-start justify-between gap-3">
      <div>
        <div class="font-black text-gray-900">${adminEscape(action.title)}</div>
        ${action.command ? `<code class="block mt-2 rounded-xl bg-white border border-amber-100 p-2 text-xs text-gray-700">${adminEscape(action.command)}</code>` : ""}
        ${(action.missingEnv || []).length ? `<div class="text-xs text-amber-800 mt-2">Missing env: ${adminEscape(action.missingEnv.join(", "))}</div>` : ""}
      </div>
      ${setupBadge(false, action.status || "required")}
    </div>
  </div>`).join("") || `<div class="text-sm text-green-700 bg-green-50 border border-green-100 rounded-2xl p-4">No owner blockers reported by setup status.</div>`;
}

async function renderAdminSetupStatus() {
  const gate = document.getElementById("admin-setup-auth-gate");
  const body = document.getElementById("admin-setup-body");
  if (!gate || !body) return;
  if (!authState?.user || derivePortalMode(authState.user, authState.user.portal_mode) !== "admin") {
    gate.classList.remove("hidden");
    body.classList.add("hidden");
    return;
  }
  gate.classList.add("hidden");
  body.classList.remove("hidden");
  const resultBox = document.getElementById("admin-setup-test-result");
  try {
    const response = await apiRequest("/api/admin/setup-status", { headers: adminAuthHeaders() });
    const status = response?.data || {};
    renderAdminSetupStatusCards(status);
    renderAdminSetupProviders(status);
    renderAdminSetupProof(status);
    renderAdminSetupOwnerActions(status);
    if (resultBox && resultBox.textContent.includes("No setup action")) {
      resultBox.textContent = `Setup status refreshed at ${new Date().toLocaleString()}.`;
    }
  } catch (error) {
    if (resultBox) resultBox.textContent = `Setup status failed: ${error.message || "request failed"}`;
  }
}

async function runAdminSetupAction(action) {
  const resultBox = document.getElementById("admin-setup-test-result");
  if (resultBox) resultBox.textContent = `Running ${action}...`;
  try {
    const response = await apiRequest(`/api/admin/setup-status/${action}`, {
      method: "POST",
      headers: adminAuthHeaders(),
      body: {}
    });
    if (resultBox) resultBox.textContent = JSON.stringify(response?.data || response, null, 2);
    await renderAdminSetupStatus();
  } catch (error) {
    if (resultBox) resultBox.textContent = `${action} failed: ${error.message || "request failed"}`;
  }
}

async function runAdminProviderTest(provider) {
  const resultBox = document.getElementById("admin-setup-test-result");
  if (resultBox) resultBox.textContent = `Testing ${provider} provider...`;
  try {
    const response = await apiRequest("/api/admin/setup-status/provider-test", {
      method: "POST",
      headers: adminAuthHeaders(),
      body: { provider }
    });
    if (resultBox) resultBox.textContent = JSON.stringify(response?.data || response, null, 2);
    await renderAdminSetupStatus();
  } catch (error) {
    if (resultBox) resultBox.textContent = `${provider} provider test failed: ${error.message || "request failed"}`;
  }
}

