function openAdminFollowUpWhatsApp(listingId) {
  const listing = adminLiveListings.find((p) => String(p.id) === String(listingId) || String(p.backend_id || "") === String(listingId))
    || adminRemoteListings.find((p) => String(p.id) === String(listingId) || String(p.backend_id || "") === String(listingId))
    || PROPERTIES.find((p) => String(p.id) === String(listingId) || String(p.backend_id || "") === String(listingId));
  if (!listing) {
    toast("Live listing not found in current snapshot.");
    return;
  }
  openAdminWhatsAppMessageModal({
    title: "Send 14-day follow-up",
    listingLabel: listing.inquiry_reference || listing.title || listing.id || "-",
    phone: listing.lister_phone || "",
    message: buildAdminFollowUpWhatsAppMessage(listing)
  });
}

function openAdminRejectedListingWhatsApp(listingId) {
  const listing = adminRemoteListings.find((p) => String(p.id) === String(listingId) || String(p.backend_id || "") === String(listingId))
    || PROPERTIES.find((p) => String(p.id) === String(listingId) || String(p.backend_id || "") === String(listingId));
  if (!listing) {
    toast("Rejected listing not found in current snapshot.");
    return;
  }
  const reason = listing.moderation_reason || listing.extra_fields?.moderation_reason || listing.review?.reason || "";
  openAdminWhatsAppMessageModal({
    title: "Send rejection follow-up",
    listingLabel: listing.inquiry_reference || listing.title || listing.id || "-",
    phone: listing.lister_phone || "",
    message: buildAdminRejectionWhatsAppMessage(listing, reason)
  });
}

