function renderAdminAdvertisingInquiries(inquiries) {
  const wrap = document.getElementById("admin-ad-inquiries-table");
  if (!wrap) return;
  adminAdvertisingInquiries = Array.isArray(inquiries) ? inquiries : [];
  if (!canUseLiveAdminApi()) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">Sign in as admin or load ADMIN_API_KEY to manage advertising leads.</div>`;
    return;
  }
  if (!adminAdvertisingInquiries.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No advertising inquiries yet. Public footer inquiries will appear here.</div>`;
    return;
  }
  wrap.innerHTML = adminAdvertisingInquiries.map((item) => {
    const idArg = adminListingIdArg(item.id);
    const packageNames = (item.product_interests || []).map((key) => {
      const pkg = (adminAdvertisingPackages || []).find((row) => row.key === key);
      return pkg?.label || key;
    });
    return `
      <div class="border border-gray-200 rounded-xl p-4 bg-white">
        <div class="flex items-start justify-between gap-3">
          <div class="min-w-0">
            <div class="font-bold text-gray-900">${adminEscape(item.business_name || item.full_name || "Advertiser")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape(item.full_name || "-")} • ${adminEscape([item.email, item.phone].filter(Boolean).join(" • ") || "-")}</div>
            <div class="text-xs text-gray-500 mt-1">Prefers ${adminEscape(item.preferred_contact_channel || "whatsapp")} • ${adminEscape(formatListingDate(item.created_at))}</div>
          </div>
          ${adStatusBadge(item.status, "lead")}
        </div>
        <div class="mt-3 rounded-xl border border-gray-100 bg-gray-50 p-3 text-sm text-gray-700">
          <div><strong>Products:</strong> ${adminEscape(packageNames.join(", ") || "-")}</div>
          <div><strong>Targets:</strong> ${adminEscape(adListText(item.target_locations || []))} • ${adminEscape(adListText(item.target_listing_types || []))}</div>
          <div><strong>Budget:</strong> ${adminEscape(item.budget_ugx ? adMoney(item.budget_ugx) : "-")} • <strong>Est:</strong> ${adminEscape(adMoney(item.estimated_value_ugx))}</div>
          ${item.message ? `<div class="mt-2">${adminEscape(item.message)}</div>` : ""}
        </div>
        <div class="mt-3 flex flex-wrap gap-2">
          <button onclick="adminCreateAdCampaignFromInquiry(${idArg})" class="bg-green-700 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs font-semibold">Create Campaign</button>
          <button onclick="adminSetAdInquiryStatus(${idArg}, 'contacted')" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Mark Contacted</button>
          <button onclick="adminSetAdInquiryStatus(${idArg}, 'won')" class="border border-green-300 text-green-700 hover:bg-green-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Won</button>
          <button onclick="adminSetAdInquiryStatus(${idArg}, 'lost')" class="border border-red-200 text-red-600 hover:bg-red-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Lost</button>
        </div>
      </div>
    `;
  }).join("");
}

