function renderAdminFeaturedAgentsRows(agents) {
  const wrap = document.getElementById("admin-featured-agents-table");
  if (!wrap) return;
  const rows = [...(Array.isArray(agents) ? agents : [])]
    .filter((agent) => String(agent?.status || "approved").toLowerCase() !== "rejected")
    .sort((a, b) => {
      const af = a?.featured_homepage === true ? 1 : 0;
      const bf = b?.featured_homepage === true ? 1 : 0;
      if (af !== bf) return bf - af;
      const ar = Number(a?.rating || 0);
      const br = Number(b?.rating || 0);
      if (ar !== br) return br - ar;
      return Number(b?.live_listings || b?.listings || 0) - Number(a?.live_listings || a?.listings || 0);
    })
    .slice(0, 40);
  if (!rows.length) {
    wrap.innerHTML = `<div class="text-sm text-gray-500 bg-gray-50 border border-gray-200 rounded-xl p-4">No approved agents available for homepage placement yet.</div>`;
    return;
  }
  wrap.innerHTML = rows.map((agent) => {
    const idArg = adminListingIdArg(agent.id);
    const featured = agent.featured_homepage === true;
    const registration = adminVerificationBadge(agent.registration_status);
    return `
      <div class="border ${featured ? "border-green-200 bg-green-50" : "border-gray-200 bg-white"} rounded-xl p-4">
        <div class="flex items-start justify-between gap-3 flex-wrap">
          <div class="min-w-0">
            <div class="font-bold text-gray-900">${adminEscape(agent.name || "Agent")}</div>
            <div class="text-xs text-gray-500 mt-1">${adminEscape(agent.company || "MakaUg")} • ${adminEscape(agent.area || "Uganda")}</div>
            <div class="mt-2 flex flex-wrap items-center gap-2 text-[11px]">
              <span class="inline-flex items-center px-2 py-1 rounded-full ${registration.cls} font-semibold">${registration.label}</span>
              <span class="inline-flex items-center px-2 py-1 rounded-full bg-gray-100 text-gray-700 font-semibold">⭐ ${adminEscape(agent.rating || 0)}</span>
              <span class="inline-flex items-center px-2 py-1 rounded-full bg-gray-100 text-gray-700 font-semibold">${adminEscape(agent.live_listings || agent.listings || 0)} live</span>
              <span class="inline-flex items-center px-2 py-1 rounded-full bg-gray-100 text-gray-700 font-semibold">${adminEscape(agent.sales || 0)} sales</span>
            </div>
          </div>
          <span class="text-xs font-semibold px-2 py-1 rounded ${featured ? "bg-green-700 text-white" : "bg-gray-100 text-gray-700"}">${featured ? "Featured Agent" : "Available"}</span>
        </div>
        <div class="mt-3 flex flex-wrap gap-2">
          <button onclick="openBrokerProfile(${idArg})" class="border border-green-700 text-green-700 hover:bg-green-50 px-3 py-1.5 rounded-lg text-xs font-semibold">Open Profile</button>
          <button onclick="adminSetAgentFeatured(${idArg}, ${featured ? "false" : "true"})" class="${featured ? "bg-gray-800 hover:bg-gray-700" : "bg-green-700 hover:bg-green-600"} text-white px-3 py-1.5 rounded-lg text-xs font-semibold">${featured ? "Remove Featured" : "Feature on Homepage"}</button>
          <button onclick="adminSetAgentRegistrationStatus(${idArg}, '${agent.registration_status === "registered" ? "not_registered" : "registered"}')" class="border border-gray-300 text-gray-700 hover:bg-gray-50 px-3 py-1.5 rounded-lg text-xs font-semibold">${agent.registration_status === "registered" ? "Mark Pending" : "Mark Verified"}</button>
        </div>
      </div>`;
  }).join("");
}

