  const priority = adminWhatsappPriorityMeta(convo.priority);
  const name = convo.contact_name || convo.phone || "WhatsApp contact";
  const role = convo.participant_type === "broker"
    ? `Broker${convo.agent_company ? ` • ${convo.agent_company}` : ""}`
    : convo.participant_type === "account"
