async function finalizeAuth(data, source, preferredAudience = "") {
  const token = data?.token;
  const user = data?.user;
  if (!token || !user) throw new Error("Authentication response is incomplete");
  const responseRedirect = data?.redirectUrl || data?.redirect_url || "";
  const resolvedMode = derivePortalMode(user, preferredAudience || portalModeForDashboardUrl(responseRedirect));
  const resolvedUser = { ...user, portal_mode: resolvedMode };
  if (preferredAudience === "agent" && user.role !== "agent_broker") {
    resolvedUser.portal_mode = "finder";
    toast("This account is not marked as a broker. Opening property finder dashboard.");
  }
  if (preferredAudience === "field_agent" && user.role !== "field_agent") {
    resolvedUser.portal_mode = "finder";
    toast("This account is not marked as a Field Agent. Opening Property Finder dashboard.");
  }
  if (preferredAudience === "admin" && user.role !== "admin") {
    resolvedUser.portal_mode = "finder";
    toast("This account is not marked as admin. Opening property finder dashboard.");
  }
	      persistAuthState(token, resolvedUser);
	      hydrateAccountForm();
	      closeModal("auth-modal");
	      closeAccountAccessDrawer();
	      toast(data?.message || `Welcome, ${user.first_name || "user"}`);
	      openSignedInDashboard(dashboardRouteForPortalMode(resolvedUser.portal_mode) || responseRedirect);
	      trackEvent("auth_success", { source, role: user.role || "" }).catch(() => {});
	    }

