function updateListPreviewMap(lat, lng, title, locationLabel, district) {
  ensureListPreviewMap();
  if (!lpPreviewMap) return;
  let mLat = Number(lat);
  let mLng = Number(lng);
  let zoom = MAP_PROPERTY_ZOOM;
  if (!Number.isFinite(mLat) || !Number.isFinite(mLng)) {
    const center = getDistrictCenter(district) || MAP_DEFAULT_CENTER;
    mLat = center.lat;
    mLng = center.lng;
    zoom = center ? MAP_DISTRICT_ZOOM : MAP_DEFAULT_ZOOM;
  }
  if (lpPreviewMapProvider === "google" && window.google?.maps) {
    const position = { lat: mLat, lng: mLng };
    if (!lpPreviewMarker) {
      lpPreviewMarker = new google.maps.Marker({
        position,
        map: lpPreviewMap,
        title: getListMapInfo(title, locationLabel).title
      });
      lpPreviewMarker.addListener("mouseover", () => {
        lpPreviewInfoWindow.setContent(getListMapInfoHtml());
        lpPreviewInfoWindow.open(lpPreviewMap, lpPreviewMarker);
      });
      lpPreviewMarker.addListener("click", () => {
        lpPreviewInfoWindow.setContent(getListMapInfoHtml());
        lpPreviewInfoWindow.open(lpPreviewMap, lpPreviewMarker);
      });
    } else {
      lpPreviewMarker.setPosition(position);
      lpPreviewMarker.setTitle(getListMapInfo(title, locationLabel).title);
    }
    lpPreviewMap.setCenter(position);
    lpPreviewMap.setZoom(zoom);
    resizeListMap(lpPreviewMap, lpPreviewMapProvider, position, zoom, 80);
    resizeListMap(lpPreviewMap, lpPreviewMapProvider, position, zoom, 260);
  } else if (window.L) {
    if (!lpPreviewMarker) lpPreviewMarker = L.marker([mLat, mLng]).addTo(lpPreviewMap);
    else lpPreviewMarker.setLatLng([mLat, mLng]);
    lpPreviewMap.setView([mLat, mLng], zoom);
    lpPreviewMarker.bindPopup(`<strong>${title || "Listing"}</strong><br>${locationLabel || "-"}`);
    resizeListMap(lpPreviewMap, lpPreviewMapProvider, { lat: mLat, lng: mLng }, zoom, 80);
    resizeListMap(lpPreviewMap, lpPreviewMapProvider, null, null, 260);
  }
  const noteEl = document.getElementById("lp-preview-map-note");
  if (noteEl) {
    const hasPin = Number.isFinite(Number(lat)) && Number.isFinite(Number(lng));
    noteEl.textContent = hasPin
      ? translateListingLabel("Pinned coordinates are confirmed for this listing.")
      : translateListingLabel("Map is centered to district until you confirm a pin in Step 1.");
  }
}

function setListPinCoords(lat, lng, recenter = true, preserveConfirm = false) {
  const nLat = Number(lat);
  const nLng = Number(lng);
  if (!Number.isFinite(nLat) || !Number.isFinite(nLng)) return;
  const latEl = document.getElementById("lp-lat");
  const lngEl = document.getElementById("lp-lng");
  if (latEl) latEl.value = nLat.toFixed(6);
  if (lngEl) lngEl.value = nLng.toFixed(6);
  ensureListPinMap();
  if (lpPinMap) {
    if (lpPinMapProvider === "google" && window.google?.maps) {
      const position = { lat: nLat, lng: nLng };
      if (!lpPinMarker) {
        lpPinMarker = new google.maps.Marker({
          position,
          map: lpPinMap,
          draggable: true,
          title: getListMapInfo().title
        });
        lpPinMarker.addListener("dragend", (evt) => {
          if (!evt.latLng) return;
          setListPinCoords(evt.latLng.lat(), evt.latLng.lng(), false);
        });
        lpPinMarker.addListener("mouseover", () => {
          lpPinInfoWindow.setContent(getListMapInfoHtml());
          lpPinInfoWindow.open(lpPinMap, lpPinMarker);
        });
        lpPinMarker.addListener("click", () => {
          lpPinInfoWindow.setContent(getListMapInfoHtml());
          lpPinInfoWindow.open(lpPinMap, lpPinMarker);
        });
      } else {
        lpPinMarker.setPosition(position);
        lpPinMarker.setTitle(getListMapInfo().title);
      }
      if (recenter) {
        lpPinMap.setCenter(position);
        lpPinMap.setZoom(MAP_PROPERTY_ZOOM);
      }
    } else if (window.L) {
      if (!lpPinMarker) lpPinMarker = L.marker([nLat, nLng]).addTo(lpPinMap);
      else lpPinMarker.setLatLng([nLat, nLng]);
      if (recenter) lpPinMap.setView([nLat, nLng], MAP_PROPERTY_ZOOM);
    }
  }
  const confirmEl = document.getElementById("lp-location-confirm");
  if (confirmEl && !preserveConfirm) confirmEl.checked = false;
  updateLpLocationConfirmButton();
  updateLpLocationStepLocks();
  resolveListPinLocation(nLat, nLng);
  resolveListPinElevation(nLat, nLng);
  updateListPreview();
  renderListReviewSummary();
}

function canConfirmLpLocation() {
  const lat = parseFloatSafe(lpVal("lp-lat"));
  const lng = parseFloatSafe(lpVal("lp-lng"));
  const hasAddressContext = !!(lpVal("lp-address") || lpResolvedLocationLabel || lpVal("lp-address-search") || lpVal("lp-area") || lpVal("list-district-sel"));
  return hasAddressContext && lat != null && lng != null;
}

function updateLpLocationConfirmButton() {
  const btn = document.getElementById("lp-location-confirm-btn");
  const label = document.getElementById("lp-location-confirm-label");
  const confirmed = !!document.getElementById("lp-location-confirm")?.checked;
  const ready = canConfirmLpLocation();
  if (btn) {
    btn.disabled = !ready;
    btn.className = !ready
      ? "mt-2 inline-flex items-center gap-2 bg-gray-200 text-gray-500 px-3 py-2 rounded-lg text-xs font-semibold cursor-not-allowed"
      : confirmed
        ? "mt-2 inline-flex items-center gap-2 bg-green-50 border border-green-200 text-green-800 px-3 py-2 rounded-lg text-xs font-semibold"
        : "mt-2 inline-flex items-center gap-2 bg-green-700 hover:bg-green-600 text-white px-3 py-2 rounded-lg text-xs font-semibold";
  }
  if (label) {
    label.textContent = !ready
      ? translateListingLabel("Find address/place or move the pin first")
      : confirmed
        ? translateListingLabel("Location confirmed")
        : translateListingLabel("Confirm this location");
  }
}

function confirmLpLocationPin() {
  const lat = parseFloatSafe(lpVal("lp-lat"));
  const lng = parseFloatSafe(lpVal("lp-lng"));
  if (!canConfirmLpLocation()) {
    markLpFieldError("lp-pin-map", "Find an address/place or place the pin before confirming.");
    toast(translateListingLabel("Find an address/place or place the pin before confirming."));
    return;
  }
  if (lat == null || lng == null) {
    markLpFieldError("lp-pin-map", "Place or sync the pin so location coordinates are captured.");
    toast(translateListingLabel("Set property pin on the map."));
    return;
  }
  const confirmEl = document.getElementById("lp-location-confirm");
  if (confirmEl) confirmEl.checked = true;
  updateLpLocationConfirmButton();
  updateListPreview();
  renderListReviewSummary();
  toast(translateListingLabel("Location confirmed"));
}

function findClosestLpHierarchyOption(district, point = null) {
  const lat = Number(point?.lat);
  const lng = Number(point?.lng);
  if (!district || !Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  let best = null;
  getDistrictLocationTree(district).forEach((cityNode) => {
    (cityNode.neighborhoods || []).forEach((neighborhood) => {
      const nLat = Number(neighborhood?.lat);
      const nLng = Number(neighborhood?.lng);
      if (!Number.isFinite(nLat) || !Number.isFinite(nLng)) return;
      const score = distanceBetweenPointsKm({ lat, lng }, { lat: nLat, lng: nLng });
      if (!best || score < best.score) {
        best = { city: cityNode.city, neighborhood: neighborhood.name, score };
      }
    });
  });
  return best;
}

function chooseFallbackNeighborhood(district, cityNode, text = "", point = null, existingArea = "") {
  const neighborhoodOptions = cityNode?.neighborhoods || [];
  if (!neighborhoodOptions.length) return "";
  const nMatch = findLpLocationOptionByText(neighborhoodOptions, (item) => item.name, `${text} ${existingArea}`);
  if (nMatch?.name) return nMatch.name;
  const nearest = findClosestLpHierarchyOption(district, point);
  if (nearest?.city === cityNode?.city && nearest?.neighborhood) return nearest.neighborhood;
  return neighborhoodOptions[0]?.name || "";
}

function applyResolvedAddressHierarchy(label = "", point = null) {
  const text = String(label || "").toLowerCase();
  const pinPoint = Number.isFinite(Number(point?.lat)) && Number.isFinite(Number(point?.lng))
    ? { lat: Number(point.lat), lng: Number(point.lng) }
    : null;
  if (!text && !pinPoint) return;
  const nearestDistrict = pinPoint ? findNearestDistrictFromCoords(pinPoint.lat, pinPoint.lng)?.district || "" : "";
  const district = DISTRICTS.find((item) => {
    const key = item.toLowerCase();
    return text.includes(key);
  }) || lpVal("list-district-sel") || nearestDistrict;
  if (!district) return;
  const region = regionForDistrict(district);
  const regionEl = document.getElementById("lp-region");
  const districtEl = document.getElementById("list-district-sel");
  const nearest = findClosestLpHierarchyOption(district, pinPoint);
  if (regionEl && region) {
    populateLpRegionOptions(region);
    regionEl.value = region;
  }
  populateLpDistrictOptions(region, district);
  if (districtEl) districtEl.value = district;
  const tree = getDistrictLocationTree(district);
  const cityMatch = findLpLocationOptionByText(tree, (item) => item.city, text)
    || (nearest?.city ? tree.find((item) => item.city === nearest.city) : null)
    || (tree.length ? tree[0] : null);
  populateLpCityOptions(district, cityMatch?.city || "");
  const activeCity = lpVal("lp-city") || cityMatch?.city || "";
  const cityNode = tree.find((item) => item.city === activeCity) || cityMatch || tree[0];
  const existingArea = lpVal("lp-area");
  const fallbackNeighborhood = chooseFallbackNeighborhood(district, cityNode, text, pinPoint, existingArea);
  populateLpNeighborhoodOptions(district, activeCity || cityNode?.city || "", fallbackNeighborhood);
  const areaEl = document.getElementById("lp-area");
  const resolvedNeighborhood = lpVal("lp-neighborhood") || fallbackNeighborhood;
  if (areaEl && (!areaEl.value.trim() || areaEl.dataset.auto === "1")) {
    areaEl.value = resolvedNeighborhood || "";
    areaEl.dataset.auto = areaEl.value ? "1" : "0";
    lpAreaManualOverride = false;
  }
  populateListAddressSuggestions({
    region,
    district,
    city: lpVal("lp-city"),
    neighborhood: lpVal("lp-neighborhood"),
    area: lpVal("lp-area")
  });
  syncLpAddressFromHierarchy();
  updateLpLocationStepLocks();
}

function setLpResolvedLocationLabel(text) {
  lpResolvedLocationLabel = text || "";
  const el = document.getElementById("lp-location-resolved");
  if (el) el.textContent = lpResolvedLocationLabel || translateListingLabel("Set a pin to resolve the nearest location label.");
}

function setLpResolvedAltitude(value) {
  lpResolvedAltitudeM = Number.isFinite(Number(value)) ? Number(value) : null;
  const el = document.getElementById("lp-alt");
  if (!el) return;
  el.value = lpResolvedAltitudeM != null ? lpResolvedAltitudeM.toFixed(1) : "";
  if (!el.value) {
    el.placeholder = translateListingLabel("Auto-detected after pin placement");
  }
}

async function resolveListPinLocation(lat, lng) {
  setLpResolvedLocationLabel(translateListingLabel("Resolving nearest location..."));
  if (lpReverseGeoTimer) clearTimeout(lpReverseGeoTimer);
  lpReverseGeoTimer = setTimeout(async () => {
    try {
      const googleLabel = await reverseGeocodeWithGoogle(lat, lng);
      if (googleLabel) {
        setLpResolvedLocationLabel(googleLabel);
        hydrateStreetSuggestionsForSelection({ lat: Number(lat), lng: Number(lng) });
        return;
      }
      const url = `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${encodeURIComponent(lat)}&lon=${encodeURIComponent(lng)}&zoom=18&addressdetails=1&countrycodes=ug`;
      const response = await fetch(url, { headers: { Accept: "application/json" } });
      if (!response.ok) throw new Error(`Reverse geocode failed (${response.status})`);
      const data = await response.json();
      const addr = data?.address || {};
      const streetName = extractStreetNameFromNominatimAddress(addr);
      if (streetName) setLpStreetName(streetName);
      const label = [
        addr.road || addr.suburb || addr.neighbourhood || addr.village || addr.town || addr.city,
        addr.city || addr.town || addr.county || addr.state_district,
        addr.state || addr.country
      ].filter(Boolean).join(", ");
      setLpResolvedLocationLabel(label || data?.display_name || translateListingLabel("Location resolved"));
    } catch (error) {
      const fallback = [lpVal("lp-neighborhood"), lpVal("lp-city"), lpVal("list-district-sel")].filter(Boolean).join(", ");
      setLpResolvedLocationLabel(fallback || translateListingLabel("Location pinned"));
    }
  }, 250);
}

async function resolveListPinElevation(lat, lng) {
  setLpResolvedAltitude(null);
  if (window.MAKAUG_ENABLE_ELEVATION_LOOKUP !== true) {
    return;
  }
  try {
    const url = `https://api.open-elevation.com/api/v1/lookup?locations=${encodeURIComponent(`${lat},${lng}`)}`;
    const response = await fetch(url, { headers: { Accept: "application/json" } });
    if (!response.ok) throw new Error(`Elevation lookup failed (${response.status})`);
    const data = await response.json();
    const elevation = Number(data?.results?.[0]?.elevation);
    if (Number.isFinite(elevation)) {
      setLpResolvedAltitude(elevation);
    }
  } catch (error) {
    setLpResolvedAltitude(null);
  }
}

async function geocodeListAddressToMap(anchorCenter = null) {
  const region = lpVal("lp-region");
  const district = lpVal("list-district-sel");
  const city = lpVal("lp-city");
  const neighborhood = lpVal("lp-neighborhood");
  const streetName = lpVal("lp-street-name");
  const address = lpVal("lp-address");
  if ((!address || address.length < 4) && !streetName) return;
  if (lpAddressGeoTimer) clearTimeout(lpAddressGeoTimer);

  lpAddressGeoTimer = setTimeout(async () => {
    const reqSeq = ++lpAddressGeoSeq;
    try {
      const hierarchyAnchor = anchorCenter || await resolveHierarchyMapAnchor({ region, district, city, neighborhood, area: lpVal("lp-area") });
      const query = uniqueTextParts([streetName, address, neighborhood, city, district, region, "Uganda"]).join(", ");
      const googlePoint = await geocodeWithGoogle(query, {
        bounds: hierarchyAnchor ? buildGoogleBoundsFromCenter(hierarchyAnchor, streetName ? 22 : 35) : null
      });
      const url = `https://nominatim.openstreetmap.org/search?format=jsonv2&limit=1&countrycodes=ug&q=${encodeURIComponent(query)}`;
      if (googlePoint && pointMatchesHierarchyAnchor(googlePoint, hierarchyAnchor, streetName ? 45 : 75)) {
        if (reqSeq !== lpAddressGeoSeq) return;
        setListPinCoords(googlePoint.lat, googlePoint.lng, true, true);
        hydrateStreetSuggestionsForSelection(googlePoint);
        return;
      }
      const response = await fetch(url, { headers: { Accept: "application/json" } });
      if (!response.ok) throw new Error(`Address geocode failed (${response.status})`);
      const rows = await response.json();
      if (reqSeq !== lpAddressGeoSeq) return;
      if (!Array.isArray(rows) || !rows.length) return;
      const lat = Number(rows[0].lat);
      const lng = Number(rows[0].lon);
      if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
      if (!pointMatchesHierarchyAnchor({ lat, lng }, hierarchyAnchor, streetName ? 45 : 75)) {
        if (hierarchyAnchor) setListPinCoords(hierarchyAnchor.lat, hierarchyAnchor.lng, true, true);
        return;
      }
      const streetCandidate = extractStreetNameFromNominatimAddress(rows[0]?.address || {});
      if (streetCandidate) setLpStreetName(streetCandidate);
      setListPinCoords(lat, lng, true, true);
    } catch (error) {
      if (anchorCenter) setListPinCoords(anchorCenter.lat, anchorCenter.lng, true, true);
    }
  }, 350);
}

async function geocodeListHierarchyToMap(anchorCenter = null) {
  const region = lpVal("lp-region");
  const district = lpVal("list-district-sel");
  const city = lpVal("lp-city");
  const neighborhood = lpVal("lp-neighborhood");
  const area = lpVal("lp-area");
  const streetName = lpVal("lp-street-name");
  if (!district && !city && !neighborhood && !area && !region) return;
  if (lpHierarchyGeoTimer) clearTimeout(lpHierarchyGeoTimer);
  lpHierarchyGeoTimer = setTimeout(async () => {
    const reqSeq = ++lpHierarchyGeoSeq;
    try {
      const areaPart = area && area !== neighborhood ? area : "";
      const query = uniqueTextParts([streetName, neighborhood, areaPart, city, district, region, "Uganda"]).join(", ");
      if (!query) return;
      const hierarchyAnchor = anchorCenter || await resolveHierarchyMapAnchor({ region, district, city, neighborhood, area });
      const googlePoint = await geocodeWithGoogle(query, {
        bounds: hierarchyAnchor ? buildGoogleBoundsFromCenter(hierarchyAnchor, streetName ? 20 : 30) : null
      });
      const url = `https://nominatim.openstreetmap.org/search?format=jsonv2&limit=1&countrycodes=ug&q=${encodeURIComponent(query)}`;
      if (googlePoint && pointMatchesHierarchyAnchor(googlePoint, hierarchyAnchor, streetName ? 40 : 70)) {
        if (reqSeq !== lpHierarchyGeoSeq) return;
        setListPinCoords(googlePoint.lat, googlePoint.lng, true, true);
        hydrateStreetSuggestionsForSelection(googlePoint);
        return;
      }
      const response = await fetch(url, { headers: { Accept: "application/json" } });
      if (!response.ok) throw new Error(`Hierarchy geocode failed (${response.status})`);
      const rows = await response.json();
      if (reqSeq !== lpHierarchyGeoSeq) return;
      if (!Array.isArray(rows) || !rows.length) return;
      const lat = Number(rows[0].lat);
      const lng = Number(rows[0].lon);
      if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
      if (!pointMatchesHierarchyAnchor({ lat, lng }, hierarchyAnchor, streetName ? 40 : 70)) {
        if (hierarchyAnchor) setListPinCoords(hierarchyAnchor.lat, hierarchyAnchor.lng, true, true);
        return;
      }
      const streetCandidate = extractStreetNameFromNominatimAddress(rows[0]?.address || {});
      if (streetCandidate) setLpStreetName(streetCandidate);
      setListPinCoords(lat, lng, true, true);
    } catch (error) {
      if (anchorCenter) setListPinCoords(anchorCenter.lat, anchorCenter.lng, true, true);
    }
  }, 220);
}

function refreshListPinMapFromInputs() {
  ensureListPinMap();
  if (!lpPinMap) return;
  const region = lpVal("lp-region");
  const area = lpVal("lp-area");
  const district = lpVal("list-district-sel") || guessDistrictFromText(area);
  const city = lpVal("lp-city");
  const neighborhood = lpVal("lp-neighborhood");
  const streetName = lpVal("lp-street-name");
  const address = lpVal("lp-address");
  const hierarchySignature = [region, district, city, neighborhood, area, streetName].join("|");
  const addressSignature = [streetName, address].join("|").toLowerCase();
  const hierarchyChanged = hierarchySignature !== lpLastHierarchySignature;
  const addressChanged = addressSignature !== lpLastAddressValue;
  if (hierarchyChanged || addressChanged) {
    const confirmEl = document.getElementById("lp-location-confirm");
    if (confirmEl) confirmEl.checked = false;
  }
  lpLastHierarchySignature = hierarchySignature;
  lpLastAddressValue = addressSignature;
  const lat = parseFloatSafe(lpVal("lp-lat"));
  const lng = parseFloatSafe(lpVal("lp-lng"));
  const hasCoords = lat != null && lng != null;
  const confirmed = !!document.getElementById("lp-location-confirm")?.checked;
  if (hasCoords && confirmed) {
    setListPinCoords(lat, lng, true, true);
    return;
  }
  const neighborhoodPoint = getNeighborhoodPoint(district, city, neighborhood);
  const cityPoint = getCityPoint(district, city);
  const center = neighborhoodPoint || cityPoint || getDistrictCenter(district) || getRegionCenter(region) || MAP_DEFAULT_CENTER;
  const zoom = streetName
    ? MAP_PROPERTY_ZOOM - 1
    : neighborhood
      ? MAP_NEIGHBORHOOD_ZOOM
      : city
        ? MAP_CITY_ZOOM
        : address
          ? MAP_CITY_ZOOM
          : (district ? MAP_DISTRICT_ZOOM : (region ? MAP_REGION_ZOOM : (area ? MAP_CITY_ZOOM : MAP_DEFAULT_ZOOM)));
  if (lpPinMapProvider === "google" && window.google?.maps) {
    lpPinMap.setCenter({ lat: center.lat, lng: center.lng });
    lpPinMap.setZoom(zoom);
  } else if (lpPinMap?.setView) {
    lpPinMap.setView([center.lat, center.lng], zoom);
  }
  const needsPreciseAnchor = !!streetName || !!address || (!neighborhoodPoint && !cityPoint && !getDistrictCenter(district) && (district || city || neighborhood || area));
  const shouldMovePin = !confirmed && (!hasCoords || hierarchyChanged || addressChanged);
  if (!needsPreciseAnchor && shouldMovePin) {
    setListPinCoords(center.lat, center.lng, false);
  }
  if (needsPreciseAnchor) {
    const reqSeq = ++lpHierarchyAnchorSeq;
    resolveHierarchyMapAnchor({ region, district, city, neighborhood, area }).then((anchorCenter) => {
      if (reqSeq !== lpHierarchyAnchorSeq || !anchorCenter) return;
      if (lpPinMapProvider === "google" && window.google?.maps) {
        lpPinMap.setCenter({ lat: anchorCenter.lat, lng: anchorCenter.lng });
        lpPinMap.setZoom(zoom);
      } else if (lpPinMap?.setView) {
        lpPinMap.setView([anchorCenter.lat, anchorCenter.lng], zoom);
      }
      if (shouldMovePin) {
        setListPinCoords(anchorCenter.lat, anchorCenter.lng, false, true);
      }
      if (address && (addressChanged || hierarchyChanged)) {
        geocodeListAddressToMap(anchorCenter);
      } else if ((area || streetName || !confirmed) && (hierarchyChanged || addressChanged || !hasCoords)) {
        geocodeListHierarchyToMap(anchorCenter);
      }
    });
    return;
  }
  if (address && (addressChanged || hierarchyChanged)) {
    geocodeListAddressToMap(center);
  } else if ((area || streetName || !confirmed) && (hierarchyChanged || addressChanged || !hasCoords)) {
    geocodeListHierarchyToMap(center);
  }
}

function syncMapToHierarchy() {
  const searchValue = lpVal("lp-address-search") || lpVal("lp-address");
  if (searchValue) {
    findLpAddressOrPlace();
    return;
  }
  if (!lpVal("lp-region") && !lpVal("list-district-sel") && !lpVal("lp-area")) {
    toast(translateListingLabel("Find an address/place or place the pin before confirming."));
    return;
  }
  const confirmEl = document.getElementById("lp-location-confirm");
  if (confirmEl) confirmEl.checked = false;
  refreshListPinMapFromInputs();
  updateLpLocationStepLocks();
  toast(translateListingLabel("Map centered to the selected address/place."));
}

function setListWizardStep(step) {
  const next = Math.max(1, Math.min(4, Number(step) || 1));
  listWizardStep = next;
  document.querySelectorAll("[data-lp-step-panel]").forEach((panel) => {
    const panelStep = parseInt(panel.getAttribute("data-lp-step-panel") || "0", 10);
    panel.classList.toggle("hidden", panelStep !== next);
  });
  [1, 2, 3, 4].forEach((idx) => {
    const circle = document.querySelector(`[data-lp-step-circle="${idx}"]`);
    const label = document.querySelector(`[data-lp-step-label="${idx}"]`);
    if (!circle || !label) return;
    if (idx === next) {
      circle.className = "w-8 h-8 rounded-full bg-green-800 text-white text-sm font-bold flex items-center justify-center";
      label.className = "text-green-800 font-semibold text-sm";
    } else if (idx < next) {
      circle.className = "w-8 h-8 rounded-full bg-green-600 text-white text-sm font-bold flex items-center justify-center";
      label.className = "text-green-700 font-semibold text-sm";
    } else {
      circle.className = "w-8 h-8 rounded-full bg-green-100 text-green-800 text-sm font-bold flex items-center justify-center";
      label.className = "text-green-700/80 font-semibold text-sm";
    }
  });
  applyListThemeToControls();
  if (next === 1) refreshListPinMapFromInputs();
  if (next === 2) updateLpPhotoRequirements();
  if (next === 4) {
    updateListPreview();
    ensureListPreviewMap();
    setTimeout(() => {
      updateListPreview();
      if (lpPreviewMap) {
        resizeListMap(lpPreviewMap, lpPreviewMapProvider);
      }
    }, 180);
    setTimeout(() => {
      if (lpPreviewMap) {
        resizeListMap(lpPreviewMap, lpPreviewMapProvider);
      }
    }, 420);
  }
}

function clearLpValidationErrors(stepPanelSelector = "") {
  const scope = stepPanelSelector ? document.querySelector(stepPanelSelector) : document;
  if (!scope) return;
  scope.querySelectorAll(".lp-inline-error").forEach((el) => el.remove());
  scope.querySelectorAll(".lp-error-target").forEach((el) => {
    if (el.dataset.lpPrevBorderClass) {
      el.classList.remove("border-red-400");
      el.classList.add(el.dataset.lpPrevBorderClass);
      delete el.dataset.lpPrevBorderClass;
    }
    el.classList.remove("lp-error-target", "ring-2", "ring-red-200", "border-red-400", "bg-red-50");
  });
}

function resolveLpErrorTarget(el) {
  if (!el) return null;
  if (el.id === "lp-location-confirm") {
    return el.closest("label") || el.parentElement || el;
  }
  return el;
}

function markLpFieldError(fieldId, message = "") {
  const el = document.getElementById(fieldId);
  if (!el) return;
  const target = resolveLpErrorTarget(el);
  if (!target) return;
  const borderClass = Array.from(target.classList).find((cls) => /^border-(?!\d)/.test(cls));
  if (borderClass && borderClass !== "border-red-400") {
    target.dataset.lpPrevBorderClass = borderClass;
    target.classList.remove(borderClass);
  }
  target.classList.add("lp-error-target", "border-red-400", "ring-2", "ring-red-200");
  if (!message) return;

  const noteId = `${fieldId}-inline-error`;
  let note = document.getElementById(noteId);
  if (!note) {
    note = document.createElement("p");
    note.id = noteId;
    note.className = "lp-inline-error text-xs text-red-600 mt-1";
    const host = target.parentElement || target;
    if (host && host.appendChild) host.appendChild(note);
  }
  if (note) note.textContent = message;
}

function markLpPhotoSelectError(index) {
  const gallery = document.getElementById("lp-photo-gallery");
  if (!gallery) return;
  const select = gallery.querySelectorAll("select")[index];
  if (!select) return;
  const borderClass = Array.from(select.classList).find((cls) => /^border-(?!\d)/.test(cls));
  if (borderClass && borderClass !== "border-red-400") {
    select.dataset.lpPrevBorderClass = borderClass;
    select.classList.remove(borderClass);
  }
  select.classList.add("lp-error-target", "border-red-400", "ring-2", "ring-red-200");
}

function validateListStep1() {
  const missing = [];
  clearLpValidationErrors("#lp-step-1");
  if (!lpVal("lp-title")) {
    missing.push("Title");
    markLpFieldError("lp-title", "Title is required.");
  }
  if (!lpVal("lp-address") && !lpResolvedLocationLabel && !lpVal("lp-address-search")) {
    missing.push("Address/place");
    markLpFieldError("lp-address-search", "Find the nearest address, road, landmark, or area.");
  }
  if (!lpVal("lp-description")) {
    missing.push("Description");
    markLpFieldError("lp-description", "Description is required.");
  }
  if (!parseIntSafe(lpVal("lp-price"))) {
    missing.push("Price");
    markLpFieldError("lp-price", "Enter a valid price.");
  }
  if (!lpVal("lp-lat") || !lpVal("lp-lng")) {
    missing.push("Map pin");
    markLpFieldError("lp-lat", "Set property pin on the map.");
    markLpFieldError("lp-lng");
    markLpFieldError("lp-pin-map", "Place or sync the pin so location coordinates are captured.");
  }
  if (!document.getElementById("lp-location-confirm")?.checked) {
    missing.push("Location confirmation");
    markLpFieldError("lp-location-confirm", "Confirm that the pin matches the property location.");
  }
  if (missing.length) {
    toast(`Please complete: ${missing.join(", ")}`);
    return false;
  }
  return true;
}

function validateListStep2() {
  clearLpValidationErrors("#lp-step-2");
  const minPhotos = getLpMinUploadPhotos(getListType());
  if (lpSelectedPhotos.length < minPhotos) {
    markLpFieldError("lp-photo-dropzone", `Upload at least ${minPhotos} photos.`);
    markLpFieldError("lp-upload-label");
    toast(`Upload at least ${minPhotos} photos to continue.`);
    return false;
  }
  if (lpSelectedPhotos.length > LP_MAX_UPLOAD_PHOTOS) {
    markLpFieldError("lp-photo-dropzone", `Maximum ${LP_MAX_UPLOAD_PHOTOS} photos allowed.`);
    markLpFieldError("lp-upload-label");
    toast(`Maximum ${LP_MAX_UPLOAD_PHOTOS} photos allowed.`);
    return false;
  }
  if (!Number.isFinite(lpMainPhotoIndex) || lpMainPhotoIndex < 0 || lpMainPhotoIndex >= lpSelectedPhotos.length) {
    markLpFieldError("lp-photo-gallery", "Choose a main photo before continuing.");
    toast("Choose a main photo before continuing.");
    return false;
  }
  const checklist = getLpPhotoChecklist(getListType());
  const unassigned = lpSelectedPhotos
    .map((file, idx) => ({ idx, name: file.name, slot: lpPhotoAssignments[idx] || "" }))
    .filter((entry) => !entry.slot);
  if (unassigned.length) {
    unassigned.forEach((entry) => markLpPhotoSelectError(entry.idx));
    toast(`Assign each photo to a category before continuing. Missing: ${unassigned.slice(0, 2).map((x) => x.name).join(", ")}`);
    return false;
  }
  const assignedKeys = new Set(Object.values(lpPhotoAssignments).map((value) => getLpPhotoAssignmentSelectValue(value)));
  const pending = checklist.filter((item) => !assignedKeys.has(item.key)).map((item) => item.label);
  if (pending.length) {
    markLpFieldError("lp-photo-required-list", "Cover all required photo categories before continuing.");
    toast(`Cover required photo types: ${pending.slice(0, 3).map((x) => translateListingLabel(x)).join(", ")}${pending.length > 3 ? "..." : ""}`);
    return false;
  }
  return true;
}

function getYouTubeEmbedUrl(url) {
  const raw = String(url || "").trim();
  if (!raw) return "";
  try {
    const parsed = new URL(raw);
    const host = parsed.hostname.replace(/^www\./, "").toLowerCase();
    let id = "";
    if (host === "youtu.be") {
      id = parsed.pathname.split("/").filter(Boolean)[0] || "";
    } else if (host.endsWith("youtube.com")) {
      if (parsed.pathname.startsWith("/shorts/") || parsed.pathname.startsWith("/embed/")) {
        id = parsed.pathname.split("/").filter(Boolean)[1] || "";
      } else {
        id = parsed.searchParams.get("v") || "";
      }
    }
    if (!/^[a-zA-Z0-9_-]{6,}$/.test(id)) return "";
    const params = new URLSearchParams({
      rel: "0",
      modestbranding: "1",
      playsinline: "1"
    });
    const origin = window.location?.origin && window.location.origin !== "null" ? window.location.origin : "";
    if (origin) params.set("origin", origin);
    return `https://www.youtube-nocookie.com/embed/${id}?${params.toString()}`;
  } catch (error) {
    return "";
  }
}

function renderVideoEmbedCard(url, options = {}) {
  const safeUrl = String(url || "").trim();
  if (!/^https?:\/\//i.test(safeUrl)) return "";
  const embedUrl = getYouTubeEmbedUrl(safeUrl);
  const title = options.title || translateListingLabel("Video tour");
  const sub = options.sub || translateListingLabel("Play the walkthrough without leaving this page.");
  if (embedUrl) {
    return `
      <div class="rounded-2xl border border-red-100 bg-red-50/50 overflow-hidden">
        <div class="flex items-center justify-between gap-3 p-3">
          <div>
            <div class="text-sm font-bold text-gray-900"><i class="fab fa-youtube text-red-600"></i> ${title}</div>
            <div class="text-xs text-gray-500 mt-0.5">${sub}</div>
          </div>
          <a href="${adminAttr(safeUrl)}" target="_blank" rel="noopener noreferrer" class="text-xs font-bold text-red-700 hover:underline">${translateListingLabel("Open YouTube")}</a>
        </div>
        <div class="aspect-video bg-black">
          <iframe src="${adminAttr(embedUrl)}" title="Property video tour" class="w-full h-full" loading="lazy" referrerpolicy="strict-origin-when-cross-origin" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowfullscreen></iframe>
        </div>
      </div>
    `;
  }
  return `
    <div class="rounded-2xl border border-green-100 bg-green-50 p-3">
      <div class="text-sm font-bold text-gray-900">${title}</div>
      <p class="text-xs text-gray-600 mt-1">${translateListingLabel("This link will be reviewed and shown on the property page.")}</p>
      <a href="${adminAttr(safeUrl)}" target="_blank" rel="noopener noreferrer" class="mt-2 inline-flex items-center gap-2 text-green-700 font-semibold text-sm hover:underline"><i class="fas fa-play-circle"></i>${translateListingLabel("Open video link")}</a>
    </div>
  `;
}

function renderLpVideoPreview() {
  const wrap = document.getElementById("lp-video-preview");
  if (!wrap) return;
  const url = lpVal("lp-video-url");
  wrap.innerHTML = url
    ? renderVideoEmbedCard(url, {
        title: translateListingLabel("Video preview"),
        sub: translateListingLabel("This is how the video tour will appear after review.")
      })
    : `<div class="rounded-xl border border-dashed border-gray-200 bg-gray-50 p-3 text-xs text-gray-500">${translateListingLabel("Add a YouTube walkthrough link to show an embedded preview here.")}</div>`;
}

function validateListStep3() {
  clearLpValidationErrors("#lp-step-3");
  const name = lpVal("lp-verify-name");
  const email = lpVal("lp-verify-email");
  const phone = normalizePhoneInput(lpVal("lp-verify-phone"));
  const nin = lpVal("lp-verify-nin");
  const otpChannel = lpListingOtpChannel === "email" ? "email" : "phone";
  const terms = document.getElementById("lp-verify-terms")?.checked;
  const fraud = document.getElementById("lp-verify-fraud")?.checked;
  const consent = document.getElementById("lp-verify-consent")?.checked;
  const ninMatch = document.getElementById("lp-verify-nin-match")?.checked;
  if (!name || !email || !phone || !nin) {
    if (!name) markLpFieldError("lp-verify-name", "Full name is required.");
    if (!email) markLpFieldError("lp-verify-email", "Email is required.");
    if (!phone) markLpFieldError("lp-verify-phone", "Phone number is required.");
    if (!nin) markLpFieldError("lp-verify-nin", "NIN is required.");
    toast("Please complete all identity fields.");
    return false;
  }
  if (!(/^\+2567\d{8}$/.test(phone) || /^\+256\d{9}$/.test(phone))) {
    markLpFieldError("lp-verify-phone", "Please enter a valid Uganda phone number.");
    toast("Please enter a valid Uganda phone number.");
    return false;
  }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    markLpFieldError("lp-verify-email", "Please enter a valid email address.");
    toast("Please enter a valid email address.");
    return false;
  }
  if (!isValidUgNin(nin)) {
    markLpFieldError("lp-verify-nin", "Please enter a valid NIN.");
    toast("Please enter a valid NIN.");
    return false;
  }
  if (!lpIdentityFileMeta) {
    markLpFieldError("lp-verify-id-file", "Please upload a photo of your National ID. PDFs are not accepted.");
    toast("Please upload a photo of your National ID. PDFs are not accepted.");
    return false;
  }
  if (/\.pdf$/i.test(lpIdentityFileMeta.name || "") || String(lpIdentityFileMeta.type || "").toLowerCase().includes("pdf") || !String(lpIdentityFileMeta.preview_url || "").startsWith("data:image/")) {
    markLpFieldError("lp-verify-id-file", "Please upload a photo of your National ID. PDFs are not accepted.");
    toast("Please upload a photo of your National ID. PDFs are not accepted.");
    return false;
  }
  if (!ninMatch) {
    markLpFieldError("lp-verify-nin-match", "Please confirm NIN matches uploaded ID.");
    toast("Please confirm NIN matches uploaded ID.");
    return false;
  }
  if (!terms || !fraud || !consent) {
    if (!terms) markLpFieldError("lp-verify-terms", "Accept terms to continue.");
    if (!fraud) markLpFieldError("lp-verify-fraud", "Confirm anti-fraud declaration.");
    if (!consent) markLpFieldError("lp-verify-consent", "Consent is required.");
    toast("Please accept the verification declarations.");
    return false;
  }
  const otpOk = !!lpListingOtpToken && (
    (otpChannel === "email" && lpListingOtpVerifiedEmail === email.toLowerCase()) ||
    (otpChannel === "phone" && lpListingOtpVerifiedPhone === phone)
  );
  if (!otpOk) {
    markLpFieldError("lp-verify-otp-code", otpChannel === "email"
      ? "Verify email OTP before continuing."
      : "Verify phone OTP before continuing.");
    toast(otpChannel === "email"
      ? "Please verify your email address with OTP before continuing."
      : "Please verify your phone number with OTP before continuing.");
    return false;
  }
  return true;
}

function nextListStepFromDetails() {
  if (!validateListStep1()) return;
  setListWizardStep(2);
}

function nextListStepFromPhotos() {
  if (!validateListStep2()) return;
  setListWizardStep(3);
}

function nextListStepFromVerify() {
  if (!validateListStep3()) return;
  renderListReviewSummary();
  setListWizardStep(4);
}

function getLpPhotoManifest() {
  return lpSelectedPhotos.map((file, idx) => ({
    name: file.name,
    size: file.size,
    type: file.type || "image/jpeg",
    slot: lpPhotoAssignments[idx] || "",
    slot_key: getLpPhotoAssignmentSelectValue(lpPhotoAssignments[idx] || ""),
    room_label: getLpPhotoSlotLabel(lpPhotoAssignments[idx], getListType()) || "",
    is_main: idx === lpMainPhotoIndex
  }));
}

function generateListingInquiryRef() {
  const yyyymmdd = new Date().toISOString().slice(0, 10).replace(/-/g, "");
  const alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let suffix = "";
  for (let i = 0; i < 5; i += 1) {
    suffix += alphabet[Math.floor(Math.random() * alphabet.length)];
  }
  return `MK-${yyyymmdd}-${suffix}`;
}

function buildListPropertyPayload(photoUploadUrls = lpPhotoUploadUrls) {
  const type = getListType();
  const cfg = LP_CONFIG[type] || LP_CONFIG.sale;
  const extra = getLpExtraValues();
  const title = lpVal("lp-title");
  const district = lpVal("list-district-sel");
  const region = lpVal("lp-region");
  const city = lpVal("lp-city");
  const neighborhood = lpVal("lp-neighborhood");
  const streetName = lpVal("lp-street-name");
  const area = lpVal("lp-area") || neighborhood || city;
  const description = lpVal("lp-description");
  const price = parseIntSafe(lpVal("lp-price"));

  const bedsRaw = lpVal("lp-beds");
  const bedsNumeric = parseIntSafe(bedsRaw);
  const bathsNumeric = parseIntSafe(lpVal("lp-baths"));
  const sizeRaw = lpVal("lp-size");
  const landParsed = parseLandSize(sizeRaw);
  const lat = parseFloatSafe(lpVal("lp-lat"));
  const lng = parseFloatSafe(lpVal("lp-lng"));
  const altitudeM = parseFloatSafe(lpVal("lp-alt"));
  const locationObject = {
    query: lpVal("lp-address-search") || null,
    placeId: lpVal("lp-place-id") || null,
    fullAddress: lpVal("lp-address") || lpResolvedLocationLabel || null,
    street: streetName || null,
    area: area || null,
    neighborhood: neighborhood || null,
    parish: null,
    town: city || null,
    city: city || null,
    district: district || null,
    region: region || null,
    country: "Uganda",
    latitude: lat,
    longitude: lng,
    plusCode: lpVal("lp-plus-code") || null,
    radius: null,
    locationConfidence: parseFloatSafe(lpVal("lp-location-confidence")),
    locationPrivacy: lpVal("lp-location-privacy") || "exact",
    geocodingProvider: lpVal("lp-geocoding-provider") || null,
    geocodedAt: lpVal("lp-geocoded-at") || null
  };
  const publicDisplayName = getPublicDisplayName();
  const nearbyFacilities = getNearbyAmenitySuggestions({ lat, lng, district, city, area });
  const autoAreaHighlights = buildLocationHighlightsText({
    type,
    area,
    district,
    city,
    neighborhood,
    nearby: nearbyFacilities
  });
  const areaHighlights = lpVal("lp-area-highlights-edit") || autoAreaHighlights;
  const studentsWelcome = type === "student" || extra.students_welcome === "yes";
  const fieldAgentAssisted = (lpVal("lp-field-agent-assisted") || "no") === "yes";
  const fieldAgentId = lpVal("lp-field-agent-id") || null;
  const ownerVerificationRequested = !!document.getElementById("lp-owner-verification-requested")?.checked;
	      const videoUrl = lpVal("lp-video-url");
	      const contactPref = lpVal("lp-contact-pref") || "both";
	      const availableFrom = lpVal("lp-available-from");
	      const inquiryReference = lpInquiryReference || generateListingInquiryRef();
  lpInquiryReference = inquiryReference;
  const newUntil = new Date(Date.now() + LISTING_NEW_WINDOW_MS).toISOString();

  const payload = {
    listing_type: type,
    title,
    district,
    area,
    address: locationObject.fullAddress,
    description,
    price,
    price_period: lpVal("lp-period") || null,
    property_type: lpVal("lp-subtype") || null,
    bedrooms: cfg.showBedsBaths ? bedsNumeric : null,
    bathrooms: cfg.showBedsBaths ? bathsNumeric : null,
    amenities: getLpAmenities(),
    listed_via: "website",
    source: "website",
    status: "pending",
    lister_name: lpVal("lp-verify-name") || null,
    lister_display_name: publicDisplayName || null,
    lister_phone: normalizePhoneInput(lpVal("lp-verify-phone")) || null,
    lister_email: (lpVal("lp-verify-email") || "").toLowerCase() || null,
    lister_type: "owner",
	          preferred_contact_method: contactPref,
	          available_from: availableFrom || null,
	          video_url: videoUrl || null,
    students_welcome: studentsWelcome,
    latitude: lat,
    longitude: lng,
    verification_terms_accepted: !!(document.getElementById("lp-verify-terms")?.checked && document.getElementById("lp-verify-fraud")?.checked && document.getElementById("lp-verify-consent")?.checked),
    inquiry_reference: inquiryReference,
    listing_otp_token: lpListingOtpToken || null,
    otp_channel: lpListingOtpChannel === "email" ? "email" : "phone",
    id_number: lpVal("lp-verify-nin") || null,
    id_document_name: lpIdentityFileMeta?.name || null,
    id_document_url: lpIdentityFileMeta?.preview_url || null,
    id_document_type: lpIdentityFileMeta?.type || null,
    new_until: newUntil,
    main_photo_index: Number.isFinite(lpMainPhotoIndex) ? lpMainPhotoIndex : 0,
    images: getLpPhotoManifest().map((item, idx) => ({
      url: photoUploadUrls[idx] || null,
      name: item.name,
      type: item.type,
      slot: item.slot,
      slot_key: item.slot_key,
      room_label: item.room_label,
      is_main: item.is_main || idx === lpMainPhotoIndex
    })),
    extra_fields: {
      ...extra,
      region: region || null,
      size_raw: sizeRaw || null,
      city: city || null,
      neighborhood: neighborhood || null,
      street_name: streetName || null,
      place_id: locationObject.placeId,
      plus_code: locationObject.plusCode,
      geocoding_provider: locationObject.geocodingProvider,
      geocoded_at: locationObject.geocodedAt,
      location_confidence: locationObject.locationConfidence,
      location_privacy: locationObject.locationPrivacy,
      location: locationObject,
      altitude_m: altitudeM,
      map_pin_confirmed: !!document.getElementById("lp-location-confirm")?.checked,
      resolved_location_label: lpResolvedLocationLabel || null,
      public_display_name: publicDisplayName || null,
      preferred_contact_method: contactPref,
      video_url: videoUrl || null,
      youtube_url: /youtube\.com|youtu\.be/i.test(videoUrl) ? videoUrl : null,
      area_highlights: areaHighlights,
      ownership_verification_requested: ownerVerificationRequested,
      lister_registration_status: "not_registered",
      nearby_facilities: nearbyFacilities.map((item) => ({
        name: item.name,
        type: item.kind,
        district: item.district,
        distance_km: Number.isFinite(item.distanceKm) ? Number(item.distanceKm.toFixed(2)) : null
      })),
      coordinates: (lat != null && lng != null) ? { lat, lng } : null,
      photo_manifest: getLpPhotoManifest(),
      main_photo_index: Number.isFinite(lpMainPhotoIndex) ? lpMainPhotoIndex : 0,
      photo_assignments: lpPhotoAssignments,
      photo_quality_issues: lpPhotoQualityIssues,
      photo_required_checked: Object.values(lpPhotoAssignments).map((value) => getLpPhotoAssignmentSelectValue(value)),
      verify: {
        nin: lpVal("lp-verify-nin") || null,
        id_document_name: lpIdentityFileMeta?.name || null,
        id_document_url: lpIdentityFileMeta?.preview_url || null,
        id_document_type: lpIdentityFileMeta?.type || null,
        consent_contact: !!document.getElementById("lp-verify-consent")?.checked,
        contact_preference: lpVal("lp-contact-pref") || "phone",
        nin_match_confirmed: !!document.getElementById("lp-verify-nin-match")?.checked,
        public_display_name: publicDisplayName || null,
        otp_channel: lpListingOtpChannel === "email" ? "email" : "phone",
        field_agent_assisted: fieldAgentAssisted,
        field_agent_id: fieldAgentAssisted ? fieldAgentId : null,
        ownership_verification_requested: ownerVerificationRequested
      },
      field_agent_assisted: fieldAgentAssisted,
      field_agent_id: fieldAgentAssisted ? fieldAgentId : null
    }
  };

  if (type === "sale") {
    payload.title_type = extra.title_type || null;
    payload.year_built = parseIntSafe(extra.year_built);
  }

  if (type === "rent") {
    payload.deposit_amount = parseIntSafe(extra.deposit);
    payload.contract_months = parseIntSafe(extra.contract_months);
    payload.furnishing = extra.furnished || null;
  }

  if (type === "land") {
    payload.title_type = extra.title_type || null;
    payload.land_size_value = landParsed.value;
    payload.land_size_unit = landParsed.unit;
    payload.extra_fields.land_owner_confirmed = extra.owner_confirmed || null;
    payload.extra_fields.land_verification_help_requested = extra.land_verification_help === "yes";
    payload.extra_fields.land_boundary_notes = extra.boundary_notes || null;
    payload.extra_fields.ownership_verification_requested = ownerVerificationRequested || extra.land_verification_help === "yes";
  }

  if (type === "commercial") {
    payload.commercial_intent = extra.commercial_mode || null;
    payload.floor_area_sqm = parseFloatSafe(extra.floor_area);
    payload.usable_size_sqm = parseFloatSafe(extra.floor_area);
    payload.parking_bays = parseIntSafe(extra.parking_bays);
    payload.title_type = extra.title_type || null;
    payload.deposit_amount = parseIntSafe(extra.deposit);
    payload.contract_months = parseIntSafe(extra.contract_months);
  }

  if (type === "student") {
    payload.nearest_university = extra.nearest_uni || null;
    payload.distance_to_uni_km = parseFloatSafe(extra.uni_distance);
    payload.room_arrangement = extra.room_arrangement || null;
    payload.room_type = lpVal("lp-subtype") || null;
  }

  return payload;
}

function renderListReviewSummary() {
  const wrap = document.getElementById("lp-review-summary");
  if (!wrap) return;
  const payload = buildListPropertyPayload();
  const photoCount = lpSelectedPhotos.length;
  const quality = lpPhotoQualityIssues.length
    ? `${lpPhotoQualityIssues.length} ${translateListingLabel("quality flag(s)")}`
    : translateListingLabel("No quality flags");
  const termsOk = (document.getElementById("lp-verify-terms")?.checked && document.getElementById("lp-verify-fraud")?.checked)
    ? translateListingLabel("Accepted")
    : translateListingLabel("Pending");
  const otpChannel = lpListingOtpChannel === "email" ? "email" : "phone";
  const otpVerified = !!lpListingOtpToken && (
    (otpChannel === "email" && lpListingOtpVerifiedEmail === (lpVal("lp-verify-email") || "").toLowerCase()) ||
    (otpChannel === "phone" && lpListingOtpVerifiedPhone === normalizePhoneInput(lpVal("lp-verify-phone")))
  );
  const otpOk = otpVerified
    ? translateListingLabel("Verified")
    : translateListingLabel("Pending");
  const fieldAgentAssisted = payload?.extra_fields?.field_agent_assisted;
  const fieldAgentTag = fieldAgentAssisted
    ? `${translateListingLabel("Yes")} (${payload?.extra_fields?.field_agent_id || "-"})`
    : translateListingLabel("No");
  wrap.innerHTML = `
    <div class="grid md:grid-cols-2 gap-3">
      <div class="bg-gray-50 border border-gray-200 rounded-lg p-3">
        <div class="text-xs uppercase text-gray-500 font-semibold">${translateListingLabel("Submission Track")}</div>
        <div class="text-sm font-semibold text-gray-800 mt-1">${translateListingLabel("Reference")}: ${payload.inquiry_reference}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Support")}: info@makaug.com</div>
      </div>
      <div class="bg-gray-50 border border-gray-200 rounded-lg p-3">
        <div class="text-xs uppercase text-gray-500 font-semibold">${translateListingLabel("Location Pin")}</div>
        <div class="text-sm font-semibold text-gray-800 mt-1">${payload.latitude != null && payload.longitude != null ? `${payload.latitude.toFixed(6)}, ${payload.longitude.toFixed(6)}` : translateListingLabel("Not set")}</div>
        <div class="text-xs text-gray-500 mt-1">${payload.extra_fields?.neighborhood || payload.area}, ${payload.extra_fields?.city || payload.district}${payload.extra_fields?.region ? `, ${payload.extra_fields.region}` : ""}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Altitude (m)")}: ${payload.extra_fields?.altitude_m != null ? Number(payload.extra_fields.altitude_m).toFixed(1) : "-"}</div>
      </div>
      <div class="bg-gray-50 border border-gray-200 rounded-lg p-3">
        <div class="text-xs uppercase text-gray-500 font-semibold">${translateListingLabel("Photos")}</div>
        <div class="text-sm font-semibold text-gray-800 mt-1">${photoCount} ${translateListingLabel("selected")}</div>
        <div class="text-xs text-gray-500 mt-1">${quality}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Main photo")}: ${lpSelectedPhotos[lpMainPhotoIndex]?.name || "-"}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Video tour")}: ${payload.video_url ? translateListingLabel("Attached") : translateListingLabel("Not set")}</div>
      </div>
      <div class="bg-gray-50 border border-gray-200 rounded-lg p-3">
        <div class="text-xs uppercase text-gray-500 font-semibold">${translateListingLabel("Verification")}</div>
        <div class="text-sm font-semibold text-gray-800 mt-1">${payload.lister_name || translateListingLabel("Not set")}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Display Name on Website *")}: ${payload.lister_display_name || translateListingLabel("Not set")}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Terms")}: ${termsOk} • OTP (${otpChannel.toUpperCase()}): ${otpOk}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Best Contact Method *")}: ${translateListingLabel(
          payload.extra_fields?.verify?.contact_preference === "whatsapp"
            ? "WhatsApp"
            : payload.extra_fields?.verify?.contact_preference === "both"
              ? "Phone + WhatsApp"
              : "Phone Call"
        )}</div>
        <div class="text-xs text-gray-500 mt-1">${translateListingLabel("Field Agent assisted?")}: ${fieldAgentTag}</div>
      </div>
    </div>
    ${payload.video_url ? `<div class="mt-3">${renderVideoEmbedCard(payload.video_url, {
      title: translateListingLabel("Video tour"),
      sub: translateListingLabel("This is how the video tour will appear after approval.")
    })}</div>` : ""}`;
}

function applySubmittedListingToLocal(payload, apiData = {}) {
  const maxId = PROPERTIES.reduce((max, p) => {
    const idNum = Number(p.id);
    return Number.isFinite(idNum) ? Math.max(max, idNum) : max;
  }, 0);
  const localId = maxId + 1;
  const nowIso = new Date().toISOString();
  const type = payload.listing_type === "student" ? "students" : payload.listing_type;
  const period = payload.price_period || "";
  const galleryPhotos = lpSelectedPhotos.map((file, idx) => ({
    url: URL.createObjectURL(file),
    name: file.name,
    slot: getLpPhotoSlotLabel(lpPhotoAssignments[idx], payload.listing_type) || `${translateListingLabel("Photo")} ${idx + 1}`,
    room_label: getLpPhotoSlotLabel(lpPhotoAssignments[idx], payload.listing_type) || "",
    location_label: [payload.area, payload.district].filter(Boolean).join(", "),
    is_main: idx === lpMainPhotoIndex
  }));
  const mainPhoto = galleryPhotos.find((item) => item.is_main) || galleryPhotos[0];
  const local = {
    id: localId,
    backend_id: apiData.id || null,
    title: payload.title,
    area: payload.area,
    district: payload.district,
    type,
    subtype: payload.property_type || payload.room_type || "Property",
    beds: payload.bedrooms || null,
    baths: payload.bathrooms || null,
    price: payload.price || 0,
    size: payload.extra_fields?.size_raw || "",
    img: mainPhoto?.url || "https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=900&q=80",
    images: galleryPhotos,
    main_photo_index: Number.isFinite(lpMainPhotoIndex) ? lpMainPhotoIndex : 0,
    photoCount: galleryPhotos.length,
    featured: false,
    lat: payload.latitude ?? null,
    lng: payload.longitude ?? null,
    desc: payload.description || "",
    status: payload.status || "pending",
    agent: null,
    period,
    video_url: payload.video_url || payload.extra_fields?.video_url || "",
    youtube_url: payload.extra_fields?.youtube_url || "",
    amenities: payload.amenities || [],
    area_highlights: payload?.extra_fields?.area_highlights || "",
    nearby_places: Array.isArray(payload?.extra_fields?.nearby_facilities) ? payload.extra_fields.nearby_facilities : [],
    contact_display_name: payload?.lister_display_name || payload?.extra_fields?.public_display_name || payload?.lister_name || "",
    nearest_university: payload.nearest_university || null,
    distance_to_uni_km: payload.distance_to_uni_km || null,
    student_universities: payload.nearest_university ? [payload.nearest_university] : [],
    student_verified: normalizeType(type) === "student" || !!payload.students_welcome,
    students_welcome: !!payload.students_welcome,
    created_at: nowIso,
    new_until: payload.new_until || null,
    listed_by: "private",
    registration_status: "not_registered"
  };
  PROPERTIES.unshift(local);
  districtCenterCache = null;
  populateListAddressSuggestions();
  renderAll();
  resetMaps();
}

function showListSubmissionSuccess(reference, payload, options = {}) {
  const successBox = document.getElementById("lp-success-box");
  const refEl = document.getElementById("lp-success-ref");
  const contactEl = document.getElementById("lp-success-contact");
  const statusEl = document.getElementById("lp-success-status");
  const modalPillEl = document.getElementById("listing-submit-pill");
  const modalTitleEl = document.getElementById("listing-submit-title");
  const modalSubEl = document.getElementById("listing-submit-sub");
  const modalRefEl = document.getElementById("listing-submit-ref");
  const modalContactEl = document.getElementById("listing-submit-contact");
  const modalStatusEl = document.getElementById("listing-submit-status");
  const modalTitleValueEl = document.getElementById("listing-submit-listing-title");
  const modalDateEl = document.getElementById("listing-submit-date");
  const modalEmailStatusEl = document.getElementById("listing-submit-email-status");
  const modalWhatsappStatusEl = document.getElementById("listing-submit-whatsapp-status");
  const modalWhatsappLinkEl = document.getElementById("listing-submit-whatsapp-link");
  const successTitleEl = document.getElementById("lp-success-title");
  const successSubEl = document.getElementById("lp-success-sub");
  const successRefLabelEl = document.getElementById("lp-success-ref-label");
  const modalRefLabelEl = document.getElementById("listing-submit-ref-label");
  const contactPref = payload?.extra_fields?.verify?.contact_preference || "both";
  const ownerEmailSent = options.owner_email_sent || options.ownerNotification?.email?.sent === true;
  const ownerWhatsAppReady = !!(options.owner_whatsapp_url || options.ownerNotification?.whatsapp?.manual_url);
  const ownerEmailDelivery = options.owner_notification?.email || options.ownerNotification?.email || {};
  const ownerWhatsappDelivery = options.owner_notification?.whatsapp || options.ownerNotification?.whatsapp || {};
  const email = payload?.lister_email || "";
  const submittedAt = new Date();
  let contactCopy = ownerEmailSent && email
    ? `${translateListingLabel("Confirmation email sent to")} ${email}. ${translateListingLabel("We will WhatsApp you once it's approved, and we can also follow up by email.")}`
    : translateListingLabel("Your listing has been received. We will email or WhatsApp you with the review update.");
  if (contactPref === "phone") contactCopy = translateListingLabel("We will call or email you once this listing is approved.");
  if (contactPref === "whatsapp" && !ownerEmailSent) contactCopy = translateListingLabel("We will WhatsApp you once it's approved, and we can also follow up by email.");
  if (ownerWhatsAppReady && !ownerEmailSent) {
    contactCopy = `${contactCopy} ${translateListingLabel("A WhatsApp confirmation message has also been prepared.")}`;
  }
  if (modalPillEl) modalPillEl.textContent = translateListingLabel("Submission Received");
  if (modalTitleEl) modalTitleEl.textContent = translateListingLabel("Your property has been submitted");
  if (modalSubEl) modalSubEl.textContent = translateListingLabel("Thank you. Your property listing has been submitted to MakaUg for review. Our team will check the details and contact you if we need anything else.");
  if (successTitleEl) successTitleEl.textContent = translateListingLabel("Your property has been submitted");
  if (successSubEl) successSubEl.textContent = translateListingLabel("Thank you. Your property listing has been submitted to MakaUg for review.");
  if (successRefLabelEl) successRefLabelEl.textContent = translateListingLabel("Reference:");
  if (modalRefLabelEl) modalRefLabelEl.textContent = translateListingLabel("Reference");
  const resolvedReference = reference || payload?.inquiry_reference || generateListingInquiryRef();
  if (!lpInquiryReference) lpInquiryReference = resolvedReference;
  if (refEl) refEl.textContent = resolvedReference;
  if (modalRefEl) modalRefEl.textContent = resolvedReference;
  if (modalTitleValueEl) modalTitleValueEl.textContent = payload?.title || translateListingLabel("Your property listing");
  if (modalDateEl) modalDateEl.textContent = submittedAt.toLocaleString();
  if (contactEl) contactEl.textContent = contactCopy;
  if (modalContactEl) {
    modalContactEl.className = "text-sm text-green-700 font-semibold mt-2";
    modalContactEl.textContent = contactCopy;
  }
  if (modalEmailStatusEl) {
    modalEmailStatusEl.textContent = ownerEmailSent
      ? translateListingLabel("Email confirmation sent.")
      : (ownerEmailDelivery?.reason === "no_email_provider_configured" || ownerEmailDelivery?.reason === "provider_missing"
        ? translateListingLabel("Email confirmation has been logged and will send when email is configured.")
        : translateListingLabel("Email confirmation logged for admin follow-up."));
  }
  if (modalWhatsappStatusEl) {
    modalWhatsappStatusEl.textContent = ownerWhatsappDelivery?.sent === true
      ? translateListingLabel("WhatsApp confirmation sent.")
      : (ownerWhatsappDelivery?.reason === "provider_missing" || ownerWhatsappDelivery?.reason === "not_configured"
        ? translateListingLabel("WhatsApp confirmation has been logged and will send when WhatsApp is configured.")
        : translateListingLabel("WhatsApp confirmation logged for admin follow-up."));
  }
  if (modalWhatsappLinkEl && options.owner_whatsapp_url) modalWhatsappLinkEl.href = options.owner_whatsapp_url;
  if (statusEl) {
    const isOffline = !!options.offline;
    statusEl.className = `text-xs mt-2 ${isOffline ? "text-amber-700" : "text-green-700"}`;
    statusEl.textContent = isOffline
      ? translateListingLabel("Submitted in offline mode. We will sync this listing once connection returns.")
      : translateListingLabel("Status: Pending Review.");
  }
  if (modalStatusEl) {
    const isOffline = !!options.offline;
    modalStatusEl.className = `text-sm font-semibold mt-1 ${isOffline ? "text-amber-700" : "text-green-900"}`;
    modalStatusEl.textContent = isOffline
      ? translateListingLabel("Submitted in offline mode. We will sync this listing once connection returns.")
      : translateListingLabel("Pending Review");
  }
  if (successBox) successBox.classList.remove("hidden");
  if (document.getElementById("listing-submit-modal")) openModal("listing-submit-modal");
}

function showListSubmissionError(message) {
  const modalPillEl = document.getElementById("listing-submit-pill");
  const modalTitleEl = document.getElementById("listing-submit-title");
  const modalSubEl = document.getElementById("listing-submit-sub");
  const modalRefEl = document.getElementById("listing-submit-ref");
  const modalContactEl = document.getElementById("listing-submit-contact");
  const modalStatusEl = document.getElementById("listing-submit-status");
  if (modalPillEl) modalPillEl.textContent = translateListingLabel("Submission Not Completed");
  if (modalTitleEl) modalTitleEl.textContent = translateListingLabel("We could not submit this listing");
  if (modalSubEl) modalSubEl.textContent = translateListingLabel("Please keep this page open and try again. If it continues, contact support with the error below.");
  if (modalRefEl) modalRefEl.textContent = "-";
  if (modalContactEl) {
    modalContactEl.className = "text-sm text-red-700 font-semibold mt-2";
    modalContactEl.textContent = message || translateListingLabel("Could not submit listing. Please try again.");
  }
  if (modalStatusEl) {
    modalStatusEl.className = "text-sm font-semibold mt-1 text-red-700";
    modalStatusEl.textContent = translateListingLabel("No listing has been created yet.");
  }
  openModal("listing-submit-modal");
}

async function submitListProperty() {
  if (!validateListStep1()) {
    setListWizardStep(1);
    return;
  }
  if (!validateListStep2()) {
    setListWizardStep(2);
    return;
  }
  if (!validateListStep3()) {
    setListWizardStep(3);
    return;
  }

  setButtonLoading("lp-submit-btn", true);
  try {
    const submitBtn = document.getElementById("lp-submit-btn");
    if (submitBtn) submitBtn.textContent = "Preparing photos...";
    const photoUploadUrls = await prepareListingPhotoUploadUrls();
    const payload = buildListPropertyPayload(photoUploadUrls);
    const response = await apiRequest("/api/properties", { method: "POST", body: payload });
    await trackEvent("property_submit", {
      listing_type: payload.listing_type,
      district: payload.district,
      area: payload.area,
      property_id: response?.data?.id || null
    });
    applySubmittedListingToLocal(payload, response?.data || {});
    const ref = response?.data?.inquiry_reference || payload.inquiry_reference;
    showListSubmissionSuccess(ref, payload, { offline: false, ...(response?.data || {}) });
    setListWizardStep(4);
    toast("Thanks. Listing submitted for review. We will contact you by WhatsApp or email within 24 hours.");
  } catch (error) {
    showListSubmissionError(error.message || "Could not submit listing. Please try again.");
    toast(error.message || "Could not submit listing. Please try again.");
  } finally {
    setButtonLoading("lp-submit-btn", false, "Submit Listing");
  }
}

async function submitLookingRequest() {
  const name = (document.getElementById("looking-name")?.value || "").trim();
  const phone = (document.getElementById("looking-phone")?.value || "").trim();
  const email = (document.getElementById("looking-email")?.value || "").trim();
  const preferredContact = (document.getElementById("looking-contact-method")?.value || "whatsapp").trim();
  const phoneIsWhatsapp = (document.getElementById("looking-phone-is-whatsapp")?.value || "yes").trim();
  const whatsappAltPhone = (document.getElementById("looking-whatsapp-alt")?.value || "").trim();
  const need = (document.getElementById("looking-need")?.value || "").trim();
  const preferredLocation = (document.getElementById("looking-location")?.value || "").trim();
  const budget = parseIntSafe(document.getElementById("looking-budget")?.value || "");
  const details = (document.getElementById("looking-details")?.value || "").trim();

  if (!name || (!phone && !email) || (!need && !details)) {
    toast(translateListingLabel("Please add your name, phone or email, and what you are looking for."));
    return;
  }
  if (preferredContact === "whatsapp" && phoneIsWhatsapp === "no" && !whatsappAltPhone) {
    toast(translateListingLabel("Please add the WhatsApp number you want us to use."));
    return;
  }

  setButtonLoading("looking-submit-btn", true);
  try {
    await apiRequest("/api/contact/looking-for-property", {
      method: "POST",
      body: {
        name,
        phone: normalizePhoneInput(phone),
        email,
        preferred_contact_channel: preferredContact,
        phone_is_whatsapp: phoneIsWhatsapp === "yes",
        whatsapp_phone: normalizePhoneInput(phoneIsWhatsapp === "yes" ? phone : whatsappAltPhone),
        preferred_locations: preferredLocation,
        listing_type: need || (currentTab === "students" ? "student" : currentTab),
        max_budget: budget || null,
        requirements: [
          need ? `Need: ${need}` : "",
          preferredLocation ? `Location: ${preferredLocation}` : "",
          budget ? `Budget: USh ${budget.toLocaleString()}` : "",
          preferredContact ? `Preferred contact: ${preferredContact}` : "",
          phoneIsWhatsapp === "no" && whatsappAltPhone ? `WhatsApp: ${whatsappAltPhone}` : "",
          details
        ].filter(Boolean).join("\n"),
        source: "looking_modal"
      }
    });
    await trackEvent("property_request_submit", { preferred_location: preferredLocation || "", tab: currentTab });
    toast(translateListingLabel("Request submitted. We will contact you shortly."));
    closeModal("looking-modal");
  } catch (error) {
    toast(error.message || translateListingLabel("Could not submit request."));
  } finally {
    setButtonLoading("looking-submit-btn", false, "Submit Request");
  }
}

async function submitHelpRequest(event) {
  if (event) event.preventDefault();
  const form = event?.target || document.getElementById("help-request-form");
  if (!form) return;
  const data = new FormData(form);
  const status = document.getElementById("help-request-status");
  const payload = {
    name: (data.get("name") || "").trim(),
    email: (data.get("email") || "").trim(),
    phone: normalizePhoneInput(data.get("phone") || ""),
    topic: (data.get("topic") || "Help").trim(),
    message: (data.get("message") || "").trim(),
    preferred_contact: (data.get("preferred_contact") || "WhatsApp").trim(),
    source: "help_centre"
  };
  if (!payload.name || !payload.email || !payload.phone || !payload.message) {
    toast("Add your name, email, phone/WhatsApp, and message.");
    return;
  }
  const button = form.querySelector("button[type='submit']");
  const original = button?.textContent || "Send help request";
  if (button) {
    button.disabled = true;
    button.textContent = "Sending...";
  }
  try {
    const res = await apiRequest("/api/contact/help-request", { method: "POST", body: payload });
    if (status) {
      status.classList.remove("hidden");
      status.textContent = `Help request received. Reference: ${res?.data?.id || "logged"}. MakaUg will contact you by ${payload.preferred_contact}.`;
    }
    toast("Help request sent to MakaUg.");
    form.reset();
  } catch (error) {
    if (status) {
      status.classList.remove("hidden");
      status.className = "rounded-xl border border-red-200 bg-red-50 p-3 text-sm text-red-700";
      status.textContent = error.message || "Could not send help request.";
    }
    toast(error.message || "Could not send help request.");
  } finally {
    if (button) {
      button.disabled = false;
      button.textContent = original;
    }
  }
}

