function setAgentOtpStatus(tone, message) {
  const el = document.getElementById("agent-otp-status");
  if (!el) return;
  if (tone === "success") {
    el.className = "text-xs text-green-700 mt-1";
  } else if (tone === "error") {
    el.className = "text-xs text-red-600 mt-1";
  } else if (tone === "warning") {
    el.className = "text-xs text-amber-700 mt-1";
  } else {
    el.className = "text-xs text-gray-500 mt-1";
  }
  el.textContent = message;
}

function setAgentOtpChannel(channel) {
  const next = String(channel || "phone").toLowerCase();
  agentOtpChannel = next === "email" ? "email" : "phone";
  agentRegistrationOtpToken = "";
  agentOtpVerifiedPhone = "";
  agentOtpVerifiedEmail = "";
  const otpInput = document.getElementById("agent-otp-code");
  if (otpInput) otpInput.value = "";
  setAgentOtpStatus("neutral", agentOtpChannel === "email"
    ? "Email OTP pending verification."
    : "SMS OTP pending verification.");
}

function resetAgentRegistrationOtpState() {
  const channelEl = document.getElementById("agent-otp-channel");
  if (channelEl) channelEl.value = "phone";
  setAgentOtpChannel("phone");
}

function renderAgentProfilePhotoPreview() {
  const preview = document.getElementById("agent-profile-photo-preview");
  const help = document.getElementById("agent-profile-photo-help");
  if (!preview) return;
  if (agentProfilePhotoDataUrl) {
    preview.innerHTML = `<img src="${adminAttr(agentProfilePhotoDataUrl)}" alt="Broker profile photo" class="w-full h-full object-cover">`;
    if (help) help.textContent = `${agentProfilePhotoFileName || "Profile photo"} is ready for the broker profile.`;
  } else {
    preview.textContent = "Photo";
    if (help) help.textContent = "Square headshot or logo recommended. JPG/PNG, max 5MB before compression.";
  }
}

function resetAgentProfilePhoto() {
  agentProfilePhotoDataUrl = "";
  agentProfilePhotoFileName = "";
  const fileInput = document.getElementById("agent-profile-photo-file");
  if (fileInput) fileInput.value = "";
  renderAgentProfilePhotoPreview();
}

async function handleAgentProfilePhotoSelection(event) {
  const file = event?.target?.files?.[0];
  if (!file) return;
  if (!(file.type || "").startsWith("image/")) {
    toast("Please choose an image file for the broker photo.");
    resetAgentProfilePhoto();
    return;
  }
  if (file.size > 5 * 1024 * 1024) {
    toast("Broker profile photo must be under 5MB.");
    resetAgentProfilePhoto();
    return;
  }
  try {
    agentProfilePhotoDataUrl = await compressPhotoForSubmission(file, { maxSide: 700, quality: 0.76 });
    agentProfilePhotoFileName = file.name || "profile-photo.jpg";
    renderAgentProfilePhotoPreview();
    toast("Broker profile photo added.");
  } catch (error) {
    resetAgentProfilePhoto();
    toast("Could not prepare broker profile photo.");
  }
}

function removeAgentProfilePhoto() {
  resetAgentProfilePhoto();
  toast("Broker profile photo removed.");
}

function onAgentPhoneInput() {
  const input = document.getElementById("agent-phone");
  const normalized = normalizePhoneInput(input?.value || "");
  if (input) input.value = normalized;
  if (!normalized) {
    if (input) input.classList.remove("border-green-300", "border-red-300");
    const msg = document.getElementById("agent-phone-msg");
    if (msg) {
      msg.className = "text-xs text-gray-500 mt-1";
      msg.textContent = "Use Uganda format e.g. +256770123456";
    }
    return;
  }
  const ok = /^\+2567\d{8}$/.test(normalized) || /^\+256\d{9}$/.test(normalized);
  setInlineValidation("agent-phone", "agent-phone-msg", ok, "Valid Uganda phone format.", "Use format +2567XXXXXXXX.");
  if (agentOtpVerifiedPhone && agentOtpVerifiedPhone !== normalized) {
    agentRegistrationOtpToken = "";
    agentOtpVerifiedPhone = "";
    setAgentOtpStatus("warning", "Phone changed. Please verify OTP again.");
  }
}

function onAgentEmailInput() {
  const email = String(document.getElementById("agent-email")?.value || "").trim().toLowerCase();
  if (!email) {
    const input = document.getElementById("agent-email");
    if (input) input.classList.remove("border-green-300", "border-red-300");
    const msg = document.getElementById("agent-email-msg");
    if (msg) {
      msg.className = "text-xs text-gray-500 mt-1";
      msg.textContent = "Enter a valid email address for OTP and updates.";
    }
    return;
  }
  const ok = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  setInlineValidation("agent-email", "agent-email-msg", ok, "Valid email format.", "Enter a valid email address.");
  if (agentOtpVerifiedEmail && agentOtpVerifiedEmail !== email) {
    agentRegistrationOtpToken = "";
    agentOtpVerifiedEmail = "";
    setAgentOtpStatus("warning", "Email changed. Please verify OTP again.");
  }
}

function onAgentNinInput() {
  const nin = normalizeNinInput(document.getElementById("agent-nin")?.value || "");
  if (!nin) {
    const input = document.getElementById("agent-nin");
    if (input) input.classList.remove("border-green-300", "border-red-300");
    const msg = document.getElementById("agent-nin-msg");
    if (msg) {
      msg.className = "text-xs text-gray-500 mt-1";
      msg.textContent = "Format check enabled for Uganda NIN style (CM/CF...).";
    }
    return;
  }
  const ok = isValidUgNin(nin);
  setInlineValidation("agent-nin", "agent-nin-msg", ok, "NIN format looks valid.", "Enter a valid Uganda NIN (e.g. CMXXXXXXXXXXXX).");
}

async function requestAgentOtp() {
  const channel = agentOtpChannel === "email" ? "email" : "phone";
  const phone = normalizePhoneInput(document.getElementById("agent-phone")?.value || "");
  const email = String(document.getElementById("agent-email")?.value || "").trim().toLowerCase();

  if (channel === "phone") {
    if (!phone || !(/^\+2567\d{8}$/.test(phone) || /^\+256\d{9}$/.test(phone))) {
      setAgentOtpStatus("error", "Enter a valid Uganda phone number first.");
      toast("Enter a valid Uganda phone number first.");
      return;
    }
  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    setAgentOtpStatus("error", "Enter a valid email address first.");
    toast("Enter a valid email address first.");
    return;
  }

  setButtonLoading("agent-send-otp-btn", true);
  try {
    await apiRequest("/api/properties/request-submit-otp", {
      method: "POST",
      body: {
        channel,
        phone: channel === "phone" ? phone : undefined,
        email: channel === "email" ? email : undefined,
        preferred_language: currentLang || "en",
        audience: "agent"
      }
    });
    agentRegistrationOtpToken = "";
    agentOtpVerifiedPhone = "";
    agentOtpVerifiedEmail = "";
    setAgentOtpStatus("success", channel === "email" ? "OTP sent to your email." : "OTP sent by SMS to your phone.");
  } catch (error) {
    const fallbackMsg = formatOtpDeliveryFallbackMessage(error.message, channel);
    setAgentOtpStatus("error", fallbackMsg);
    toast(fallbackMsg);
  } finally {
    setButtonLoading("agent-send-otp-btn", false, "Send OTP");
  }
}

async function verifyAgentOtp() {
  const channel = agentOtpChannel === "email" ? "email" : "phone";
  const phone = normalizePhoneInput(document.getElementById("agent-phone")?.value || "");
  const email = String(document.getElementById("agent-email")?.value || "").trim().toLowerCase();
  const code = String(document.getElementById("agent-otp-code")?.value || "").trim();

  if (!code) {
    setAgentOtpStatus("error", "Enter the 6-digit OTP code.");
    toast("Enter the 6-digit OTP code.");
    return;
  }
  if (channel === "phone" && !phone) {
    setAgentOtpStatus("error", "Enter phone number and OTP code.");
    toast("Enter phone number and OTP code.");
    return;
  }
  if (channel === "email" && !email) {
    setAgentOtpStatus("error", "Enter email and OTP code.");
    toast("Enter email and OTP code.");
    return;
  }

  setButtonLoading("agent-verify-otp-btn", true);
  try {
    const response = await apiRequest("/api/properties/verify-submit-otp", {
      method: "POST",
      body: {
        channel,
        phone: channel === "phone" ? phone : undefined,
        email: channel === "email" ? email : undefined,
        code
      }
    });
    agentRegistrationOtpToken = response?.data?.listing_otp_token || "";
    agentOtpVerifiedPhone = channel === "phone" ? phone : "";
    agentOtpVerifiedEmail = channel === "email" ? email : "";
    setAgentOtpStatus("success", `${channel === "email" ? "Email" : "Phone"} OTP verified.`);
  } catch (error) {
    agentRegistrationOtpToken = "";
    setAgentOtpStatus("error", error.message || "OTP verification failed.");
    toast(error.message || "OTP verification failed.");
  } finally {
    setButtonLoading("agent-verify-otp-btn", false, "Verify OTP");
  }
}

async function submitAgentApplication() {
  const fullName = (document.getElementById("agent-full-name")?.value || "").trim();
  const licenceNumber = (document.getElementById("agent-licence")?.value || "").trim();
  const companyName = (document.getElementById("agent-company")?.value || "").trim();
  const phone = normalizePhoneInput(document.getElementById("agent-phone")?.value || "");
  const whatsapp = normalizePhoneInput(document.getElementById("agent-whatsapp")?.value || "");
  const email = (document.getElementById("agent-email")?.value || "").trim().toLowerCase();
  const districtsCovered = (document.getElementById("agent-areas")?.value || "").trim();
  const nin = normalizeNinInput((document.getElementById("agent-nin")?.value || "").trim());
  const registrationStatus = "not_registered";
  const fieldAgentAssisted = (document.getElementById("agent-field-assisted")?.value || "no") === "yes";
  const fieldAgentId = (document.getElementById("agent-field-id")?.value || "").trim();
  const otpChannel = agentOtpChannel === "email" ? "email" : "phone";
  const resolvedLicenceNumber = licenceNumber || `PENDING-${Date.now()}`;

  if (!fullName || !phone || !email || !districtsCovered || !nin) {
    toast("Please complete all required broker fields.");
    return;
  }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    toast("Please enter a valid email address for broker registration.");
    return;
  }
  if (!(/^\+2567\d{8}$/.test(phone) || /^\+256\d{9}$/.test(phone))) {
    toast("Please enter a valid Uganda phone number.");
    return;
  }
  if (!isValidUgNin(nin)) {
    toast("Please enter a valid Uganda NIN.");
    return;
  }
  const otpVerified = !!agentRegistrationOtpToken && (
    (otpChannel === "email" && agentOtpVerifiedEmail === email) ||
    (otpChannel === "phone" && agentOtpVerifiedPhone === phone)
  );
  if (!otpVerified) {
    setAgentOtpStatus("error", otpChannel === "email"
      ? "Verify email OTP before submitting."
      : "Verify phone OTP before submitting.");
    toast(otpChannel === "email"
      ? "Please verify email OTP before submitting."
      : "Please verify phone OTP before submitting.");
    return;
  }
  if (fieldAgentAssisted && !fieldAgentId) {
    toast("Please enter Field Agent ID or set assisted to No.");
    return;
  }

  setButtonLoading("agent-submit-btn", true);
  try {
    await apiRequest("/api/agents/register", {
      method: "POST",
      body: {
        full_name: fullName,
        licence_number: resolvedLicenceNumber,
        company_name: companyName,
        phone,
        whatsapp: whatsapp || phone,
        email,
        districts_covered: districtsCovered,
        nin,
        registration_status: registrationStatus,
        registration_request: "admin_review",
        otp_channel: otpChannel,
        listing_otp_token: agentRegistrationOtpToken,
        profile_photo_url: agentProfilePhotoDataUrl || undefined,
        bio: fieldAgentAssisted ? `Onboarded with Field Agent ${fieldAgentId}` : undefined
      }
    });
    await trackEvent("agent_register_submit", { district_scope: districtsCovered });
    toast("Application submitted. Broker verification will be reviewed by admin.");
    resetAgentProfilePhoto();
    closeModal("broker-reg-modal");
  } catch (error) {
    toast(error.message || "Could not submit application.");
  } finally {
    setButtonLoading("agent-submit-btn", false, "Submit Application");
  }
}

function syncAgentRegistrationForm() {
  const licenceLabel = document.getElementById("agent-licence-label");
  const certificateLabel = document.getElementById("agent-certificate-label");
  const licenceInput = document.getElementById("agent-licence");
  const fullNameInput = document.getElementById("agent-full-name");
  const certificateWrap = document.getElementById("agent-certificate-wrap");
  const licenceWrap = document.getElementById("agent-licence-wrap");
  const registeredNote = document.getElementById("agent-registered-note");
  const notRegisteredNote = document.getElementById("agent-not-registered-note");

  if (fullNameInput) fullNameInput.placeholder = "As on your legal National ID";
  if (licenceLabel) licenceLabel.textContent = "AREA Uganda Licence Number (optional)";
  if (certificateLabel) certificateLabel.textContent = "Upload AREA Certificate (optional)";
  if (licenceInput) licenceInput.placeholder = "Add it if available";
  if (licenceWrap) licenceWrap.classList.remove("hidden");
  if (certificateWrap) certificateWrap.classList.remove("hidden");
  if (certificateWrap) certificateWrap.classList.remove("opacity-70");
  if (registeredNote) registeredNote.classList.remove("hidden");
  if (notRegisteredNote) notRegisteredNote.classList.add("hidden");
}

function toggleAgentFieldIdInput() {
  const assisted = (document.getElementById("agent-field-assisted")?.value || "no") === "yes";
  const wrap = document.getElementById("agent-field-id-wrap");
  if (!wrap) return;
  wrap.classList.toggle("hidden", !assisted);
}

function setLpOtpChannel(channel) {
  const next = String(channel || "phone").toLowerCase();
  lpListingOtpChannel = next === "email" ? "email" : "phone";
  const otpStatus = document.getElementById("lp-otp-status");
  if (otpStatus) {
    otpStatus.className = "text-xs text-gray-500 mt-1";
    otpStatus.textContent = lpListingOtpChannel === "email"
      ? "Email OTP pending verification."
      : "SMS OTP pending verification.";
  }
  lpListingOtpToken = "";
  lpListingOtpVerifiedPhone = "";
  lpListingOtpVerifiedEmail = "";
  renderListReviewSummary();
}

function toggleLpFieldAgentId() {
  const assisted = (document.getElementById("lp-field-agent-assisted")?.value || "no") === "yes";
  const wrap = document.getElementById("lp-field-agent-id-wrap");
  if (wrap) wrap.classList.toggle("hidden", !assisted);
  if (!assisted) {
    const input = document.getElementById("lp-field-agent-id");
    if (input) input.value = "";
  }
  renderListReviewSummary();
}

function getListChoiceType() {
  return lpChoiceType || getListType() || "sale";
}

function listingThemeClass(type = "sale") {
  return `lp-theme-${["sale", "rent", "land", "commercial", "student"].includes(type) ? type : "sale"}`;
}

function getListPropertyRouteMode() {
  try {
    return new URLSearchParams(window.location.search || "").get("mode") || "";
  } catch (_) {
    return "";
  }
}

function getListPropertyRouteType() {
  try {
    const value = new URLSearchParams(window.location.search || "").get("type") || "";
    return ["sale", "rent", "land", "commercial", "student"].includes(value) ? value : "";
  } catch (_) {
    return "";
  }
}

function inferListTypeFromCurrentRoute() {
  const path = String(window.location.pathname || "").toLowerCase();
  if (currentPage === "rent" || path.includes("to-rent")) return "rent";
  if (currentPage === "students" || path.includes("student")) return "student";
  if (currentPage === "land" || path.includes("land")) return "land";
  if (currentPage === "commercial" || path.includes("commercial")) return "commercial";
  if (currentPage === "sale" || path.includes("for-sale")) return "sale";
  return getListChoiceType() || "sale";
}

