function applyListPropertyTheme(type = getListChoiceType()) {
  const themeClasses = ["lp-theme-sale", "lp-theme-rent", "lp-theme-land", "lp-theme-commercial", "lp-theme-student"];
  ["page-list-property", "lp-wizard-shell", "list-choice-box"].forEach((id) => {
    const el = document.getElementById(id);
    if (!el) return;
    el.classList.remove(...themeClasses);
    el.classList.add(listingThemeClass(type));
  });
  requestAnimationFrame(() => {
    applyListThemeToControls();
  });
}

function applyListThemeToControls() {
  const host = document.getElementById("page-list-property") || document.getElementById("lp-wizard-shell");
  if (!host) return;
  const style = getComputedStyle(host);
  const accent = style.getPropertyValue("--lp-accent").trim() || "#166534";
  const soft = style.getPropertyValue("--lp-soft").trim() || "#f0fdf4";
  const border = style.getPropertyValue("--lp-border").trim() || "#bbf7d0";
  const ink = style.getPropertyValue("--lp-ink").trim() || "#14532d";
  document.querySelectorAll("[data-lp-step-circle]").forEach((circle) => {
    const step = Number(circle.getAttribute("data-lp-step-circle") || 0);
    circle.style.background = step <= listWizardStep ? accent : soft;
    circle.style.color = step <= listWizardStep ? "#ffffff" : ink;
    circle.style.borderColor = border;
  });
  document.querySelectorAll("[data-lp-step-label]").forEach((label) => {
    const step = Number(label.getAttribute("data-lp-step-label") || 0);
    label.style.color = step <= listWizardStep ? ink : "color-mix(in srgb, var(--lp-ink) 68%, #64748b)";
  });
}

function syncListChoiceCopy(type = getListChoiceType()) {
  const meta = listChoiceMeta(type);
  setTextById("lp-choice-gate-title", translateListingLabel(meta.gateTitle));
  setTextById("lp-choice-gate-copy", translateListingLabel(meta.gateCopy));
  setTextById("lp-choice-online-context", translateListingLabel(meta.onlineCopy));
  setTextById("lp-choice-whatsapp-context", translateListingLabel(meta.whatsappCopy));
  setTextById("list-choice-sub", translateListingLabel(meta.modalSub));
  setTextById("list-choice-online-copy", translateListingLabel(meta.onlineCopy));
  setTextById("list-choice-wa-copy", translateListingLabel(meta.whatsappCopy));
  const title = document.getElementById("list-choice-title");
  if (title) title.textContent = translateListingLabel(meta.gateTitle);
  const subtitle = document.getElementById("lp-page-subtitle");
  if (subtitle) subtitle.textContent = translateListingLabel(meta.gateCopy);
  document.querySelectorAll("[data-list-choice-type]").forEach((chip) => {
    chip.classList.toggle("active", chip.getAttribute("data-list-choice-type") === type);
  });
}

function setListChoiceType(type) {
  const selected = ["sale", "rent", "land", "commercial", "student"].includes(type) ? type : "sale";
  lpChoiceType = selected;
  applyListPropertyTheme(selected);
  syncListChoiceCopy(selected);
  const radio = document.querySelector(`input[name='lp-type'][value='${selected}']`);
  if (radio) {
    radio.checked = true;
    setListType(selected);
  }
  updateListPropertyWhatsAppLinks();
}

function setListPropertyFormVisible(visible) {
  const show = visible === true;
  document.getElementById("lp-stepper")?.classList.toggle("hidden", !show);
  document.getElementById("lp-wizard-shell")?.classList.toggle("hidden", !show);
  document.getElementById("lp-choice-gate")?.classList.toggle("hidden", show);
  if (show) {
    setListWizardStep(listWizardStep || 1);
    ensureListPinMap();
    refreshListPinMapFromInputs();
  }
}

function maybeOpenListPropertyChoiceModal() {
  if (currentPage !== "list-property") return;
  const mode = getListPropertyRouteMode();
  const type = getListPropertyRouteType();
  if (type) setListChoiceType(type);
  if (mode === "online") {
    chooseListPropertyOnline({ source: "route_query", skipModalClose: true });
    return;
  }
  setListPropertyFormVisible(false);
  window.setTimeout(() => {
    if (currentPage === "list-property" && !lpListingPathChoice) openListPropertyOptions();
  }, 120);
}

function openListPropertyOptions() {
  if (!document.getElementById("list-choice-modal")) {
    trackEvent("list_property_cta_clicked", { source: "public_route_fallback" });
    window.location.href = "/list-property";
    return;
  }
  setListChoiceType(inferListTypeFromCurrentRoute());
  updateListPropertyWhatsAppLinks();
  openModal("list-choice-modal");
}

function publicRouteForPageModal(page) {
  return {
    advertise: "/advertise",
    "how-it-works": "/how-it-works",
    careers: "/careers",
    help: "/help",
    safety: "/safety",
    terms: "/terms",
    privacy: "/privacy-policy",
    cookies: "/cookie-policy",
    "anti-fraud": "/anti-fraud"
  }[String(page || "").toLowerCase()] || "/";
}

function handleAdvertisePropertyCta(event) {
  if (event) event.preventDefault();
  trackEvent("advertise_property_cta_clicked", {
    source_page: window.location.pathname || "/",
    signed_in: !!authState?.user
  });
  const mode = derivePortalMode(authState?.user, authState?.user?.portal_mode);
  if (mode === "admin") {
    window.location.href = "/admin/advertising";
    return;
  }
  if (mode === "advertiser") {
    window.location.href = "/advertiser-dashboard?tab=create-campaign";
    return;
  }
  navigatePublicRoute("/advertise", null, { source: "advertise_cta" });
}

function handleListPropertyFreeCta(event) {
  if (event) event.preventDefault();
  trackEvent("list_property_free_cta_clicked", {
    source_page: window.location.pathname || "/",
    signed_in: !!authState?.user
  });
  const inferredType = inferListTypeFromCurrentRoute();
  navigatePublicRoute(`/list-property?type=${encodeURIComponent(inferredType)}`, null, { source: "list_property_cta" });
}

function getSelectedListPropertyTypeLabel() {
  const selected = document.querySelector('input[name="lp-type"]:checked')?.value || getListChoiceType() || "";
  return {
    sale: "For Sale",
    rent: "For Rent",
    student: "Student accommodation",
    land: "Land",
    commercial: "Commercial"
  }[selected] || "";
}

function getListPropertyContext() {
  const location = (
    document.getElementById("lp-address-search")?.value ||
    document.getElementById("lp-place-search")?.value ||
    document.getElementById("lp-manual-landmark")?.value ||
    document.getElementById("lp-area")?.value ||
    ""
  ).trim();
  return {
    listing_type: getListChoiceType(),
    listing_type_label: getSelectedListPropertyTypeLabel(),
    title: (document.getElementById("lp-title")?.value || document.getElementById("listing-title")?.value || "").trim(),
    location,
    source_page: window.location.pathname || "/list-property",
    signed_in: !!authState?.user,
    language: currentLang || "en"
  };
}

function logListPropertyIntent(mode, extra = {}) {
  const context = getListPropertyContext();
  const payload = {
    mode,
    ...context,
    ...extra
  };
  trackEvent("list_property_path_selected", payload);
  apiRequest("/api/properties/listing-intent", {
    method: "POST",
    body: payload
  }).catch(() => {});
}

function buildListPropertyWhatsAppMessage() {
  const type = getSelectedListPropertyTypeLabel();
  const title = (document.getElementById("lp-title")?.value || document.getElementById("listing-title")?.value || "").trim();
  const location = (document.getElementById("lp-place-search")?.value || document.getElementById("lp-address-search")?.value || document.getElementById("lp-manual-landmark")?.value || "").trim();
  const parts = ["Hi MakaUg, I want to list a property."];
  if (type) parts.push(`Type: ${type}.`);
  if (title) parts.push(`Title: ${title}.`);
  if (location) parts.push(`Location: ${location}.`);
  parts.push("Please help me create the listing.");
  return parts.join(" ").replace(/\b(undefined|null)\b/gi, "").replace(/\s+/g, " ").trim();
}

function listPropertyWhatsAppUrl() {
  return `https://wa.me/256760112587?text=${encodeURIComponent(buildListPropertyWhatsAppMessage())}`;
}

function updateListPropertyWhatsAppLinks() {
  const href = listPropertyWhatsAppUrl();
  ["lp-wa-link", "lp-whatsapp-option-btn"].forEach((id) => {
    const link = document.getElementById(id);
    if (link) link.href = href;
  });
}

function chooseListPropertyOnline(options = {}) {
  lpListingPathChoice = "online";
  const type = getListChoiceType();
  setListChoiceType(type);
  logListPropertyIntent("online", { source: options.source || "list_property_choice" });
  if (currentPage !== "list-property") {
    window.location.href = `/list-property?mode=online&type=${encodeURIComponent(type)}`;
    return;
  }
  if (!options.skipModalClose) closeModal("list-choice-modal");
  setListPropertyFormVisible(true);
  window.setTimeout(() => {
    document.getElementById("lp-title")?.focus?.();
  }, 80);
}

function chooseListPropertyWhatsApp(options = {}) {
  const event = options.event;
  const href = listPropertyWhatsAppUrl();
  logListPropertyIntent("whatsapp_ai", { source: options.source || "list_property_choice" });
  try {
    const link = event?.currentTarget || document.getElementById("lp-whatsapp-option-btn") || document.getElementById("lp-wa-link");
    if (link) link.href = href;
  } catch (_) {}
  closeModal("list-choice-modal");
  if (!event) {
    window.open(href, "_blank", "noopener,noreferrer");
  }
  return true;
}

function handleListPropertyWhatsAppClick(event) {
  const href = listPropertyWhatsAppUrl();
  logListPropertyIntent("whatsapp_ai", { source: "form_whatsapp_cta" });
  try {
    const link = event?.currentTarget || document.getElementById("lp-wa-link");
    if (link) link.href = href;
  } catch (_) {}
}

function openListPropertyWhatsApp() {
  chooseListPropertyWhatsApp({ source: "form_whatsapp_cta" });
}

function handleSavedClick(event) {
  if (!authState?.user) {
    if (event) event.preventDefault();
    trackEvent("saved_auth_required_clicked", { source_page: window.location.pathname || "/" });
    openAuthSignIn("finder");
    return;
  }
  if (event) event.preventDefault();
  window.location.href = "/dashboard?tab=saved";
}

function handlePropertyNeedCta(event) {
  if (document.getElementById("looking-modal")) {
    if (event) event.preventDefault();
    openModal("looking-modal");
    return;
  }
  if (!authState?.user && event) {
    event.preventDefault();
    openAuthSignIn("finder");
  }
}

