function renderAccountAccessRoleCards() {
  return ["finder", "student", "agent", "field_agent", "advertiser"].map((role) => {
    const copy = accountAccessRoleCopy(role);
    const theme = accountAccessRoleTheme(role);
    return `<button type="button" data-auth-drawer-role="${role}" data-auth-role-card="1" data-auth-role-accent="${theme.name}" onclick="setAccountAccessRole('${role}')" class="group text-left rounded-2xl border px-3.5 py-3 focus:outline-none focus:ring-2 focus:ring-offset-1 transition" style="border-color:#e5e7eb; --tw-ring-color:${theme.primary};">
      <span class="flex items-center gap-3">
        <span class="w-10 h-10 rounded-2xl flex items-center justify-center transition" style="background:${theme.soft}; color:${theme.primary};">
          <i class="fas ${copy.icon}" aria-hidden="true"></i>
        </span>
        <span>
          <span class="block text-sm font-black text-gray-900">${adminEscape(copy.label)}</span>
          <span class="block text-xs text-gray-600 mt-0.5">${adminEscape(copy.body)}</span>
        </span>
      </span>
    </button>`;
  }).join("");
}

