function applyAccountAccessLanguageUi() {
  const drawer = document.getElementById("account-access-drawer");
  if (!drawer) return;
  setTextById("account-access-title", accountAccessText("heading"));
  setTextById("account-access-brand-kicker", `${publicBrand()} account`);
  setTextById("auth-drawer-benefits", accountAccessRouteBenefit());
  const sub = drawer.querySelector("[data-auth-drawer-subheading]");
  if (sub) sub.textContent = accountAccessText("subheading");
  const roleList = document.getElementById("account-access-role-list");
  if (roleList) roleList.innerHTML = renderAccountAccessRoleCards();
  const langLabel = drawer.querySelector("[data-auth-label-language]");
  if (langLabel) langLabel.textContent = accountAccessText("language");
  const continueAs = drawer.querySelector("[data-auth-label-continue-as]");
  if (continueAs) continueAs.textContent = accountAccessText("continueAs");
  drawer.querySelectorAll("[data-auth-text]").forEach((el) => {
    const key = el.getAttribute("data-auth-text");
    if (key) el.textContent = accountAccessText(key);
  });
  const termsCopy = document.getElementById("account-access-terms-copy");
  if (termsCopy) {
    termsCopy.innerHTML = `${accountAccessText("terms").replace("Terms & Conditions", `<button type="button" data-auth-accent-link="1" onclick="openPolicyPreviewModal('terms')" onfocus="showPolicyPreviewCard(this, 'terms')" onblur="hidePolicyPreviewCard()" onmouseenter="showPolicyPreviewCard(this, 'terms')" onmouseleave="hidePolicyPreviewCard()" class="font-bold text-green-700 underline decoration-green-200">Terms & Conditions</button>`)}`;
  }
  const privacyCopy = document.getElementById("account-access-privacy-copy");
  if (privacyCopy) {
    privacyCopy.innerHTML = `${accountAccessText("privacy").replace("Privacy Policy", `<button type="button" data-auth-accent-link="1" onclick="openPolicyPreviewModal('privacy')" onfocus="showPolicyPreviewCard(this, 'privacy')" onblur="hidePolicyPreviewCard()" onmouseenter="showPolicyPreviewCard(this, 'privacy')" onmouseleave="hidePolicyPreviewCard()" class="font-bold text-green-700 underline decoration-green-200">Privacy Policy</button>`)}`;
  }
  setAccountAccessRole(accountAccessDrawerAudience);
  applyAccountAccessTheme();
  if (accountAccessDrawerMode === "create" || accountAccessDrawerMode === "verify") {
    setAccountAccessCreateStep(accountAccessCreateStep);
  } else if (accountAccessDrawerMode === "forgot") {
    setTextById("account-access-mode-label", accountAccessText("forgotTitle"));
    const btn = document.getElementById("account-access-continue-btn");
    if (btn) btn.textContent = accountAccessForgotResetState ? accountAccessText("resetPassword") : accountAccessText("sendResetCode");
  } else {
    setTextById("account-access-mode-label", accountAccessText("signIn"));
    const btn = document.getElementById("account-access-continue-btn");
    if (btn) btn.textContent = accountAccessText("signIn");
  }
  updateAccountAccessProgress(accountAccessDrawerStep);
}

function renderAccountAccessScreening() {
  const wrap = document.getElementById("account-access-screening");
  if (!wrap) return;
  const questions = (ACCOUNT_ACCESS_SCREENING[accountAccessDrawerAudience] || ACCOUNT_ACCESS_SCREENING.finder).slice(0, 5);
  wrap.innerHTML = questions.map((question) => `
    <label class="block">
      <span class="block text-xs font-bold text-gray-600 mb-1">${adminEscape(accountAccessScreeningText(question.label))}</span>
      <select data-auth-screening-key="${question.key}" class="w-full min-h-[48px] border rounded-xl px-4 py-3 text-sm bg-white" style="border-color:var(--auth-role-border, #bbf7d0);">
        ${question.options.map((option) => `<option value="${adminAttr(option)}">${adminEscape(accountAccessScreeningText(option))}</option>`).join("")}
      </select>
    </label>
  `).join("");
}

function updateAccountAccessProgress(step = "account") {
  accountAccessDrawerStep = step;
  const progress = document.getElementById("account-access-progress-summary");
  if (!progress) return;
  const labels = {
    details: "1 of 4: Details",
    verify: "2 of 4: Verify",
    preferences: "3 of 4: Preferences",
    password: "4 of 4: Password"
  };
  const shouldShow = accountAccessDrawerMode === "create" || accountAccessDrawerMode === "verify";
  progress.classList.toggle("hidden", !shouldShow);
  progress.textContent = shouldShow ? (labels[step] || labels.details) : "";
}

function updateAccountAccessRoleFocus() {
  const listWrap = document.getElementById("account-access-role-list-wrap");
  const selectedWrap = document.getElementById("account-access-selected-role-card");
  const secondary = document.getElementById("account-access-secondary-actions");
  const isFocusedFlow = accountAccessDrawerMode === "create" || accountAccessDrawerMode === "verify";
  if (listWrap) listWrap.classList.toggle("hidden", isFocusedFlow);
  if (selectedWrap) {
    const copy = accountAccessRoleCopy(accountAccessDrawerAudience);
    const theme = accountAccessRoleTheme(accountAccessDrawerAudience);
    selectedWrap.classList.toggle("hidden", !isFocusedFlow);
    selectedWrap.style.borderColor = theme.border;
    selectedWrap.style.background = theme.soft;
    selectedWrap.innerHTML = isFocusedFlow ? `<div class="flex items-center justify-between gap-3">
      <div class="flex items-center gap-3">
        <span class="w-10 h-10 rounded-2xl bg-white flex items-center justify-center" style="color:${theme.primary};"><i class="fas ${copy.icon}" aria-hidden="true"></i></span>
        <span><span class="block text-sm font-black text-gray-900">${adminEscape(copy.label)}</span><span class="block text-xs text-gray-600">${adminEscape(copy.body)}</span></span>
      </div>
      ${accountAccessDrawerMode === "create" && accountAccessCreateStep === "details" ? `<button type="button" onclick="showAccountAccessRolePicker()" class="text-xs font-bold" style="color:${theme.primary};">Back to account type</button>` : ""}
    </div>` : "";
  }
  if (secondary) secondary.classList.toggle("hidden", accountAccessDrawerMode === "verify" || accountAccessDrawerMode === "forgot");
}

function applyAccountAccessTheme() {
  const drawer = document.getElementById("account-access-drawer");
  if (!drawer) return;
  const theme = accountAccessRoleTheme(accountAccessDrawerAudience);
  drawer.setAttribute("data-auth-role-theme", normalizeAuthAudience(accountAccessDrawerAudience));
  drawer.style.setProperty("--auth-role-primary", theme.primary);
  drawer.style.setProperty("--auth-role-secondary", theme.secondary);
  drawer.style.setProperty("--auth-role-soft", theme.soft);
  drawer.style.setProperty("--auth-role-border", theme.border);
  drawer.style.setProperty("--auth-role-text", theme.text);
  const header = document.getElementById("account-access-header");
  if (header) header.style.background = theme.header;
  const benefit = document.getElementById("auth-drawer-benefits");
  if (benefit) {
    benefit.style.background = theme.soft;
    benefit.style.borderColor = theme.border;
    benefit.style.color = theme.text;
  }
  const modeLabel = document.getElementById("account-access-mode-label");
  if (modeLabel) modeLabel.style.color = theme.text;
  const roleLabel = document.getElementById("account-access-role-label");
  if (roleLabel) roleLabel.style.color = theme.primary;
  const progress = document.getElementById("account-access-progress-summary");
  if (progress) progress.style.background = "rgba(255,255,255,0.18)";
  const otpWrap = document.getElementById("account-access-otp-method-wrap");
  if (otpWrap) {
    otpWrap.style.background = theme.soft;
    otpWrap.style.borderColor = theme.border;
  }
  const continueBtn = document.getElementById("account-access-continue-btn");
  if (continueBtn) {
    continueBtn.style.background = theme.primary;
    continueBtn.style.borderColor = theme.primary;
  }
  drawer.querySelectorAll("#account-access-secondary-actions button, [data-auth-accent-link]").forEach((el) => {
    el.style.color = theme.primary;
  });
  drawer.querySelectorAll(".accent-green-700").forEach((el) => {
    el.style.accentColor = theme.primary;
  });
}

function setAccountAccessCreateStep(step = "details") {
  accountAccessCreateStep = ["details", "verify", "preferences", "password"].includes(step) ? step : "details";
  const isVerify = accountAccessCreateStep === "verify";
  const stepIds = {
    details: "account-access-create-details-step",
    preferences: "account-access-create-preferences-step",
    password: "account-access-create-password-step"
  };
  Object.entries(stepIds).forEach(([key, id]) => {
    document.getElementById(id)?.classList.toggle("hidden", key !== accountAccessCreateStep);
  });
  document.getElementById("account-access-otp-wrap")?.classList.toggle("hidden", !isVerify);
  document.getElementById("account-access-create-wrap")?.classList.toggle("hidden", isVerify);
  document.getElementById("account-access-signin-wrap")?.classList.add("hidden");
  document.getElementById("account-access-password-wrap")?.classList.add("hidden");
  document.getElementById("account-access-forgot-wrap")?.classList.add("hidden");
  const note = document.getElementById("account-access-create-flow-note");
  if (note) {
    const noteKey = accountAccessCreateStep === "preferences"
      ? "preferencesStepNote"
      : (accountAccessCreateStep === "password" ? "passwordStepNote" : "contactStepNote");
    note.textContent = accountAccessText(noteKey);
  }
  const titles = {
    details: accountAccessText("detailsTitle"),
    verify: accountAccessText("verifyTitle"),
    preferences: accountAccessText("preferencesTitle"),
    password: accountAccessText("passwordTitle")
  };
  setTextById("account-access-mode-label", titles[accountAccessCreateStep] || accountAccessText("createAccount"));
  const btn = document.getElementById("account-access-continue-btn");
  if (btn) {
    const labels = {
      details: accountAccessText("sendCode"),
      verify: accountAccessText("verifyCode"),
      preferences: accountAccessText("continue"),
      password: accountAccessText("createFinal")
    };
    btn.textContent = labels[accountAccessCreateStep] || accountAccessText("continue");
  }
  updateAccountAccessProgress(accountAccessCreateStep);
  updateAccountAccessRoleFocus();
  applyAccountAccessTheme();
}

function showAccountAccessRolePicker() {
  accountAccessDrawerMode = "signin";
  accountAccessPendingOtp = null;
  accountAccessContactVerificationToken = "";
  accountAccessCreateStep = "details";
  accountAccessForgotResetState = null;
  const signInWrap = document.getElementById("account-access-signin-wrap");
  const createWrap = document.getElementById("account-access-create-wrap");
  const passwordWrap = document.getElementById("account-access-password-wrap");
  const otpWrap = document.getElementById("account-access-otp-wrap");
  const forgotWrap = document.getElementById("account-access-forgot-wrap");
  if (signInWrap) signInWrap.classList.remove("hidden");
  if (createWrap) createWrap.classList.add("hidden");
  if (passwordWrap) passwordWrap.classList.remove("hidden");
  if (otpWrap) otpWrap.classList.add("hidden");
  if (forgotWrap) forgotWrap.classList.add("hidden");
  setTextById("account-access-mode-label", accountAccessText("signIn"));
  const btn = document.getElementById("account-access-continue-btn");
  if (btn) btn.textContent = accountAccessText("signIn");
  updateAccountAccessProgress("account");
  updateAccountAccessSignInCopy();
  updateAccountAccessRoleFocus();
}

function showAccountAccessSignIn() {
  accountAccessDrawerMode = "signin";
  accountAccessForgotResetState = null;
  document.getElementById("account-access-signin-wrap")?.classList.remove("hidden");
  document.getElementById("account-access-password-wrap")?.classList.remove("hidden");
  document.getElementById("account-access-create-wrap")?.classList.add("hidden");
  document.getElementById("account-access-otp-wrap")?.classList.add("hidden");
  document.getElementById("account-access-forgot-wrap")?.classList.add("hidden");
  setTextById("account-access-mode-label", accountAccessText("signIn"));
  const btn = document.getElementById("account-access-continue-btn");
  if (btn) btn.textContent = accountAccessText("signIn");
  updateAccountAccessProgress("account");
  updateAccountAccessSignInCopy();
  updateAccountAccessRoleFocus();
  setTimeout(() => document.getElementById("account-access-identifier")?.focus(), 30);
}

