function openPageMod(page) {
  const html = PAGE_CONTENT[page];
  if (!html) {
    toast("Content coming soon");
    return;
  }
  const body = document.getElementById("page-modal-body");
  if (!body) {
    window.location.href = publicRouteForPageModal(page);
    return;
  }
  if (body) body.innerHTML = html;
  if (body) localizePageModalContent(body);
  openModal("page-modal");
  if (page === "advertise") hydrateAdvertisePricingPreview();
}

function localizePageModalContent(root) {
  if (!root || (currentLang || "en") === "en") return;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);
  const nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  nodes.forEach((node) => {
    const raw = node.nodeValue || "";
    const trimmed = raw.trim();
    if (!trimmed || trimmed.length > 90) return;
    const translated = translateListingLabel(trimmed);
    if (translated && translated !== trimmed) {
      node.nodeValue = raw.replace(trimmed, translated);
    }
  });
  root.querySelectorAll("input[placeholder], textarea[placeholder]").forEach((el) => {
    const placeholder = el.getAttribute("placeholder") || "";
    el.setAttribute("placeholder", translateListingLabel(placeholder));
  });
  root.querySelectorAll("button, a").forEach((el) => {
    if (el.children.length) return;
    const text = (el.textContent || "").trim();
    if (text && text.length < 60) el.textContent = translateListingLabel(text);
  });
}

async function hydrateAdvertisePricingPreview() {
  const wrap = document.getElementById("advertising-live-rate-card");
  if (!wrap) return;
  try {
    const res = await apiRequest("/api/advertising/placements");
    const rows = Array.isArray(res?.data) ? res.data : [];
    if (!rows.length) {
      wrap.innerHTML = `<div class="font-bold text-gray-800">Live placement menu</div><div class="text-xs text-gray-500 mt-1">Ask MakaUg for current placement availability and pricing.</div>`;
      return;
    }
    wrap.innerHTML = `
      <div class="font-bold text-gray-800">Live placement menu</div>
      <div class="grid sm:grid-cols-2 gap-2 mt-2">
        ${rows.slice(0, 8).map((slot) => `
          <div class="rounded-xl border border-white bg-white p-2">
            <div class="text-xs font-bold text-gray-900">${adminEscape(slot.label)}</div>
            <div class="text-[11px] text-gray-500">${adminEscape(slot.page_key)} • ${adminEscape(slot.size_label || slot.slot_type || "")}</div>
            <div class="text-xs font-black text-green-700 mt-1">From ${adminEscape(adMoney(slot.base_price_ugx))}</div>
          </div>
        `).join("")}
      </div>`;
  } catch (error) {
    wrap.innerHTML = `<div class="font-bold text-gray-800">Live placement menu</div><div class="text-xs text-gray-500 mt-1">Current prices can be confirmed by MakaUg after inquiry.</div>`;
  }
}

async function submitAdvertisingInquiry(event) {
  event.preventDefault();
  const form = event.currentTarget;
  const status = document.getElementById("advertising-inquiry-status");
  const data = new FormData(form);
  const products = data.getAll("product_interests").map((item) => String(item || "").trim()).filter(Boolean);
  if (!products.length) {
    toast("Choose at least one advertising option.");
    return;
  }
  const payload = {
    full_name: String(data.get("full_name") || "").trim(),
    business_name: String(data.get("business_name") || "").trim(),
    email: String(data.get("email") || "").trim(),
    phone: normalizePhoneInput(data.get("phone") || ""),
    preferred_contact_channel: String(data.get("preferred_contact_channel") || "whatsapp").trim(),
    product_interests: products,
    target_locations: String(data.get("target_locations") || "").trim(),
    target_listing_types: String(data.get("target_listing_types") || "").trim(),
    budget_ugx: String(data.get("budget_ugx") || "").trim(),
    desired_duration_days: String(data.get("desired_duration_days") || "").trim(),
    audience_segments: [
      `Reporting: ${String(data.get("reporting_cadence") || "weekly").trim()}`,
      data.get("wants_dashboard_access") ? "Paid dashboard access requested" : "No dashboard access requested"
    ],
    message: [
      String(data.get("message") || "").trim(),
      `Reporting cadence: ${String(data.get("reporting_cadence") || "weekly").trim()}`,
      data.get("wants_dashboard_access") ? "Advertiser wants paid real-time dashboard access." : "Advertiser does not need dashboard access yet."
    ].filter(Boolean).join("\n"),
    source: "website_advertise_with_us"
  };
  if (!payload.email && !payload.phone) {
    toast("Add an email or phone number so MakaUg can reply.");
    return;
  }
  try {
    const submit = form.querySelector("button[type='submit']");
    if (submit) {
      submit.disabled = true;
      submit.textContent = "Sending...";
    }
    const result = await apiRequest("/api/advertising/inquiries", {
      method: "POST",
      body: payload
    });
    if (status) {
      status.classList.remove("hidden");
      status.innerHTML = `Thanks. Your advertising inquiry was received.<br>Reference: <strong>${adminEscape(result?.data?.id || "-")}</strong><br>MakaUg will prepare the package, creative preview, and payment step.`;
    }
    form.reset();
    toast("Advertising inquiry sent.");
  } catch (e) {
    toast(`Advertising inquiry failed: ${e.message || "error"}`);
  } finally {
    const submit = form.querySelector("button[type='submit']");
    if (submit) {
      submit.disabled = false;
      submit.textContent = "Send advertising inquiry";
    }
  }
}

function addAdUnits() {
  const pages = document.querySelectorAll(".page");
  pages.forEach((page) => {
    if (page.querySelector(".ad-wrap")) return;
    const pageName = (page.id || "").replace("page-", "").replace(/-/g, " ").trim() || "page";
    const adSlot = String(GOOGLE_ADSENSE_SLOTS[page.id] || GOOGLE_ADSENSE_SLOTS.default || "").trim();
    const hasLiveAds = GOOGLE_ADSENSE_CLIENT && adSlot;
    const sponsoredLabel = translateListingLabel("Sponsored");
    const placementLabel = translateListingLabel("Sponsored MakaUg placement");
    const reachLabel = translateListingLabel("Reach active property seekers on");
    const bookSlotLabel = translateListingLabel("Book this slot");
    const wrap = document.createElement("div");
    wrap.className = "ad-wrap";
    wrap.innerHTML = `
      <div class="max-w-7xl mx-auto px-4 py-3">
        <div class="ad-unit">
          <span class="ad-tag"><i class="fas fa-bullhorn"></i> ${sponsoredLabel}</span>
          <span class="text-sm text-green-900 font-semibold">${placementLabel} • ${reachLabel} ${translateListingLabel(pageName)}</span>
          ${hasLiveAds
            ? `<div class="ad-slot" data-adsense-client="${GOOGLE_ADSENSE_CLIENT}" data-adsense-slot="${adSlot}" data-ads-loaded="0"></div>`
            : `<button type="button" onclick="openPageMod('advertise')" class="text-sm font-bold text-green-700 hover:underline">${bookSlotLabel}</button>`
          }
        </div>
      </div>`;

    if (page.children.length > 1) {
      page.insertBefore(wrap, page.children[1]);
    } else {
      page.appendChild(wrap);
    }
  });
  renderGoogleAdsSlots();
}

function renderGoogleAdsSlots() {
  if (!window.adsbygoogle) return;
  document.querySelectorAll(".ad-slot[data-adsense-client]").forEach((slot) => {
    if (slot.dataset.adsLoaded === "1") return;
    const client = slot.dataset.adsenseClient || "";
    const adSlot = slot.dataset.adsenseSlot || "";
    if (!client || !adSlot) return;
    slot.innerHTML = `<ins class="adsbygoogle" style="display:block" data-ad-client="${client}" data-ad-slot="${adSlot}" data-ad-format="auto" data-full-width-responsive="true"></ins>`;
    try {
      (window.adsbygoogle = window.adsbygoogle || []).push({});
      slot.dataset.adsLoaded = "1";
    } catch (error) {
      slot.dataset.adsLoaded = "0";
    }
  });
}

function initGoogleAds() {
  if (!GOOGLE_ADSENSE_CLIENT) return;
  const scriptId = "makaug-adsense-script";
  if (document.getElementById(scriptId)) {
    renderGoogleAdsSlots();
    return;
  }
  const script = document.createElement("script");
  script.id = scriptId;
  script.async = true;
  script.crossOrigin = "anonymous";
  script.src = `https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${encodeURIComponent(GOOGLE_ADSENSE_CLIENT)}`;
  script.onload = () => renderGoogleAdsSlots();
  document.head.appendChild(script);
}

