function improveLpDescription() {
  const descEl = document.getElementById("lp-description");
  if (!descEl) return;
  const existing = lpVal("lp-description");
  const type = getListType();
  const subtype = document.getElementById("lp-subtype")?.selectedOptions?.[0]?.textContent || "";
  const title = lpVal("lp-title");
  const district = lpVal("list-district-sel");
  const city = lpVal("lp-city");
  const area = lpVal("lp-area") || lpVal("lp-neighborhood");
  const priceText = lpNum("lp-price") ? fmtP(lpNum("lp-price"), lpVal("lp-period")) : "";
  const beds = lpVal("lp-beds");
  const baths = lpVal("lp-baths");
  const amenities = Array.from(document.querySelectorAll("#lp-amenities input:checked"))
    .map((el) => el.getAttribute("data-label") || el.value)
    .filter(Boolean);
  const extra = getLpExtraValues();
  const nearby = getNearbyAmenitySuggestions({
    lat: parseFloatSafe(lpVal("lp-lat")),
    lng: parseFloatSafe(lpVal("lp-lng")),
    district,
    city,
    area
  }).slice(0, 3).map((item) => item.name);

  const introBits = [title, subtype].filter(Boolean).join(" - ");
  const locationBits = [area, city, district].filter(Boolean).join(", ");
  const factBits = [];
  if (beds) factBits.push(`${beds} ${countLabel(beds, "bed", "beds")}`);
  if (baths) factBits.push(`${baths} ${countLabel(baths, "bath", "baths")}`);
  if (extra.year_built) factBits.push(`${translateListingLabel("Built in")} ${extra.year_built}`);
  if (extra.furnished) factBits.push(`${translateListingLabel("Furnishing")}: ${extra.furnished}`);
  if (extra.title_type) factBits.push(`${translateListingLabel("Title Type")}: ${extra.title_type}`);
  if (extra.contract_months) factBits.push(`${translateListingLabel("Minimum Contract")}: ${extra.contract_months} ${translateListingLabel("months")}`);
  if (extra.deposit) factBits.push(`${translateListingLabel("Deposit")}: ${fmtP(parseIntSafe(extra.deposit) || 0)}`);
  const amenitiesText = amenities.length ? amenities.slice(0, 6).join(", ") : translateListingLabel("standard amenities");
  const nearbyText = nearby.length ? nearby.join(", ") : translateListingLabel("key daily services");
  const areaSummary = (lpVal("lp-area-highlights-edit") || "").trim();
  const typePurpose = {
    sale: translateListingLabel("ideal for buyers looking for long-term value"),
    rent: translateListingLabel("well-suited for renters seeking convenience"),
    land: translateListingLabel("suitable for development or long-term investment"),
    commercial: translateListingLabel("positioned for business operations and growth"),
    student: translateListingLabel("tailored for students and guardians seeking safe accommodation")
  };

  const generated = [
    introBits || title || translateListingLabel("Property listing"),
    locationBits ? `${translateListingLabel("Located in")} ${locationBits}.` : "",
    factBits.length ? `${translateListingLabel("Key facts")}: ${factBits.join(", ")}.` : "",
    `${translateListingLabel("Features include")}: ${amenitiesText}.`,
    `${translateListingLabel("Nearby highlights include")}: ${nearbyText}.`,
    areaSummary ? `${translateListingLabel("Area summary")}: ${areaSummary}` : "",
    `${translateListingLabel("This listing is")} ${typePurpose[type] || translateListingLabel("well-positioned in its area")}.`,
    priceText ? `${translateListingLabel("Guide price")}: ${priceText}.` : "",
    existing && existing.length > 20 ? `${translateListingLabel("Owner notes")}: ${existing}` : ""
  ].filter(Boolean).join(" ");

  descEl.value = generated.replace(/\s+/g, " ").trim();
  updateListPreview();
  renderListReviewSummary();
  toast(translatePropertyUi("AI description written. You can still edit it before submitting."));
}

