function formatRadiusDistanceText(miles) {
  if (miles === 0.25) return "1/4";
  if (miles === 0.5) return "1/2";
  return Number.isInteger(miles) ? String(miles) : String(miles);
}

function radiusLabel(miles) {
  if (!miles) return tr("areaOnly");
  const unit = miles <= 1 ? tr("mileUnitSingular") : tr("mileUnitPlural");
  return `${tr("withinLabel")} ${formatRadiusDistanceText(miles)} ${unit}`;
}

function populateRadiusSelects() {
  const ids = [
    "hero-radius-f",
    "sale-radius-f",
    "rent-radius-f",
    "student-radius-f",
    "commercial-radius-f",
    "land-radius-f"
  ];
  ids.forEach((id) => {
    const el = document.getElementById(id);
    if (!el) return;
    const current = el.value || "0";
    el.innerHTML = SEARCH_RADIUS_MI_OPTIONS.map((miles) => `<option value="${miles}">${radiusLabel(miles)}</option>`).join("");
    if (Array.from(el.options).some((opt) => opt.value === current)) el.value = current;
    else el.value = "0";
  });
}

function setHeroRadiusState(type) {
  const radiusEl = document.getElementById("hero-radius-f");
  if (!radiusEl) return;
  const disabled = type === "students";
  if (disabled) radiusEl.value = "0";
  radiusEl.disabled = disabled;
  radiusEl.classList.toggle("opacity-70", disabled);
  radiusEl.classList.toggle("cursor-not-allowed", disabled);
}

function milesToKm(miles) {
  const value = parseFloat(miles || "0");
  if (!Number.isFinite(value) || value <= 0) return 0;
  return value * 1.60934;
}

function getRadiusKmFromSelect(selectId) {
  const miles = document.getElementById(selectId)?.value || "0";
  return milesToKm(miles);
}

function isPointInUgandaClient(lat, lng) {
  const nLat = Number(lat);
  const nLng = Number(lng);
  return Number.isFinite(nLat) && Number.isFinite(nLng)
    && nLat >= -1.7 && nLat <= 4.5
    && nLng >= 29.2 && nLng <= 35.2;
}

function roundSearchCoord(value) {
  const num = Number(value);
  return Number.isFinite(num) ? Number(num.toFixed(3)) : null;
}

function getNearMeSearchState(page) {
  return nearMeSearchState[page] || null;
}

function clearNearMeSearchState(page) {
  if (nearMeSearchState[page]) nearMeSearchState[page] = null;
}

function setHeroLocationStatus(message = "", state = "idle") {
  const button = document.getElementById("hero-location-control");
  const label = document.getElementById("hero-location-label");
  const helper = document.getElementById("hero-location-helper");
  const isActive = state === "active";
  if (button) {
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
    button.dataset.locationState = state;
  }
  if (label) label.textContent = tr("heroLocationLabel");
  if (helper) {
    helper.textContent = message || tr("heroLocationHelper");
    helper.classList.toggle("is-visible", state !== "idle");
  }
}

function heroOptionLabel(option) {
  if (!option) return "";
  return option.labelKey ? tr(option.labelKey) : option.label;
}

function setHeroSelectOptions(selectId, options = [], placeholderKey = "") {
  const el = document.getElementById(selectId);
  if (!el) return;
  const previous = el.value;
  el.innerHTML = options.map((option, index) => {
    const label = index === 0 && placeholderKey ? tr(placeholderKey) : heroOptionLabel(option);
    return `<option value="${adminEscape(option.value || "")}">${adminEscape(label || "")}</option>`;
  }).join("");
  if (Array.from(el.options).some((option) => option.value === previous)) {
    el.value = previous;
  }
}

