function getHeroFilterValues() {
  const config = heroCurrentFilterConfig();
  const minPrice = parseInt(document.getElementById("hero-min-price-f")?.value || "0", 10) || 0;
  const maxPrice = parseInt(document.getElementById("hero-max-price-f")?.value || "0", 10) || 0;
  const bedroomsRaw = config.showBedrooms ? (document.getElementById("hero-bedrooms-f")?.value || "") : "";
  const radiusMiles = parseFloat(document.getElementById("hero-radius-advanced-f")?.value || String(DEFAULT_NEAR_ME_RADIUS_MI)) || DEFAULT_NEAR_ME_RADIUS_MI;
  const propertyType = (document.getElementById("hero-property-type-f")?.value || "").trim();
  return {
    propertyType,
    minPrice,
    maxPrice,
    currency: activeCur || "UGX",
    bedrooms: bedroomsRaw,
    bathrooms: config.showBathrooms ? (parseInt(document.getElementById("hero-bathrooms-f")?.value || "0", 10) || 0) : 0,
    amenities: (document.getElementById("hero-amenities-f")?.value || "").trim(),
    commercialType: currentTab === "commercial" ? propertyType : "",
    landTitleType: currentTab === "land" ? propertyType : "",
    radiusMiles,
    radiusKm: milesToKm(radiusMiles),
    sort: document.getElementById("hero-sort-f")?.value || "newest"
  };
}

function heroListingMatchesFilters(property, filters = {}) {
  const searchText = getPropertySearchText(property);
  const propertyType = String(filters.propertyType || "").toLowerCase();
  const bedrooms = String(filters.bedrooms || "").toLowerCase();
  const amenities = String(filters.amenities || "").toLowerCase();
  if (propertyType && !((property.subtype || "").toLowerCase().includes(propertyType) || searchText.includes(propertyType))) return false;
  if (filters.minPrice && Number(property.price || 0) < filters.minPrice) return false;
  if (filters.maxPrice && Number(property.price || 0) > filters.maxPrice) return false;
  if (bedrooms === "studio" && !searchText.includes("studio") && Number(property.beds || property.bedrooms || 0) > 1) return false;
  if (bedrooms && bedrooms !== "studio") {
    const wantedBeds = parseInt(bedrooms, 10);
    if (Number.isFinite(wantedBeds) && wantedBeds > 0 && Number(property.beds || property.bedrooms || 0) < wantedBeds) return false;
  }
  if (filters.bathrooms && Number(property.baths || property.bathrooms || 0) < filters.bathrooms) return false;
  if (amenities && !searchText.includes(amenities)) return false;
  return true;
}

