function renderSaved() {
  const el = document.getElementById("saved-content");
  if (!el) return;
  if (!authState?.user) {
    el.innerHTML = `
      <div class="text-center py-10">
        <i class="far fa-user-circle text-4xl text-gray-300 mb-3"></i>
        <p class="text-gray-700 font-semibold">Create or sign in to your free account to save properties.</p>
        <p class="text-sm text-gray-500 mt-1">Saved properties then appear in your personal finder dashboard.</p>
        <div class="mt-5 flex flex-col sm:flex-row justify-center gap-2">
          <button onclick="openAuthSignUp('finder')" class="bg-green-700 text-white px-5 py-2 rounded-lg text-sm font-semibold">Create Free Account</button>
          <button onclick="openAuthSignIn('finder')" class="border border-green-700 text-green-700 px-5 py-2 rounded-lg text-sm font-semibold">Sign In</button>
        </div>
      </div>`;
    return;
  }
  const list = getPublicListings().filter((p) => isPropertySaved(p.id));
  if (!list.length) {
    el.innerHTML = `
      <div class="text-center py-10">
        <i class="far fa-heart text-4xl text-gray-300 mb-3"></i>
        <p class="text-gray-600 font-medium">No saved properties yet.</p>
        <button onclick="showPage('sale')" class="mt-4 bg-green-700 text-white px-5 py-2 rounded-lg text-sm font-semibold">Browse Properties</button>
      </div>`;
    return;
  }
  el.innerHTML = `<div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">${list.map(propCard).join("")}</div>`;
}

function renderAll() {
  const publicListings = getPublicListings();
  renderGrid("home-grid", getFeaturedListings(publicListings).slice(0, 3));
  renderGrid("sale-grid", publicListings.filter((p) => normalizeType(p.type) === "sale"));
  renderGrid("rent-grid", publicListings.filter((p) => normalizeType(p.type) === "rent"));
  const studentList = publicListings.filter((p) => isStudentDiscoverable(p));
  renderStudentGrid(studentList);
  updateStudentHeader(studentList);
  renderGrid("commercial-grid", publicListings.filter((p) => normalizeType(p.type) === "commercial"));
  renderGrid("land-grid", publicListings.filter((p) => normalizeType(p.type) === "land"));
  renderBrokers("home-brokers", getFeaturedBrokers(getBrokerDirectory()).slice(0, 3));
  renderBrokers("brokers-grid", getBrokerDirectory());
  const saleCountEl = document.getElementById("sale-count");
  if (saleCountEl) saleCountEl.textContent = publicListings.filter((p) => normalizeType(p.type) === "sale").length;
  const rentCountEl = document.getElementById("rent-count");
  if (rentCountEl) rentCountEl.textContent = publicListings.filter((p) => normalizeType(p.type) === "rent").length;
  renderSaved();
  renderFinderDashboard();
  renderStudentDashboard();
  renderAgentDashboard();
  renderFieldDashboard();
  renderAdvertiserDashboard();
  ensureRevenuePlacements();
}

const PAGE_ROUTE_MAP = Object.freeze({
  home: "/",
  sale: "/for-sale",
  rent: "/to-rent",
  students: "/student-accommodation",
  commercial: "/commercial",
  land: "/land",
  brokers: "/brokers",
  mortgage: "/mortgage",
  "ai-chatbot": "/discover-ai-chatbot",
  advertise: "/advertise",
  "how-it-works": "/how-it-works",
  careers: "/careers",
  help: "/help",
  safety: "/safety",
  fraud: "/anti-fraud",
  "privacy-policy": "/privacy-policy",
  "cookie-policy": "/cookie-policy",
  terms: "/terms",
  "list-property": "/list-property",
  about: "/about",
  saved: "/saved",
  account: "/account",
  "finder-dashboard": "/dashboard",
  "student-dashboard": "/student-dashboard",
  "agent-dashboard": "/broker-dashboard",
  "field-dashboard": "/field-agent-dashboard",
  "advertiser-dashboard": "/advertiser-dashboard",
  "admin-dashboard": "/admin",
  "admin-docs": "/admin/docs",
  "admin-setup-status": "/admin/setup-status"
});

const PUBLIC_ROUTE_PAGE_MAP = Object.freeze({
  "/": "home",
  "/for-sale": "sale",
  "/sale": "sale",
  "/to-rent": "rent",
  "/rent": "rent",
  "/students": "students",
  "/student-accommodation": "students",
  "/commercial": "commercial",
  "/land": "land",
  "/brokers": "brokers",
  "/find-brokers": "brokers",
  "/mortgage": "mortgage",
  "/mortgage-finder": "mortgage",
  "/discover-ai-chatbot": "ai-chatbot",
  "/ai-chatbot": "ai-chatbot",
  "/advertise": "advertise",
  "/how-it-works": "how-it-works",
  "/careers": "careers",
  "/help": "help",
  "/safety": "safety",
  "/fraud": "fraud",
  "/anti-fraud": "fraud",
  "/report-fraud": "fraud",
  "/privacy-policy": "privacy-policy",
  "/cookie-policy": "cookie-policy",
  "/terms": "terms",
  "/list-property": "list-property",
  "/about": "about",
  "/saved": "saved",
  "/account": "account"
});

function normalizePageKey(page) {
  const key = String(page || "").trim();
  return {
    "for-sale": "sale",
    "to-rent": "rent",
    "student-accommodation": "students",
    "anti-fraud": "fraud",
    "report-fraud": "fraud",
    "broker-dashboard": "agent-dashboard",
    "field-agent-dashboard": "field-dashboard"
  }[key] || key;
}

function normalizeRoutePath(path = "/") {
  const clean = String(path || "/").split("#")[0].split("?")[0].replace(/\/+$/, "");
  return clean || "/";
}

function routeForPage(page) {
  return PAGE_ROUTE_MAP[normalizePageKey(page)] || "";
}

function pageForPublicRoute(path) {
  return PUBLIC_ROUTE_PAGE_MAP[normalizeRoutePath(path)] || "";
}

function currentPathWithQueryAndHash() {
  return `${window.location.pathname || "/"}${window.location.search || ""}${window.location.hash || ""}`;
}

function updateRouteHistoryForPage(page, source = "show_page") {
  const route = routeForPage(page);
  if (!route || currentPathWithQueryAndHash() === route) return;
  try {
    window.history.pushState({ page, source }, "", route);
  } catch (error) {}
}

function closeRouteTransientModals(nextPage, previousPage) {
  if (!previousPage || nextPage === previousPage) return;
  const modalIds = [];
  if (nextPage !== "list-property") modalIds.push("list-choice-modal", "listing-submit-modal");
  if (nextPage !== "detail") modalIds.push("save-property-modal", "report-modal");
  if (nextPage !== "ai-chatbot") modalIds.push("howto-video-modal");
  modalIds.forEach((id) => {
    const el = document.getElementById(id);
    if (el?.classList.contains("open")) el.classList.remove("open");
  });
  if (modalIds.length) syncModalOpenState();
}

function showPage(page, options = {}) {
  const targetPage = normalizePageKey(page);
  const previousPage = currentPage;
  const el = document.getElementById("page-" + targetPage);
  if (el) {
    if (!el.classList.contains("active")) {
      document.querySelectorAll(".page.active").forEach((p) => {
        if (p !== el) p.classList.remove("active");
      });
      el.classList.add("active");
    }
    if (options.scroll !== false) window.scrollTo({ top: 0, left: 0, behavior: "auto" });
    lastPage = currentPage;
    currentPage = targetPage;
    closeRouteTransientModals(targetPage, previousPage);
    if (options.history !== false) updateRouteHistoryForPage(targetPage, options.source || "show_page");
  } else {
    const route = routeForPage(targetPage);
    if (route && window.location.pathname !== route) {
      navigatePublicRoute(route, null, { source: "show_page_fallback" });
      return;
    }
  }
  closeMobile();
  window.setTimeout(() => refreshActivePublicMapsAfterRoute(), 120);
  window.requestAnimationFrame(() => scheduleMapsInit({ force: targetPage !== previousPage }));
  if (targetPage && targetPage !== previousPage) {
    trackEvent("page_view", { page: targetPage });
  }
  if (targetPage === "finder-dashboard") renderFinderDashboard();
  if (targetPage === "student-dashboard") renderStudentDashboard();
  if (targetPage === "saved") renderSaved();
  if (targetPage === "agent-dashboard") renderAgentDashboard();
  if (targetPage === "field-dashboard") renderFieldDashboard();
  if (targetPage === "advertiser-dashboard") renderAdvertiserDashboard();
  if (targetPage === "admin-dashboard") renderAdminDashboard();
  if (targetPage === "admin-setup-status") renderAdminSetupStatus();
  if (targetPage === "list-property") {
    if (previousPage !== "list-property") {
      listWizardStep = 1;
      lpListingPathChoice = "";
      lpInquiryReference = "";
      lpMainPhotoIndex = 0;
      lpSelectedPhotos = [];
      lpPhotoUploadUrls = [];
      lpPhotoUploadSignature = "";
      lpPhotoAssignments = {};
      lpListingOtpToken = "";
      lpListingOtpVerifiedPhone = "";
      lpResolvedLocationLabel = "";
      lpLastHierarchySignature = "";
      lpLastAddressValue = "";
      lpAreaManualOverride = false;
      lpStreetManualOverride = false;
      lpAddressManualOverride = false;
      const success = document.getElementById("lp-success-box");
      if (success) success.classList.add("hidden");
      renderLpVideoPreview();
    }
    const routeType = getListPropertyRouteType();
    if (routeType) setListChoiceType(routeType);
    if (getListPropertyRouteMode() === "online") {
      chooseListPropertyOnline({ source: "route_query", skipModalClose: true });
    } else {
      setListChoiceType(getListChoiceType());
      setListPropertyFormVisible(false);
      maybeOpenListPropertyChoiceModal();
    }
  }
}

function mountPublicRouteFragment(doc, page) {
  const incoming = doc.getElementById(`page-${page}`);
  if (!incoming) return false;
  const imported = document.importNode(incoming, true);
  imported.classList.add("active");
  document.querySelectorAll(".page").forEach((el) => {
    if (el.id !== imported.id) el.remove();
  });
  const existing = document.getElementById(imported.id);
  if (existing) {
    existing.replaceWith(imported);
  } else {
    const footer = document.querySelector("footer");
    document.body.insertBefore(imported, footer || document.body.lastElementChild);
  }
  clearStaleMapRegistry();
  doc.querySelectorAll(".modal-overlay").forEach((modal) => {
    if (!modal.id || document.getElementById(modal.id)) return;
    document.body.appendChild(document.importNode(modal, true));
  });
  return true;
}

async function loadPublicRouteFragment(nextUrl, page, options = {}) {
  const source = options.source || "spa_fragment";
  document.documentElement.classList.add("route-loading");
  try {
    const response = await fetch(nextUrl, {
      method: "GET",
      headers: { Accept: "text/html", "X-MakaUg-Route-Fragment": "1" },
      credentials: "same-origin"
    });
    if (!response.ok) throw new Error(`Route fetch failed (${response.status})`);
    const html = await response.text();
    const doc = new DOMParser().parseFromString(html, "text/html");
    if (!mountPublicRouteFragment(doc, page)) throw new Error(`Route fragment missing page-${page}`);
    const url = new URL(nextUrl, window.location.origin);
    const nextPath = `${normalizeRoutePath(url.pathname)}${url.search || ""}${url.hash || ""}`;
    if (currentPathWithQueryAndHash() !== nextPath) {
      try { window.history.pushState({ page, source }, "", nextPath); } catch (error) {}
    }
    renderAll();
    renderHowToVideoSections();
    renderMortgageFinder();
    filterStudents();
    filterCommercial();
    filterLand();
    wireSearchTypeahead();
    setLang(currentLang, true, false);
    showPage(page, { history: false, source, scroll: options.scroll !== false });
    applyHeroSearchHandoff(page);
    return true;
  } catch (error) {
    console.warn("Falling back to full route navigation", error);
    window.location.href = nextUrl;
    return false;
  } finally {
    document.documentElement.classList.remove("route-loading");
  }
}

function navigatePublicRoute(target, event, options = {}) {
  if (event) event.preventDefault();
  let url;
  try {
    url = new URL(String(target || "/"), window.location.origin);
  } catch (error) {
    return true;
  }
  if (url.origin !== window.location.origin) return true;
  const path = normalizeRoutePath(url.pathname);
  if (path === "/login") {
    openAuthSignIn(url.searchParams.get("role") || url.searchParams.get("audience") || "finder");
    const nextUrl = `${path}${url.search || ""}${url.hash || ""}`;
    if (currentPathWithQueryAndHash() !== nextUrl) {
      try { window.history.pushState({ page: "auth", source: options.source || "spa_login" }, "", nextUrl); } catch (error) {}
    }
    return false;
  }
  if (["/signup", "/student-signup", "/broker-signup", "/field-agent-signup", "/advertiser-signup"].includes(path) || url.searchParams.get("auth") === "create") {
    const role = path.includes("student")
      ? "student"
      : (path.includes("broker")
        ? "agent"
        : (path.includes("field-agent")
          ? "field_agent"
          : (path.includes("advertiser") ? "advertiser" : (url.searchParams.get("role") || url.searchParams.get("audience") || "finder"))));
    openAuthSignUp(role);
    const nextUrl = `${path}${url.search || ""}${url.hash || ""}`;
    if (currentPathWithQueryAndHash() !== nextUrl) {
      try { window.history.pushState({ page: "auth-create", role, source: options.source || "spa_signup" }, "", nextUrl); } catch (error) {}
    }
    return false;
  }
  const page = pageForPublicRoute(path);
  if (!page) return true;
  const nextUrl = `${path}${url.search || ""}${url.hash || ""}`;
  if (!document.getElementById(`page-${page}`)) {
    loadPublicRouteFragment(nextUrl, page, options);
    return false;
  }
  if (currentPathWithQueryAndHash() !== nextUrl) {
    try { window.history.pushState({ page, source: options.source || "spa_link" }, "", nextUrl); } catch (error) {}
  }
  showPage(page, { history: false, source: options.source || "spa_link" });
  applyHeroSearchHandoff(page);
  return false;
}

let publicRouteInterceptorInstalled = false;
function installPublicRouteInterceptor() {
  if (publicRouteInterceptorInstalled) return;
  publicRouteInterceptorInstalled = true;
  document.addEventListener("click", (event) => {
    if (event.defaultPrevented || event.button !== 0 || event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
    const anchor = event.target?.closest?.("a[href]");
    if (!anchor || anchor.target || anchor.hasAttribute("download") || anchor.dataset.noSpa === "true") return;
    let url;
    try {
      url = new URL(anchor.getAttribute("href"), window.location.origin);
    } catch (error) {
      return;
    }
    if (url.origin !== window.location.origin) return;
    const handled = navigatePublicRoute(url, event, { source: "internal_link" });
    if (handled === false) {
      event.stopPropagation();
    }
  });
  window.addEventListener("popstate", () => {
    parseInitialDeepLink();
  });
}

function returnToLastPageFromDetail() {
  const target = lastPage || "home";
  showPage(target);
  const route = routeForPage(target) || "/";
  try {
    if (route && window.location.pathname !== route) {
      window.history.pushState({ page: target, source: "detail_back" }, "", route);
    }
  } catch (error) {}
  return false;
}

function mapRemotePropertyForUi(p, options = {}) {
  const images = Array.isArray(p?.images) ? p.images : [];
  const imageItems = images.map((item, index) => ({
    url: item.url || item,
    is_main: item.is_primary === true || index === 0,
    sort_order: item.sort_order ?? index,
    slot_key: item.slot_key || item.slot || "",
    slot: item.slot_key || item.slot || "",
    room_label: /^photo\s*\d+$/i.test(String(item.room_label || "").trim()) ? "" : (item.room_label || ""),
    location_label: [p.area, p.district].filter(Boolean).join(", ")
  })).filter((item) => item.url);
  const id = String(p?.id || "");
  return {
    ...p,
    id,
    backend_id: id,
    title: p?.title || "Untitled listing",
    type: normalizeType(p?.listing_type || p?.type),
    subtype: p?.property_type || p?.subtype || "Property",
    beds: p?.bedrooms,
    baths: p?.bathrooms,
    price: Number(p?.price || 0),
    period: p?.price_period || p?.period || "",
    img: p?.primary_image_url || p?.img || imageItems[0]?.url || "https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=900&q=80",
    desc: p?.description || p?.desc || "",
    address: p?.address || "",
    lat: Number(p?.latitude ?? p?.lat),
    lng: Number(p?.longitude ?? p?.lng),
    status: p?.status || "pending",
    sold_at: p?.sold_at || null,
    moderation_status: normalizeModerationStatus(p?.status),
    featured: p?.featured === true || String(p?.extra_fields?.featured || "").toLowerCase() === "true",
    featured_at: p?.featured_at || p?.extra_fields?.featured_at || null,
    registration_status: p?.registration_status || p?.agent_registration_status || p?.extra_fields?.lister_registration_status || "not_registered",
    lister_registration_status: p?.extra_fields?.lister_registration_status || p?.registration_status || "not_registered",
    inquiry_reference: p?.inquiry_reference || "",
    agent: p?.agent_id || p?.agent || null,
    lister_display_name: p?.lister_name || p?.contact_display_name || "",
    area_highlights: p?.extra_fields?.area_highlights || p?.area_highlights || "",
    translations: p?.extra_fields?.translations || p?.translations || {},
    city: p?.city || p?.extra_fields?.city || "",
    neighborhood: p?.neighborhood || p?.extra_fields?.neighborhood || "",
    region: p?.region || p?.extra_fields?.region || "",
    street_name: p?.street_name || p?.extra_fields?.street_name || "",
    preferred_contact_method: p?.preferred_contact_method || p?.extra_fields?.preferred_contact_method || "both",
    video_url: p?.video_url || p?.extra_fields?.video_url || p?.extra_fields?.youtube_url || "",
    youtube_url: p?.youtube_url || p?.extra_fields?.youtube_url || "",
    resolved_location_label: p?.resolved_location_label || p?.extra_fields?.resolved_location_label || "",
    nearby_places: Array.isArray(p?.extra_fields?.nearby_facilities) ? p.extra_fields.nearby_facilities : (Array.isArray(p?.nearby_places) ? p.nearby_places : []),
    images: imageItems,
    detail_loaded: options.detailLoaded === true || images.length > 0,
    owner_preview_visible: options.ownerPreview === true,
    owner_preview_token: options.token || ""
  };
}

function findPropertyForUi(id) {
  return PROPERTIES.find((p) => String(p.id) === String(id) || String(p.backend_id || "") === String(id));
}

function upsertPropertyForUi(property) {
  if (!property?.id) return null;
  const mapped = property.type ? property : mapRemotePropertyForUi(property);
  mapped.remote_source = mapped.remote_source || "api";
  const idx = PROPERTIES.findIndex((p) => String(p.id) === String(mapped.id) || String(p.backend_id || "") === String(mapped.id));
  if (idx >= 0) {
    const existing = PROPERTIES[idx];
    const next = { ...existing, ...mapped };
    if ((!Array.isArray(mapped.images) || mapped.images.length === 0) && Array.isArray(existing.images) && existing.images.length) {
      next.images = existing.images;
    }
    if (existing.detail_loaded === true && mapped.detail_loaded !== true) {
      next.detail_loaded = true;
    }
    if (existing.owner_preview_token && !mapped.owner_preview_token) {
      next.owner_preview_token = existing.owner_preview_token;
      next.owner_preview_visible = existing.owner_preview_visible;
    }
    PROPERTIES[idx] = next;
    return PROPERTIES[idx];
  } else {
    PROPERTIES.push(mapped);
  }
  return mapped;
}

async function loadRemotePropertyDetailForUi(id, options = {}) {
  const listingId = String(id || "").trim();
  if (!listingId) return null;
  const response = await apiRequest(`/api/properties/${encodeURIComponent(listingId)}`);
  const mapped = mapRemotePropertyForUi(response?.data || {}, { ...options, detailLoaded: true });
  mapped.remote_source = "api";
  return upsertPropertyForUi(mapped) || mapped;
}

async function hydratePropertyDetailForUi(property) {
  if (!property) return null;
  if (property.detail_loaded || property.owner_preview_visible === true) return property;
  const listingId = property.backend_id || property.id;
  if (!listingId || property.remote_source !== "api") return property;
  try {
    return await loadRemotePropertyDetailForUi(listingId);
  } catch (error) {
    console.warn("Unable to load full listing detail", error);
    return property;
  }
}

async function refreshPublicListingsFromApi({ silent = true } = {}) {
  if (publicListingsApiLoading) return false;
  publicListingsApiLoading = true;
  try {
  const response = await apiRequest("/api/properties?status=approved&limit=1000");
    const rows = Array.isArray(response?.data) ? response.data : [];
    const remoteIds = new Set(rows.map((p) => String(p.id || "")).filter(Boolean));
    for (let i = PROPERTIES.length - 1; i >= 0; i -= 1) {
      const p = PROPERTIES[i];
      const id = String(p?.backend_id || p?.id || "");
      if (p?.remote_source === "api" && id && !remoteIds.has(id)) {
        PROPERTIES.splice(i, 1);
      }
    }
    rows.forEach((p) => upsertPropertyForUi(p));
    publicListingsFromApiLoaded = true;
    return true;
  } catch (e) {
    if (!silent) toast(`Live listings refresh failed: ${e.message || "error"}`);
    return false;
  } finally {
    publicListingsApiLoading = false;
  }
}

async function openOwnerListingPreview(listingId, token) {
  if (!listingId || !token) return false;
  try {
    const response = await apiRequest(`/api/properties/${encodeURIComponent(listingId)}/preview?token=${encodeURIComponent(token)}`);
    const property = mapRemotePropertyForUi(response?.data || {}, { ownerPreview: true, token, detailLoaded: true });
    upsertPropertyForUi(property);
    openDetail(property.id);
    toast("Private listing preview loaded.");
    return true;
  } catch (e) {
    toast(e.message || "Unable to load listing preview.");
    return false;
  }
}

async function openOwnerPreviewEdit(id) {
  const property = PROPERTIES.find((p) => String(p.id) === String(id) || String(p.backend_id || "") === String(id));
  if (!property?.owner_preview_token || !property?.backend_id) {
    toast("Preview edit token is missing.");
    return;
  }
  const title = window.prompt("Edit listing title:", property.title || "");
  if (title == null) return;
  const description = window.prompt("Edit listing description:", property.desc || property.description || "");
  if (description == null) return;
  try {
    const response = await apiRequest(`/api/properties/${encodeURIComponent(property.backend_id)}/preview`, {
      method: "PATCH",
      body: {
        token: property.owner_preview_token,
        listing: { title, description }
      }
    });
    property.title = response?.data?.title || title;
    property.desc = response?.data?.description || description;
    property.description = property.desc;
    toast("Listing wording updated.");
    openDetail(property.id);
  } catch (e) {
    toast(e.message || "Unable to update listing.");
  }
}

async function parseInitialDeepLink() {
  const path = (window.location.pathname || "/").replace(/\/+$/, "") || "/";
  const qs = new URLSearchParams(window.location.search || "");

  const authIntent = String(qs.get("auth") || "").toLowerCase();
  if (path === "/login" || authIntent === "signin") {
    const role = qs.get("role") || qs.get("audience") || "finder";
    openAuthSignIn(role);
    return true;
  }
  if (path === "/signup" || path === "/student-signup" || path === "/broker-signup" || path === "/field-agent-signup" || path === "/advertiser-signup" || authIntent === "create") {
    const role = path.includes("student")
      ? "student"
      : (path.includes("broker")
        ? "agent"
        : (path.includes("field-agent")
          ? "field_agent"
          : (path.includes("advertiser") ? "advertiser" : (qs.get("role") || qs.get("audience") || "finder"))));
    openAuthSignUp(role);
    return true;
  }

  const propertyFromPath = path.match(/^\/property\/([^/?#]+)/i)?.[1];
  const agentFromPath = path.match(/^\/agents?\/([^/?#]+)/i)?.[1];
  const propertyFromQuery = qs.get("property") || qs.get("listing");
  const brokerFromQuery = qs.get("broker") || qs.get("agent");
  const previewToken = qs.get("token") || qs.get("edit_token");

  if (qs.get("listing_preview") && propertyFromQuery && previewToken) {
    await openOwnerListingPreview(propertyFromQuery, previewToken);
    return true;
  }

  if (propertyFromPath || propertyFromQuery) {
    const pid = decodeURIComponent(propertyFromPath || propertyFromQuery || "");
    const found = getPublicListings().find((p) => String(p.id) === String(pid) || String(p.backend_id || "") === String(pid));
    if (found) {
      await openDetail(found.id);
      return true;
    }
    try {
      const loaded = await loadRemotePropertyDetailForUi(pid);
      if (loaded && isListingPublicVisible(loaded)) {
        await openDetail(loaded.id);
        return true;
      }
    } catch (error) {
      console.warn("Unable to open linked property", error);
    }
    if (publicListingsApiLoading || !publicListingsFromApiLoaded) {
      const loaded = await refreshPublicListingsFromApi({ silent: true });
      const retry = loaded
        ? getPublicListings().find((p) => String(p.id) === String(pid) || String(p.backend_id || "") === String(pid))
        : null;
      if (retry) {
        await openDetail(retry.id);
        return true;
      }
    }
  }

  if (path === "/property" && !propertyFromQuery) {
    const latest = getPublicListings().sort(sortListingsByNewest)[0];
    if (latest) {
      await openDetail(latest.id);
      return true;
    }
  }

  if (agentFromPath || brokerFromQuery) {
    const bid = agentFromPath || brokerFromQuery;
    const found = findBrokerById(bid);
    if (found) {
      showPage("brokers", { history: false, source: "deep_link" });
      openBrokerProfile(found.id);
      return true;
    }
  }

  if (path === "/admin/setup-status") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "admin") {
      showPage("admin-setup-status", { history: false, source: "deep_link" });
      renderAdminSetupStatus();
    } else {
      openAuthSignIn("admin");
    }
    return true;
  }

  if (path === "/admin/docs") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "admin") {
      showPage("admin-docs", { history: false, source: "deep_link" });
    } else {
      openAuthSignIn("admin");
    }
    return true;
  }

  if (path === "/admin" || path === "/admin-dashboard" || path.startsWith("/admin/")) {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "admin") {
      showPage("admin-dashboard", { history: false, source: "deep_link" });
      renderAdminDashboard();
    } else {
      openAuthSignIn("admin");
    }
    return true;
  }

  if (path === "/advertiser-dashboard") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "advertiser") {
      showPage("advertiser-dashboard", { history: false, source: "deep_link" });
      renderAdvertiserDashboard();
    } else {
      openAuthSignIn("advertiser");
    }
    return true;
  }

  if (path === "/dashboard") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "finder") {
      showPage("finder-dashboard", { history: false, source: "deep_link" });
      renderFinderDashboard();
    } else {
      openAuthSignIn("finder");
    }
    return true;
  }

  if (path === "/student-dashboard") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "student") {
      showPage("student-dashboard", { history: false, source: "deep_link" });
      renderStudentDashboard();
    } else {
      openAuthSignIn("student");
    }
    return true;
  }

  if (path === "/broker-dashboard") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "agent") {
      showPage("agent-dashboard", { history: false, source: "deep_link" });
      renderAgentDashboard();
    } else {
      openAuthSignIn("agent");
    }
    return true;
  }

  if (path === "/field-agent-dashboard") {
    if (authState?.user && derivePortalMode(authState.user, authState.user.portal_mode) === "field_agent") {
      showPage("field-dashboard", { history: false, source: "deep_link" });
      renderFieldDashboard();
    } else {
      openAuthSignIn("field_agent");
    }
    return true;
  }

  const publicRoutePage = pageForPublicRoute(path);
  if (publicRoutePage) {
    if (!document.getElementById(`page-${publicRoutePage}`)) {
      await loadPublicRouteFragment(`${path}${window.location.search || ""}${window.location.hash || ""}`, publicRoutePage, {
        source: "popstate_missing_fragment",
        scroll: false
      });
      return true;
    }
    showPage(publicRoutePage, { history: false, source: "deep_link" });
    applyHeroSearchHandoff(publicRoutePage);
    return true;
  }

  return false;
}

function setTab(el, type) {
  const group = el.parentElement;
  group.querySelectorAll(".tab-btn").forEach((b) => b.classList.remove("active"));
  el.classList.add("active");
  currentTab = type;
  setHeroLocationFilter(type);
  setHeroRadiusState(type);
  setHeroContextFilter(type);
  applyHeroSearchLanguageUI();
  setHeroLocationStatus(getNearMeSearchState(type) ? tr("heroLocationActive") : tr("heroLocationHelper"), getNearMeSearchState(type) ? "active" : "idle");
  closeHeroSuggestions();
  const heroInput = document.getElementById("hero-q");
  if (heroInput && document.activeElement === heroInput && heroInput.value.trim()) {
    renderTypeahead(heroInput, getLocationSuggestionPool(currentTab === "students"), () => {});
  }
}

function buildHeroSearchBackendPayload({ query = "", area = "", filters = {}, nearState = null, resultsCount = 0 } = {}) {
  const payload = {
    query,
    category: currentTab,
    source: nearState ? "homepage_location_control" : "homepage_search",
    language: currentLang || "en",
    session: getAnalyticsClientId(),
    resultsCount
  };
  if (currentTab === "students") {
    payload.student_portal = "true";
  } else {
    payload.listing_type = currentTab;
  }
  if (area) payload.area = area;
  if (filters.propertyType) payload.propertyType = filters.propertyType;
  if (filters.propertyType) payload.property_type = filters.propertyType;
  if (filters.minPrice) payload.minPrice = filters.minPrice;
  if (filters.minPrice) payload.min_price = filters.minPrice;
  if (filters.maxPrice) payload.maxPrice = filters.maxPrice;
  if (filters.maxPrice) payload.max_price = filters.maxPrice;
  if (filters.currency) payload.currency = filters.currency;
  if (filters.bedrooms) payload.bedrooms = filters.bedrooms;
  if (filters.bathrooms) payload.bathrooms = filters.bathrooms;
  if (filters.amenities) payload.amenities = filters.amenities;
  if (filters.commercialType) payload.commercialType = filters.commercialType;
  if (filters.commercialType) payload.commercial_type = filters.commercialType;
  if (filters.landTitleType) payload.landTitleType = filters.landTitleType;
  if (filters.landTitleType) payload.land_title_type = filters.landTitleType;
  if (filters.sort) payload.sort = filters.sort;
  if (nearState) {
    payload.lat = nearState.lat;
    payload.lng = nearState.lng;
    payload.radiusMiles = nearState.radiusMiles || filters.radiusMiles || DEFAULT_NEAR_ME_RADIUS_MI;
    payload.radiusKm = nearState.radiusKm || filters.radiusKm || milesToKm(payload.radiusMiles);
    payload.radiusUnit = "miles";
    payload.locationSource = "browser_geolocation";
  }
  return payload;
}

function recordHeroSearchBackendPayload(payload = {}) {
  const params = new URLSearchParams();
  Object.entries(payload).forEach(([key, value]) => {
    if (value === undefined || value === null || value === "") return;
    if (key === "resultsCount" || key === "category") return;
    params.set(key, String(value));
  });
  params.set("limit", "12");
  const endpoint = `${API_BASE}/api/properties/search?${params.toString()}`;
  fetch(endpoint, { credentials: "same-origin" })
    .then((res) => res.json().catch(() => ({})).then((body) => ({ ok: res.ok, body })))
    .then(({ ok, body }) => {
      trackEvent("homepage_search_backend_checked", {
        category: payload.category,
        source: payload.source,
        radius_miles: payload.radiusMiles || null,
        backend_ok: ok,
        backend_results: Array.isArray(body?.data) ? body.data.length : null,
        outside_uganda: Boolean(body?.data?.outside_uganda || body?.error?.includes?.("outside Uganda"))
      });
    })
    .catch((error) => {
      trackEvent("homepage_search_backend_check_failed", {
        category: payload.category,
        source: payload.source,
        error: error?.message || "network_error"
      });
    });
}

function doSearch() {
  const qRaw = document.getElementById("hero-q").value || "";
  const q = qRaw.toLowerCase().trim();
  const areaOrUniRaw = document.getElementById("hero-district").value || "";
  const areaOrUni = currentTab === "students"
    ? (areaOrUniRaw || (document.getElementById("hero-q").value || ""))
    : (areaOrUniRaw || guessDistrictFromText(document.getElementById("hero-q").value || ""));
  const uniValue = areaOrUni.toLowerCase().trim();
  const heroRadiusValue = document.getElementById("hero-radius-f")?.value || "0";
  const heroRadiusKm = getRadiusKmFromSelect("hero-radius-f");
  const heroFilters = getHeroFilterValues();
  const pageMap = { sale: "sale", rent: "rent", students: "students", commercial: "commercial", land: "land" };
  const heroNearState = getNearMeSearchState(currentTab);
  const routedRadiusValue = heroNearState
    ? String(heroNearState.radiusMiles || DEFAULT_NEAR_ME_RADIUS_MI)
    : heroRadiusValue;
  let results = getPublicListings().filter((p) => {
    const typeMatch = currentTab === "students" ? isStudentDiscoverable(p) : normalizeType(p.type) === currentTab;
    const districtMatch = heroNearState
      ? propertyMatchesNearMe(p, heroNearState, heroRadiusKm || heroNearState.radiusKm)
      : currentTab === "students"
        ? (!uniValue
          || (p.nearest_university || "").toLowerCase().includes(uniValue)
          || (p.student_universities || []).join(" ").toLowerCase().includes(uniValue)
          || (p.area || "").toLowerCase().includes(uniValue))
        : matchDistrictRadius(p, areaOrUni, heroRadiusKm);
    const qMatch = !q || getPropertySearchText(p).includes(q);
    const filterMatch = heroListingMatchesFilters(p, heroFilters);
    return typeMatch && districtMatch && qMatch && filterMatch;
  });
  results = decorateAndSortNearMeResults(results, heroNearState);
  incrementUserSearchCount();
  const destinationPage = pageMap[currentTab] || "sale";
  const backendPayload = buildHeroSearchBackendPayload({
    query: qRaw.trim(),
    area: areaOrUni || "",
    filters: heroFilters,
    nearState: heroNearState,
    resultsCount: results.length
  });
  recordHeroSearchBackendPayload(backendPayload);
  saveHeroSearchHandoff(destinationPage, {
    query: qRaw || "",
    area: areaOrUni || "",
    radius: routedRadiusValue,
    radiusMiles: heroNearState?.radiusMiles || (parseFloat(heroRadiusValue || "0") || null),
    filters: heroFilters,
    nearState: heroNearState ? {
      lat: heroNearState.lat,
      lng: heroNearState.lng,
      radiusMiles: heroNearState.radiusMiles,
      radiusKm: heroNearState.radiusKm,
      district: heroNearState.district || "",
      label: heroNearState.label || ""
    } : null
  });
  showPage(destinationPage);
  if (currentTab === "rent") {
    const rq = document.getElementById("rent-location-f");
    const rd = document.getElementById("rent-district-f");
    const rr = document.getElementById("rent-radius-f");
    const rb = document.getElementById("rent-min-beds-f");
    const rMax = document.getElementById("rent-price-f");
    const rMin = document.getElementById("rent-min-price-f");
    const rType = document.getElementById("rent-type-f");
    if (rq) rq.value = document.getElementById("hero-q").value || "";
    if (rd) rd.value = areaOrUni;
    if (rr) rr.value = routedRadiusValue;
    if (rb) rb.value = /^\d+$/.test(heroFilters.bedrooms) ? heroFilters.bedrooms : "";
    if (rMin) rMin.value = heroFilters.minPrice ? String(heroFilters.minPrice) : "";
    if (rMax) rMax.value = heroFilters.maxPrice ? String(heroFilters.maxPrice) : "";
    if (rType) rType.value = heroFilters.bedrooms === "studio" ? "studio" : heroFilters.propertyType;
    filterListings("rent");
  } else if (currentTab === "students") {
    const sq = document.getElementById("student-q-f");
    const su = document.getElementById("student-uni-f");
    const sr = document.getElementById("student-radius-f");
    const stQuick = document.getElementById("student-type-quick-f");
    const sbudget = document.getElementById("student-budget-f");
    if (sq) sq.value = document.getElementById("hero-q").value || "";
    if (su) su.value = areaOrUni;
    if (sr) sr.value = routedRadiusValue;
    if (stQuick) stQuick.value = heroFilters.propertyType === "hostel" || heroFilters.propertyType === "room" || heroFilters.propertyType === "studio" || heroFilters.propertyType === "apartment" ? heroFilters.propertyType : "";
    if (sbudget) sbudget.value = heroFilters.maxPrice ? String(heroFilters.maxPrice) : "";
    filterStudents();
  } else if (currentTab === "commercial") {
    const cq = document.getElementById("commercial-q-f");
    const cd = document.getElementById("commercial-district-f");
    const cr = document.getElementById("commercial-radius-f");
    const ct = document.getElementById("commercial-type-f");
    const cMin = document.getElementById("commercial-min-price-f");
    const cMax = document.getElementById("commercial-price-f");
    const commercialTypeMap = { office: "Office", retail: "Retail", warehouse: "Warehouse", shop: "Shop" };
    if (cq) cq.value = document.getElementById("hero-q").value || "";
    if (cd) cd.value = areaOrUni;
    if (cr) cr.value = routedRadiusValue;
    if (ct) ct.value = commercialTypeMap[heroFilters.propertyType] || (heroFilters.propertyType === "commercial space" ? "" : "");
    if (cMin) cMin.value = heroFilters.minPrice ? String(heroFilters.minPrice) : "";
    if (cMax) cMax.value = heroFilters.maxPrice ? String(heroFilters.maxPrice) : "";
    filterCommercial();
  } else if (currentTab === "land") {
    const lq = document.getElementById("land-q-f");
    const ld = document.getElementById("land-district-f");
    const lr = document.getElementById("land-radius-f");
    const lt = document.getElementById("land-type-f");
    const lMin = document.getElementById("land-min-price-f");
    const lMax = document.getElementById("land-price-f");
    const landTypeMap = { residential: "Residential", commercial: "Commercial", agricultural: "Agricultural" };
    if (lq) lq.value = document.getElementById("hero-q").value || "";
    if (ld) ld.value = areaOrUni;
    if (lr) lr.value = routedRadiusValue;
    if (lt) lt.value = landTypeMap[heroFilters.propertyType] || "";
    if (lMin) lMin.value = heroFilters.minPrice ? String(heroFilters.minPrice) : "";
    if (lMax) lMax.value = heroFilters.maxPrice ? String(heroFilters.maxPrice) : "";
    filterLand();
  } else {
    const sq = document.getElementById("sale-location-f");
    const sd = document.getElementById("sale-district-f");
    const sr = document.getElementById("sale-radius-f");
    const sb = document.getElementById("sale-min-beds-f");
    const sMin = document.getElementById("sale-min-price-f");
    const sMax = document.getElementById("sale-price-f");
    const sType = document.getElementById("sale-type-f");
    if (sq) sq.value = document.getElementById("hero-q").value || "";
    if (sd) sd.value = areaOrUni;
    if (sr) sr.value = routedRadiusValue;
    if (sb) sb.value = /^\d+$/.test(heroFilters.bedrooms) ? heroFilters.bedrooms : "";
    if (sMin) sMin.value = heroFilters.minPrice ? String(heroFilters.minPrice) : "";
    if (sMax) sMax.value = heroFilters.maxPrice ? String(heroFilters.maxPrice) : "";
    if (sType) sType.value = heroFilters.bedrooms === "studio" ? "studio" : heroFilters.propertyType;
    filterListings("sale");
  }
  toast(`Found ${results.length} properties`);
  trackEvent("property_search", {
    listing_type: currentTab,
    query: q || "",
    district_or_university: areaOrUni || "",
    filters: heroFilters,
    results_count: results.length,
    radius_miles: heroNearState?.radiusMiles || null,
    radius_unit: heroNearState ? "miles" : null,
    search_source: heroNearState ? "homepage_location_control" : "homepage_search",
    near_me: Boolean(heroNearState)
  });
}

function quickSearch(area) {
  document.getElementById("hero-q").value = area;
  doSearch();
}

function filterListings(page) {
  let list = getPublicListings().filter((p) => normalizeType(p.type) === page);
  if (page === "sale") {
    const q = (document.getElementById("sale-location-f")?.value || "").toLowerCase().trim();
    const dRaw = document.getElementById("sale-district-f")?.value || "";
    const d = dRaw || guessDistrictFromText(q);
    const radiusKm = getRadiusKmFromSelect("sale-radius-f");
    const nearState = getNearMeSearchState("sale");
    const minBeds = parseInt(document.getElementById("sale-min-beds-f")?.value || "0", 10);
    const maxBeds = parseInt(document.getElementById("sale-beds-f")?.value || "0", 10);
    const min = parseInt(document.getElementById("sale-min-price-f")?.value || "0", 10);
    const max = parseInt(document.getElementById("sale-price-f")?.value || "0", 10);
    const type = (document.getElementById("sale-type-f")?.value || "").toLowerCase().trim();
    list = list.filter((p) => {
      const text = getPropertySearchText(p);
      const qMatch = !q || text.includes(q);
      const dMatch = nearState ? propertyMatchesNearMe(p, nearState, radiusKm || nearState.radiusKm) : matchDistrictRadius(p, d, radiusKm);
      const minBedsMatch = !minBeds || (p.beds || 0) >= minBeds;
      const maxBedsMatch = !maxBeds || (p.beds || 0) <= maxBeds;
      const minMatch = !min || p.price >= min;
      const maxMatch = !max || p.price <= max;
      const typeMatch = !type || ((p.subtype || "").toLowerCase().includes(type) || text.includes(type));
      return qMatch && dMatch && minBedsMatch && maxBedsMatch && minMatch && maxMatch && typeMatch;
    });
    list = decorateAndSortNearMeResults(list, nearState);
    const saleCountEl = document.getElementById("sale-count");
    if (saleCountEl) saleCountEl.textContent = list.length;
    renderGrid("sale-grid", list);
    setMapMarkers("map-sale", list);
  } else if (page === "rent") {
    const q = (document.getElementById("rent-location-f")?.value || "").toLowerCase().trim();
    const dRaw = document.getElementById("rent-district-f")?.value || "";
    const d = dRaw || guessDistrictFromText(q);
    const radiusKm = getRadiusKmFromSelect("rent-radius-f");
    const nearState = getNearMeSearchState("rent");
    const minBeds = parseInt(document.getElementById("rent-min-beds-f")?.value || "0", 10);
    const maxBeds = parseInt(document.getElementById("rent-beds-f")?.value || "0", 10);
    const min = parseInt(document.getElementById("rent-min-price-f")?.value || "0", 10);
    const max = parseInt(document.getElementById("rent-price-f")?.value || "0", 10);
    const type = (document.getElementById("rent-type-f")?.value || "").toLowerCase().trim();
    const sort = document.getElementById("rent-sort-f")?.value || "newest";
    list = list.filter((p) => {
      const text = getPropertySearchText(p);
      const qMatch = !q || text.includes(q);
      const dMatch = nearState ? propertyMatchesNearMe(p, nearState, radiusKm || nearState.radiusKm) : matchDistrictRadius(p, d, radiusKm);
      const minBedsMatch = !minBeds || (p.beds || 0) >= minBeds;
      const maxBedsMatch = !maxBeds || (p.beds || 0) <= maxBeds;
      const minMatch = !min || p.price >= min;
      const maxMatch = !max || p.price <= max;
      const typeMatch = !type || ((p.subtype || "").toLowerCase().includes(type) || text.includes(type));
      return qMatch && dMatch && minBedsMatch && maxBedsMatch && minMatch && maxMatch && typeMatch;
    });
    if (sort === "price_asc") list.sort((a, b) => a.price - b.price);
    if (sort === "price_desc") list.sort((a, b) => b.price - a.price);
    if (sort === "newest") list.sort(sortListingsByNewest);
    if (nearState) list = decorateAndSortNearMeResults(list, nearState);
    const rentCountEl = document.getElementById("rent-count");
    if (rentCountEl) rentCountEl.textContent = list.length;
    renderGrid("rent-grid", list);
    setMapMarkers("map-rent", list);
  }
}

function filterStudents() {
  const q = (document.getElementById("student-q-f")?.value || "").toLowerCase().trim();
  const dRaw = document.getElementById("student-district-f")?.value || "";
  const d = dRaw || guessDistrictFromText(q);
  const radiusKm = getRadiusKmFromSelect("student-radius-f");
  const nearState = getNearMeSearchState("students");
  const uni = (document.getElementById("student-uni-f")?.value || "").toLowerCase().trim();
  const type = (document.getElementById("student-type-quick-f")?.value || "").toLowerCase().trim();
  const amenity = (document.getElementById("student-amenity-f")?.value || "").toLowerCase().trim();
  const category = (document.getElementById("student-category-f")?.value || "").toLowerCase().trim();
  const verifiedOnly = document.getElementById("student-verified-f")?.value === "1";
  const sort = document.getElementById("student-sort-f")?.value || "newest";
  const max = parseInt(document.getElementById("student-budget-f")?.value || "0", 10);
  let list = getPublicListings().filter((p) => isStudentDiscoverable(p));
  list = list.filter((p) => {
    const text = getPropertySearchText(p);
    const pType = studentTypeKey(p);
    const nearCampus = typeof p.distance_to_uni_km === "number" ? p.distance_to_uni_km <= 2 : false;
    const uniMatchText = (p.nearest_university || "").toLowerCase() + " " + (p.student_universities || []).join(" ").toLowerCase();
    const amenityMatchText = (p.amenities || []).join(" ").toLowerCase();
    const typeMatch = !type || pType === type;
    const qMatch = !q || text.includes(q);
    const dMatch = nearState ? propertyMatchesNearMe(p, nearState, radiusKm || nearState.radiusKm) : matchDistrictRadius(p, d, radiusKm);
    const uMatch = !uni || uniMatchText.includes(uni);
    const aMatch = !amenity || amenityMatchText.includes(amenity);
    const cMatch = !category
      || (category === "hostel" && pType === "hostel")
      || (category === "apartment" && (pType === "apartment" || pType === "studio"))
      || (category === "shared" && pType === "shared")
      || (category === "near" && nearCampus);
    const vMatch = !verifiedOnly || !!p.student_verified || !!p.students_welcome;
    const maxMatch = !max || p.price <= max;
    return typeMatch && qMatch && dMatch && uMatch && aMatch && cMatch && vMatch && maxMatch;
  });
  if (sort === "price_asc") list.sort((a, b) => a.price - b.price);
  if (sort === "price_desc") list.sort((a, b) => b.price - a.price);
  if (sort === "distance_asc") list.sort((a, b) => (a.distance_to_uni_km || 999) - (b.distance_to_uni_km || 999));
  if (sort === "newest") list.sort(sortListingsByNewest);
  if (nearState) list = decorateAndSortNearMeResults(list, nearState);
  renderStudentGrid(list);
  updateStudentHeader(list);
  setMapMarkers("map-students", list);
  return list;
}

function setStudentCategory(category, btn) {
  const categoryInput = document.getElementById("student-category-f");
  if (categoryInput) categoryInput.value = category || "";
  document.querySelectorAll("[data-student-cat]").forEach((chip) => {
    const val = chip.getAttribute("data-student-cat") || "";
    const active = val === (category || "");
    if (active) {
      chip.classList.add("bg-white", "text-green-900");
      chip.classList.remove("bg-white/10", "hover:bg-white/20", "text-white");
    } else {
      chip.classList.remove("bg-white", "text-green-900");
      chip.classList.add("bg-white/10", "hover:bg-white/20", "text-white");
    }
  });
  filterStudents();
}

function quickStudentUni(name) {
  const uniSel = document.getElementById("student-uni-f");
  if (uniSel) uniSel.value = name;
  const qEl = document.getElementById("student-q-f");
  if (qEl && !qEl.value.trim()) qEl.value = name;
  filterStudents();
}

function syncStudentType(value) {
  const quickSel = document.getElementById("student-type-quick-f");
  if (quickSel) quickSel.value = value || "";
  filterStudents();
}

function toggleStudentVerified() {
  const input = document.getElementById("student-verified-f");
  const btn = document.getElementById("student-verified-btn");
  if (!input || !btn) return;
  const next = input.value === "1" ? "0" : "1";
  input.value = next;
  if (next === "1") {
    btn.className = "h-10 px-4 rounded-lg bg-white text-purple-900 text-sm font-semibold border border-white/30";
  } else {
    btn.className = "h-10 px-4 rounded-lg bg-purple-950/40 text-white text-sm font-semibold border border-white/25";
  }
  filterStudents();
}

function numericValue(v) {
  const match = String(v || "").match(/[\d.]+/);
  return match ? parseFloat(match[0]) : 0;
}

