const DISTRICT_TO_REGION = (() => {
  const map = {};
  Object.entries(UG_REGION_DISTRICTS).forEach(([region, districts]) => {
    districts.forEach((district) => { map[district] = region; });
  });
  DISTRICTS.forEach((district) => {
    if (!map[district]) {
      map[district] = "Central";
    }
  });
  return map;
})();

