function getListType() {
  return document.querySelector("input[name='lp-type']:checked")?.value || "sale";
}

function setSelectOptions(id, options, fallbackValue, localize = true) {
  const el = document.getElementById(id);
  if (!el) return;
  const prev = el.value;
  const normalized = options.map((opt) => (typeof opt === "string" ? { value: opt, label: opt } : opt));
  el.innerHTML = normalized.map((opt) => {
    const label = localize ? translateListingLabel(opt.label) : opt.label;
    return `<option value="${opt.value}">${label}</option>`;
  }).join("");
  if (normalized.some((opt) => opt.value === prev)) el.value = prev;
  else if (fallbackValue !== undefined && normalized.some((opt) => opt.value === fallbackValue)) el.value = fallbackValue;
  else if (normalized.length) el.value = normalized[0].value;
}

function renderLpExtraFields(type, preserveExisting = true) {
  const cfg = LP_CONFIG[type] || LP_CONFIG.sale;
  const wrap = document.getElementById("lp-extra-fields");
  if (!wrap) return;
  if (!cfg.extras || !cfg.extras.length) {
    wrap.innerHTML = "";
    return;
  }
  const prevValues = {};
  if (preserveExisting) {
    wrap.querySelectorAll("input, select").forEach((el) => {
      prevValues[el.id] = el.value;
    });
  }

  wrap.innerHTML = cfg.extras.map((field) => {
    const id = `lp-extra-${field.key}`;
    const dependsAttr = field.dependsOn ? ` data-depends-on="${field.dependsOn}" data-depends-values="${(field.dependsValues || []).join(",")}"` : "";
    const infoHtml = field.info === "title_types"
      ? `<details class="mt-1 text-xs text-gray-500"><summary class="cursor-pointer text-green-700 font-semibold">${translateListingLabel("What do Freehold, Leasehold, Mailo & Customary mean?")}</summary><div class="mt-2 space-y-1"><p><strong>${translateListingLabel("Freehold")}:</strong> ${translateListingLabel("Full ownership of land/building with no expiry date.")}</p><p><strong>${translateListingLabel("Leasehold")}:</strong> ${translateListingLabel("Right to use land/building for a fixed term (e.g. 49/99 years).")}</p><p><strong>${translateListingLabel("Mailo")}:</strong> ${translateListingLabel("Registered ownership tenure common in central Uganda, sometimes with occupants on kibanja.")}</p><p><strong>${translateListingLabel("Customary")}:</strong> ${translateListingLabel("Community/family-held land under customary rules, often requires formalization for transfer.")}</p></div></details>`
      : "";
    if (field.type === "select") {
      const normalized = (field.options || []).map((opt) => (typeof opt === "string" ? { value: opt, label: opt } : opt));
      const opts = normalized.map((opt) => `<option value="${opt.value}">${translateListingLabel(opt.label)}</option>`).join("");
      const onChange = field.key === "commercial_mode"
        ? `syncCommercialMode(this.value); updateLpDependentFields(); updateListPreview(); renderListReviewSummary();`
        : `updateLpDependentFields(); updateListPreview(); renderListReviewSummary();`;
      return `<div${dependsAttr}><label class="block text-sm font-semibold text-gray-700 mb-1.5">${translateListingLabel(field.label)}</label><select id="${id}" onchange="${onChange}" class="w-full border border-green-100 rounded-xl px-4 py-3 text-sm bg-white">${opts}</select>${infoHtml}</div>`;
    }
    const inputType = field.type === "number" ? "number" : "text";
    return `<div${dependsAttr}><label class="block text-sm font-semibold text-gray-700 mb-1.5">${translateListingLabel(field.label)}</label><input id="${id}" type="${inputType}" oninput="updateLpDependentFields(); updateListPreview(); renderListReviewSummary();" class="w-full border border-green-100 rounded-xl px-4 py-3 text-sm" placeholder="${translateListingLabel(field.placeholder || "")}">${infoHtml}</div>`;
  }).join("");

  if (preserveExisting) {
    Object.entries(prevValues).forEach(([id, value]) => {
      const el = document.getElementById(id);
      if (el) el.value = value;
    });
  }
  updateLpDependentFields();
  applyPremiumFormLabels();
}

function updateLpDependentFields() {
  const extraValues = getLpExtraValues();
  document.querySelectorAll("#lp-extra-fields [data-depends-on]").forEach((row) => {
    const dep = row.getAttribute("data-depends-on");
    const vals = (row.getAttribute("data-depends-values") || "").split(",").map((x) => x.trim()).filter(Boolean);
    const depValue = (extraValues[dep] || "").trim();
    const show = !vals.length || vals.includes(depValue);
    row.classList.toggle("hidden", !show);
  });
}

function syncCommercialMode(mode) {
  if (getListType() !== "commercial") return;
  const modeSel = document.getElementById("lp-extra-commercial_mode");
  const currentMode = mode || modeSel?.value || "sale";
  if (modeSel) modeSel.value = currentMode;

  const periodLabelEl = document.getElementById("lp-period-label");
	      if (currentMode === "rent") {
	        if (periodLabelEl) periodLabelEl.textContent = translateListingLabel("Rent Period");
    setSelectOptions("lp-period", [
      { value: "mo", label: "Per Month" },
      { value: "yr", label: "Per Year" },
      { value: "wk", label: "Per Week" }
    ], "mo");
  } else {
    if (periodLabelEl) periodLabelEl.textContent = translateListingLabel("Sale Price Model");
    setSelectOptions("lp-period", [
      { value: "once", label: "Total / Sale Price" },
      { value: "neg", label: "Negotiable" }
    ], "once");
	      }
	      const availableFromWrap = document.getElementById("lp-available-from-wrap");
	      if (availableFromWrap) availableFromWrap.classList.toggle("hidden", currentMode !== "rent");

	      updateLpDependentFields();
	    }

function renderLpAmenities(type, preserveExisting = true) {
  const cfg = LP_CONFIG[type] || LP_CONFIG.sale;
  const wrap = document.getElementById("lp-amenities");
  if (!wrap) return;
  const prev = preserveExisting
    ? new Set(Array.from(wrap.querySelectorAll("input:checked")).map((el) => el.value))
    : new Set();
  wrap.innerHTML = (cfg.amenities || []).map((amenity) => {
    const checked = prev.has(amenity.value) ? "checked" : "";
    const label = translateListingLabel(amenity.label);
    return `<label class="inline-flex items-center gap-1.5"><input type="checkbox" value="${amenity.value}" data-label="${label}" class="accent-green-700" onchange="updateListPreview(); renderListReviewSummary();" ${checked}> ${label}</label>`;
  }).join("");
}

function updateListTypeChips(type) {
  const base = "lp-type-chip inline-flex items-center gap-2 border rounded-xl px-4 py-2.5 text-sm text-gray-700 cursor-pointer transition-colors";
  document.querySelectorAll("[data-lp-type-chip]").forEach((chip) => {
    const val = chip.getAttribute("data-lp-type-chip");
    chip.className = val === type ? `${base} lp-type-active` : base;
  });
}

