function applyBrokerFilters() {
  const text = (document.getElementById("broker-q-f")?.value || "").toLowerCase().trim();
  const district = (document.getElementById("broker-district-f")?.value || "").toLowerCase().trim();
  const specialty = (document.getElementById("broker-specialty-f")?.value || "").toLowerCase().trim();
  const language = (document.getElementById("broker-language-f")?.value || "").toLowerCase().trim();
  const status = (document.getElementById("broker-status-f")?.value || "").toLowerCase().trim();
  const list = getBrokerDirectory().filter((b) => {
    const haystack = [
      b.name,
      b.company,
      b.area,
      b.licence,
      (b.specialties || []).join(" "),
      (b.languages || []).join(" ")
    ].join(" ").toLowerCase();
    const districtMatch = !district || b.area.toLowerCase().includes(district);
    const specialtyMatch = !specialty || (b.specialties || []).some((s) => s.toLowerCase() === specialty);
    const languageMatch = !language || (b.languages || []).some((l) => l.toLowerCase() === language);
    const statusMatch = !status || String(b.registration_status || "").toLowerCase() === status;
    const textMatch = !text || haystack.includes(text);
    return districtMatch && specialtyMatch && languageMatch && statusMatch && textMatch;
  });
  renderBrokers("brokers-grid", list);
}

function filterBrokers(q) {
  const input = document.getElementById("broker-q-f");
  if (input && typeof q === "string" && input.value !== q) input.value = q;
  applyBrokerFilters();
}

function filterBrokerDistrict(district) {
  const districtEl = document.getElementById("broker-district-f");
  if (districtEl && typeof district === "string" && districtEl.value !== district) districtEl.value = district;
  applyBrokerFilters();
}

function getBrokerMapPoint(broker) {
  if (!broker) return null;
  const brokerListings = getPublicListings()
    .filter((p) => String(p.agent || "") === String(broker.id || ""))
    .map((p) => ({ property: p, point: getListingMapPoint(p) }))
    .filter((entry) => Number.isFinite(entry.point?.lat) && Number.isFinite(entry.point?.lng));
  if (brokerListings.length) {
    const totals = brokerListings.reduce((acc, entry) => {
      acc.lat += entry.point.lat;
      acc.lng += entry.point.lng;
      return acc;
    }, { lat: 0, lng: 0 });
    return {
      lat: totals.lat / brokerListings.length,
      lng: totals.lng / brokerListings.length,
      listingsCount: brokerListings.length
    };
  }

  const areaText = String(broker.area || "").toLowerCase();
  const matchedDistricts = DISTRICTS.filter((district) => areaText.includes(district.toLowerCase()));
  const centers = matchedDistricts.map((district) => getDistrictCenter(district)).filter(Boolean);
  if (centers.length) {
    const avg = centers.reduce((acc, c) => {
      acc.lat += c.lat;
      acc.lng += c.lng;
      return acc;
    }, { lat: 0, lng: 0 });
    return {
      lat: avg.lat / centers.length,
      lng: avg.lng / centers.length,
      listingsCount: 0
    };
  }

  return { ...MAP_DEFAULT_CENTER, listingsCount: 0 };
}

function ensureGoogleMapsApi() {
  if (!GOOGLE_MAPS_API_KEY) return Promise.resolve(false);
  if (window.google?.maps) return Promise.resolve(true);
  if (googleMapsLoadPromise) return googleMapsLoadPromise;

  googleMapsLoadPromise = new Promise((resolve) => {
    const scriptId = "makaug-google-maps-script";
    const existing = document.getElementById(scriptId);
    if (existing) {
      existing.addEventListener("load", () => resolve(!!window.google?.maps), { once: true });
      existing.addEventListener("error", () => resolve(false), { once: true });
      return;
    }
    const script = document.createElement("script");
    script.id = scriptId;
    script.async = true;
    script.defer = true;
    script.src = `https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(GOOGLE_MAPS_API_KEY)}&libraries=places`;
    script.onload = () => resolve(!!window.google?.maps);
    script.onerror = () => resolve(false);
    document.head.appendChild(script);
  });

  return googleMapsLoadPromise;
}

function ensureLeafletApi() {
  if (window.L) return Promise.resolve(true);
  if (leafletLoadPromise) return leafletLoadPromise;

  leafletLoadPromise = new Promise((resolve) => {
    if (!document.querySelector('link[data-makaug-leaflet-css="true"]')) {
      const link = document.createElement("link");
      link.rel = "stylesheet";
      link.href = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";
      link.setAttribute("data-makaug-leaflet-css", "true");
      document.head.appendChild(link);
    }

    const existing = document.getElementById("makaug-leaflet-script");
    if (existing) {
      existing.addEventListener("load", () => resolve(!!window.L), { once: true });
      existing.addEventListener("error", () => resolve(false), { once: true });
      return;
    }

    const script = document.createElement("script");
    script.id = "makaug-leaflet-script";
    script.async = true;
    script.src = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.js";
    script.onload = () => resolve(!!window.L);
    script.onerror = () => resolve(false);
    document.head.appendChild(script);
  });

  return leafletLoadPromise;
}

function getActivePublicMapIds() {
  const activePage = document.querySelector(".page.active");
  if (!activePage) return [];
  return PUBLIC_MAP_IDS.filter((id) => activePage.querySelector(`#${id}`));
}

function mapInstanceMatchesDom(mapId) {
  const el = document.getElementById(mapId);
  const map = maps[mapId];
  if (!el || !map) return false;
  const provider = mapProviders[mapId] || "leaflet";
  if (provider === "google" && typeof map.getDiv === "function") return map.getDiv() === el;
  if (provider === "leaflet" && map._container) return map._container === el;
  return true;
}

function destroyMapInstance(mapId) {
  const provider = mapProviders[mapId];
  const map = maps[mapId];
  try { clearMapMarkers(mapId); } catch (e) {}
  if (provider === "leaflet" && map?.remove) {
    try { map.remove(); } catch (e) {}
  }
  const el = document.getElementById(mapId);
  if (el) {
    if (provider === "leaflet" && el._leaflet_id) {
      try { el._leaflet_id = null; } catch (e) {}
    }
    if (provider === "google" || provider === "leaflet") {
      try { el.innerHTML = ""; } catch (e) {}
    }
  }
  delete maps[mapId];
  delete markers[mapId];
  delete mapProviders[mapId];
}

function clearStaleMapRegistry() {
  PUBLIC_MAP_IDS.forEach((mapId) => {
    if (!maps[mapId]) return;
    if (!document.getElementById(mapId) || !mapInstanceMatchesDom(mapId)) destroyMapInstance(mapId);
  });
}

function publicMapNeedsInit(mapId) {
  const el = document.getElementById(mapId);
  return !!el && (!maps[mapId] || !mapInstanceMatchesDom(mapId));
}

function activePublicMapsNeedInit() {
  clearStaleMapRegistry();
  return getActivePublicMapIds().some((id) => publicMapNeedsInit(id));
}

function resizePublicMap(mapId, delay = 80) {
  const map = maps[mapId];
  if (!map) return;
  window.setTimeout(() => {
    try {
      if (mapProviders[mapId] === "google" && window.google?.maps) {
        google.maps.event.trigger(map, "resize");
      } else if (map.invalidateSize) {
        map.invalidateSize();
      }
    } catch (e) {}
  }, delay);
}

function refreshActivePublicMapsAfterRoute() {
  clearStaleMapRegistry();
  const activeMapIds = getActivePublicMapIds();
  if (!activeMapIds.length) return;
  if (activeMapIds.some((id) => publicMapNeedsInit(id))) {
    scheduleMapsInit({ force: true });
    return;
  }
  activeMapIds.forEach((id) => {
    resizePublicMap(id, 40);
    resizePublicMap(id, 240);
  });
  resetMaps();
}

function clearMapMarkers(mapId) {
  const provider = mapProviders[mapId] || "leaflet";
  (markers[mapId] || []).forEach((marker) => {
    try {
      if (provider === "google" && marker?.setMap) marker.setMap(null);
      else if (maps[mapId]?.removeLayer) maps[mapId].removeLayer(marker);
    } catch (e) {}
  });
  markers[mapId] = [];
}

function addGoogleMarkers(mapId, list) {
  const map = maps[mapId];
  if (!map || !window.google?.maps) return;
  const infoWindow = new google.maps.InfoWindow();
  (list || []).forEach((p) => {
    const point = getListingMapPoint(p);
    if (!Number.isFinite(point?.lat) || !Number.isFinite(point?.lng) || !isLikelyUgandaCoordinate(point.lat, point.lng)) return;
    const marker = new google.maps.Marker({
      position: { lat: point.lat, lng: point.lng },
      map,
      title: p.title || "MakaUg listing"
    });
    const content = buildMapListingPopupHtml(p);
    marker.addListener("mouseover", () => {
      infoWindow.setContent(content);
      infoWindow.open(map, marker);
    });
    marker.addListener("click", () => {
      infoWindow.setContent(content);
      infoWindow.open(map, marker);
    });
    markers[mapId].push(marker);
  });
}

function wireLeafletMarkerClick(marker, kind = "listing") {
  if (!marker) return;
  marker.on("mouseover", () => marker.openPopup());
  marker.on("click", () => marker.openPopup());
  marker.on("add", () => {
    const el = marker.getElement && marker.getElement();
    if (!el) return;
    el.setAttribute("data-map-marker", kind);
    el.setAttribute("aria-label", kind === "broker" ? "Open broker map result" : "Open property map result");
    el.addEventListener("click", () => marker.openPopup());
  });
  window.setTimeout(() => {
    const el = marker.getElement && marker.getElement();
    if (!el || el.dataset.makaugMarkerWired === "1") return;
    el.dataset.makaugMarkerWired = "1";
    el.setAttribute("data-map-marker", kind);
    el.setAttribute("aria-label", kind === "broker" ? "Open broker map result" : "Open property map result");
    el.addEventListener("click", () => marker.openPopup());
  }, 0);
}

function setBrokerMapMarkers(list) {
  const mapId = "map-brokers";
  const map = maps[mapId];
  if (!map) return;

  clearMapMarkers(mapId);

  const points = (list || [])
    .map((broker) => ({ broker, point: getBrokerMapPoint(broker) }))
    .filter((item) => item.point && Number.isFinite(item.point.lat) && Number.isFinite(item.point.lng));

  if (mapProviders[mapId] === "google" && window.google?.maps) {
    const infoWindow = new google.maps.InfoWindow();
    points.forEach(({ broker, point }) => {
      const brokerIdArg = adminListingIdArg(broker.id);
      const brokerPath = getBrokerProfilePath(broker);
      const marker = new google.maps.Marker({
        position: { lat: point.lat, lng: point.lng },
        map,
        title: broker.name || "MakaUg broker"
      });
      const openBrokerInfo = () => {
        infoWindow.setContent(`
          <div data-map-marker-popup="broker" style="min-width:210px">
            <div style="font-weight:700;color:#111827;margin-bottom:2px">${adminEscape(broker.name || "Broker")}</div>
            <div style="font-size:12px;color:#6b7280;margin-bottom:8px">${adminEscape(broker.company || "")}</div>
            <div style="font-size:12px;color:#374151;margin-bottom:8px">Location: ${adminEscape(broker.area || "")}</div>
            <a href="${adminAttr(brokerPath)}" data-map-broker-link="1" data-broker-id="${adminAttr(broker.id)}" onclick="return openMapBrokerProfile(event, ${brokerIdArg});" style="display:block;width:100%;box-sizing:border-box;background:#166534;color:#fff;border:none;border-radius:8px;padding:7px 10px;font-size:12px;font-weight:700;cursor:pointer;text-align:center;text-decoration:none;">
              View Broker
            </a>
          </div>
        `);
        infoWindow.open(map, marker);
      };
      marker.addListener("mouseover", openBrokerInfo);
      marker.addListener("click", openBrokerInfo);
      markers[mapId].push(marker);
    });
    if (!points.length) {
      map.setCenter({ lat: 1.3733, lng: 32.2903 });
      map.setZoom(MAP_BROKER_DEFAULT_ZOOM);
    } else if ((list || []).length >= 3) {
      map.setCenter({ lat: 1.3733, lng: 32.2903 });
      map.setZoom(MAP_BROKER_DEFAULT_ZOOM);
    } else if (points.length === 1) {
      map.setCenter({ lat: points[0].point.lat, lng: points[0].point.lng });
      map.setZoom(MAP_DISTRICT_ZOOM);
    } else {
      const bounds = new google.maps.LatLngBounds();
      points.forEach((item) => bounds.extend({ lat: item.point.lat, lng: item.point.lng }));
      map.fitBounds(bounds);
      google.maps.event.addListenerOnce(map, "idle", () => {
        if (map.getZoom() > MAP_CITY_ZOOM) map.setZoom(MAP_CITY_ZOOM);
      });
    }
    return;
  }

  if (!window.L) return;

  points.forEach(({ broker, point }) => {
    const brokerIdArg = adminListingIdArg(broker.id);
    const brokerPath = getBrokerProfilePath(broker);
    const marker = L.marker([point.lat, point.lng]).addTo(map);

    marker.bindPopup(`
      <div data-map-marker-popup="broker" style="min-width:210px">
        <div style="font-weight:700;color:#111827;margin-bottom:2px">${broker.name}</div>
        <div style="font-size:12px;color:#6b7280;margin-bottom:8px">${broker.company}</div>
        <div style="font-size:12px;color:#374151;margin-bottom:8px">📍 ${broker.area}</div>
        <div style="display:flex;justify-content:space-between;gap:8px;font-size:12px;margin-bottom:8px">
          <span style="font-weight:600;color:#166534">⭐ ${broker.rating}</span>
          <span style="color:#4b5563">${broker.listings} listings</span>
        </div>
        <a href="${adminAttr(brokerPath)}" data-map-broker-link="1" data-broker-id="${adminAttr(broker.id)}" onclick="return openMapBrokerProfile(event, ${brokerIdArg});" style="display:block;width:100%;box-sizing:border-box;background:#166534;color:#fff;border:none;border-radius:8px;padding:7px 10px;font-size:12px;font-weight:700;cursor:pointer;text-align:center;text-decoration:none;">
          View Broker
        </a>
      </div>
    `);

    wireLeafletMarkerClick(marker, "broker");
    markers[mapId].push(marker);
  });

  if (!points.length) {
    map.setView([1.3733, 32.2903], MAP_BROKER_DEFAULT_ZOOM);
    return;
  }

  if ((list || []).length >= 3) {
    map.setView([1.3733, 32.2903], MAP_BROKER_DEFAULT_ZOOM);
    return;
  }

  if (points.length === 1) {
    const one = points[0].point;
    map.setView([one.lat, one.lng], MAP_DISTRICT_ZOOM);
    return;
  }

  const bounds = L.latLngBounds(points.map((item) => [item.point.lat, item.point.lng]));
  map.fitBounds(bounds.pad(0.25), { maxZoom: MAP_CITY_ZOOM });
  if (map.getZoom() < 6) map.setZoom(6);
}

async function initMaps() {
  const mapSpecs = [
    { id: "map-home", filter: () => getPublicListings() },
    { id: "map-sale", filter: () => getPublicListings().filter((p) => normalizeType(p.type) === "sale") },
    { id: "map-rent", filter: () => getPublicListings().filter((p) => normalizeType(p.type) === "rent") },
    { id: "map-students", filter: () => getPublicListings().filter((p) => isStudentDiscoverable(p)) },
    { id: "map-commercial", filter: () => getPublicListings().filter((p) => normalizeType(p.type) === "commercial") },
    { id: "map-land", filter: () => getPublicListings().filter((p) => normalizeType(p.type) === "land") }
  ];

  const useGoogle = await ensureGoogleMapsApi();
  if (useGoogle && window.google?.maps) {
    mapSpecs.forEach((spec) => {
      const el = document.getElementById(spec.id);
      if (!el) return;
      const initialList = spec.filter();
      if (maps[spec.id] && mapProviders[spec.id] === "google" && mapInstanceMatchesDom(spec.id)) {
        setMapMarkers(spec.id, initialList);
        resizePublicMap(spec.id, 80);
        return;
      }
      if (maps[spec.id]) destroyMapInstance(spec.id);
      el.innerHTML = "";
      const map = new google.maps.Map(el, {
        center: MAP_DEFAULT_CENTER,
        zoom: MAP_DEFAULT_ZOOM,
        mapTypeControl: true,
        streetViewControl: true,
        fullscreenControl: true
      });
      maps[spec.id] = map;
      mapProviders[spec.id] = "google";
      markers[spec.id] = [];
      addMarkers(spec.id, initialList);
      fitMapToListings(spec.id, initialList);
      resizePublicMap(spec.id, 80);
    });

    const brokerMapEl = document.getElementById("map-brokers");
    if (brokerMapEl) {
      if (maps["map-brokers"] && mapProviders["map-brokers"] === "google" && mapInstanceMatchesDom("map-brokers")) {
        setBrokerMapMarkers(getBrokerDirectory());
        resizePublicMap("map-brokers", 80);
        return;
      }
      if (maps["map-brokers"]) destroyMapInstance("map-brokers");
      brokerMapEl.innerHTML = "";
      const brokerMap = new google.maps.Map(brokerMapEl, {
        center: { lat: 1.3733, lng: 32.2903 },
        zoom: MAP_BROKER_DEFAULT_ZOOM,
        mapTypeControl: true,
        streetViewControl: true,
        fullscreenControl: true
      });
      maps["map-brokers"] = brokerMap;
      mapProviders["map-brokers"] = "google";
      markers["map-brokers"] = [];
      setBrokerMapMarkers(getBrokerDirectory());
      resizePublicMap("map-brokers", 80);
    }
    return;
  }

  if (!(await ensureLeafletApi())) return;
  mapSpecs.forEach((spec) => {
    const el = document.getElementById(spec.id);
    if (!el) return;
    const initialList = spec.filter();
    if (maps[spec.id] && mapProviders[spec.id] === "leaflet" && mapInstanceMatchesDom(spec.id)) {
      setMapMarkers(spec.id, initialList);
      resizePublicMap(spec.id, 80);
      return;
    }
    if (maps[spec.id]) destroyMapInstance(spec.id);
    if (el._leaflet_id) {
      try { el._leaflet_id = null; } catch (e) {}
    }
    el.innerHTML = "";
    const map = L.map(spec.id).setView([MAP_DEFAULT_CENTER.lat, MAP_DEFAULT_CENTER.lng], MAP_DEFAULT_ZOOM);
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      attribution: "&copy; OpenStreetMap contributors",
      maxZoom: 18
    }).addTo(map);
    maps[spec.id] = map;
    mapProviders[spec.id] = "leaflet";
    markers[spec.id] = [];
    addMarkers(spec.id, initialList);
    fitMapToListings(spec.id, initialList);
    resizePublicMap(spec.id, 80);
  });

  const brokerMapEl = document.getElementById("map-brokers");
  if (brokerMapEl) {
    if (maps["map-brokers"] && mapProviders["map-brokers"] === "leaflet" && mapInstanceMatchesDom("map-brokers")) {
      setBrokerMapMarkers(getBrokerDirectory());
      resizePublicMap("map-brokers", 80);
      return;
    }
    if (maps["map-brokers"]) destroyMapInstance("map-brokers");
    if (brokerMapEl._leaflet_id) {
      try { brokerMapEl._leaflet_id = null; } catch (e) {}
    }
    brokerMapEl.innerHTML = "";
    const brokerMap = L.map("map-brokers").setView([1.3733, 32.2903], MAP_BROKER_DEFAULT_ZOOM);
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      attribution: "&copy; OpenStreetMap contributors",
      maxZoom: 18
    }).addTo(brokerMap);
    maps["map-brokers"] = brokerMap;
    mapProviders["map-brokers"] = "leaflet";
    markers["map-brokers"] = [];
    setBrokerMapMarkers(getBrokerDirectory());
    resizePublicMap("map-brokers", 80);
  }
}

let mapsInitScheduled = false;
let mapsInitStarted = false;
let mapsInitPromise = null;

function scheduleMapsInit(options = {}) {
  const activePage = document.querySelector(".page.active");
  const hasActiveMap = !!activePage?.querySelector(PUBLIC_MAP_SELECTOR);
  if (!hasActiveMap) return;
  const needsInit = Boolean(options.force) || activePublicMapsNeedInit();
  if (mapsInitStarted && !needsInit) {
    refreshActivePublicMapsAfterRoute();
    return;
  }
  if (mapsInitScheduled && !options.force) return;
  mapsInitScheduled = true;
  const onHomeOnly = activePage?.id === "page-home";
  const delay = hasActiveMap && !onHomeOnly ? 300 : 2500;
  const start = () => {
    mapsInitScheduled = false;
    if (mapsInitPromise) return;
    mapsInitStarted = true;
    mapsInitPromise = initMaps()
      .then(() => {
        getActivePublicMapIds().forEach((id) => {
          resizePublicMap(id, 80);
          resizePublicMap(id, 300);
        });
        resetMaps();
      })
      .catch((error) => console.warn("Map initialization skipped", error))
      .finally(() => {
        mapsInitPromise = null;
      });
  };
  if (onHomeOnly) {
    window.setTimeout(start, delay);
  } else if ("requestIdleCallback" in window) {
    window.requestIdleCallback(start, { timeout: Math.max(delay, 1200) });
  } else {
    window.setTimeout(start, delay);
  }
}

function addMarkers(mapId, list) {
  if (!maps[mapId]) return;
  if (mapProviders[mapId] === "google") {
    addGoogleMarkers(mapId, list);
    return;
  }
  if (!window.L) return;
  list.forEach((p) => {
    const point = getListingMapPoint(p);
    if (!Number.isFinite(point?.lat) || !Number.isFinite(point?.lng) || !isLikelyUgandaCoordinate(point.lat, point.lng)) return;
    const marker = L.marker([point.lat, point.lng]).addTo(maps[mapId]);
    marker.bindPopup(buildMapListingPopupHtml(p));
    wireLeafletMarkerClick(marker, "listing");
    markers[mapId].push(marker);
  });
}

function fitMapToListings(mapId, list) {
  const map = maps[mapId];
  if (!map) return;
  const homeOverviewCenter = getHomeMapOverviewCenter();
  const points = (list || [])
    .map((p) => getListingMapPoint(p))
    .filter((point) => Number.isFinite(point?.lat) && Number.isFinite(point?.lng) && isLikelyUgandaCoordinate(point.lat, point.lng))
    .map((point) => ({ lat: point.lat, lng: point.lng }));

  if (mapProviders[mapId] === "google" && window.google?.maps) {
    if (!points.length) {
      map.setCenter(mapId === "map-home" ? homeOverviewCenter : MAP_DEFAULT_CENTER);
      map.setZoom(mapId === "map-home" ? MAP_HOME_MIN_ZOOM : MAP_DEFAULT_ZOOM);
      return;
    }
    if (points.length === 1) {
      map.setCenter(points[0]);
      map.setZoom(MAP_NEIGHBORHOOD_ZOOM);
      return;
    }
    const bounds = new google.maps.LatLngBounds();
    points.forEach((point) => bounds.extend(point));
    map.fitBounds(bounds);
    google.maps.event.addListenerOnce(map, "idle", () => {
      const maxZoom = mapId === "map-home" ? MAP_HOME_MAX_ZOOM : MAP_MULTI_LISTING_MAX_ZOOM;
      const minZoom = mapId === "map-home" ? MAP_HOME_MIN_ZOOM : 0;
      if (map.getZoom() > maxZoom) map.setZoom(maxZoom);
      if (map.getZoom() < minZoom) map.setZoom(minZoom);
    });
    return;
  }

  if (!window.L) return;
  if (!points.length) {
    const fallbackCenter = mapId === "map-home" ? homeOverviewCenter : MAP_DEFAULT_CENTER;
    map.setView([fallbackCenter.lat, fallbackCenter.lng], mapId === "map-home" ? MAP_HOME_MIN_ZOOM : MAP_DEFAULT_ZOOM);
    return;
  }
  if (points.length === 1) {
    map.setView([points[0].lat, points[0].lng], MAP_NEIGHBORHOOD_ZOOM);
    return;
  }
  const bounds = L.latLngBounds(points.map((point) => [point.lat, point.lng]));
  const maxZoom = mapId === "map-home" ? MAP_HOME_MAX_ZOOM : MAP_MULTI_LISTING_MAX_ZOOM;
  map.fitBounds(bounds.pad(mapId === "map-home" ? 0.08 : 0.2), { maxZoom });
  if (mapId === "map-home" && map.getZoom() < MAP_HOME_MIN_ZOOM) {
    map.setZoom(MAP_HOME_MIN_ZOOM);
  }
}

function setMapMarkers(mapId, list) {
  if (!maps[mapId]) return;
  clearMapMarkers(mapId);
  addMarkers(mapId, list || []);
  fitMapToListings(mapId, list || []);
}

function resetMaps() {
  const publicListings = getPublicListings();
  setMapMarkers("map-home", publicListings);
  setMapMarkers("map-sale", publicListings.filter((p) => normalizeType(p.type) === "sale"));
  setMapMarkers("map-rent", publicListings.filter((p) => normalizeType(p.type) === "rent"));
  setMapMarkers("map-students", publicListings.filter((p) => isStudentDiscoverable(p)));
  setMapMarkers("map-commercial", publicListings.filter((p) => normalizeType(p.type) === "commercial"));
  setMapMarkers("map-land", publicListings.filter((p) => normalizeType(p.type) === "land"));
  setBrokerMapMarkers(getBrokerDirectory());
}

async function initDetailMap(p) {
  const el = document.getElementById("map-detail");
  if (!el) return;
  const useGoogle = await ensureGoogleMapsApi();
  const rawLat = Number(p?.lat ?? p?.latitude);
  const rawLng = Number(p?.lng ?? p?.longitude);
  const lat = Number.isFinite(rawLat) ? rawLat : MAP_DEFAULT_CENTER.lat;
  const lng = Number.isFinite(rawLng) ? rawLng : MAP_DEFAULT_CENTER.lng;
  if (useGoogle && window.google?.maps) {
    el.innerHTML = "";
    const map = new google.maps.Map(el, {
      center: { lat, lng },
      zoom: MAP_PROPERTY_ZOOM,
      mapTypeId: "hybrid",
      mapTypeControl: true,
      streetViewControl: true,
      fullscreenControl: true
    });
    const marker = new google.maps.Marker({
      position: { lat, lng },
      map,
      title: p.title || "MakaUg listing"
    });
    const info = new google.maps.InfoWindow({ content: `<strong>${adminEscape(p.title || "Property")}</strong>` });
    info.open(map, marker);
    marker.addListener("mouseover", () => info.open(map, marker));
    marker.addListener("click", () => info.open(map, marker));
    return;
  }
  if (!(await ensureLeafletApi())) return;
  if (el._leaflet_id) {
    try { el._leaflet_id = null; } catch (e) {}
  }
  el.innerHTML = "";
  const map = L.map("map-detail").setView([lat, lng], MAP_PROPERTY_ZOOM);
  L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
    attribution: "&copy; OpenStreetMap contributors",
    maxZoom: 19
  }).addTo(map);
  L.marker([lat, lng]).addTo(map).bindPopup(p.title).openPopup();
  setTimeout(() => map.invalidateSize(), 150);
}

function openModal(id) {
  const el = document.getElementById(id);
  if (!el) {
    const fallback = {
      "auth-modal": "/login",
      "list-choice-modal": "/list-property",
      "looking-modal": "/dashboard?intent=property-need",
      "report-modal": "/report-fraud",
      "broker-reg-modal": "/broker-signup",
      "page-modal": "/help",
      "save-property-modal": "/login?next=%2Fdashboard%3Ftab%3Dsaved"
    }[id];
    if (fallback) window.location.href = fallback;
    return false;
  }
  if (el) el.classList.add("open");
  if (id === "auth-modal") {
    setAuthModalTab("signin");
    setAuthSignInAudience("finder");
    setAuthSignUpAudience("finder");
  }
  if (id === "broker-reg-modal") {
    syncAgentRegistrationForm();
    resetAgentRegistrationOtpState();
    resetAgentProfilePhoto();
  }
  syncModalOpenState();
  return true;
}

function closeModal(id) {
  const el = document.getElementById(id);
  if (el) el.classList.remove("open");
  if (id === "broker-reg-modal") {
    resetAgentRegistrationOtpState();
    resetAgentProfilePhoto();
  }
  syncModalOpenState();
}

function syncModalOpenState() {
  const anyOpen = !!document.querySelector(".modal-overlay.open");
  document.body.classList.toggle("modal-open", anyOpen);
}

document.addEventListener("click", (e) => {
  if (e.target.classList.contains("modal-overlay")) {
    e.target.classList.remove("open");
    syncModalOpenState();
  }
});

function toggleMobile() {
  const el = document.getElementById("mobile-menu");
  el.classList.toggle("mobile-open");
}

function closeMobile() {
  const el = document.getElementById("mobile-menu");
  el.classList.remove("mobile-open");
}

function toast(message, duration = 2400) {
  const el = document.getElementById("toast-el");
  if (!el) return;
  el.textContent = message;
  el.classList.add("show");
  clearTimeout(el._timer);
  el._timer = setTimeout(() => el.classList.remove("show"), duration);
}

